(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).sw = [
  { id:1, topic:"Sayansi ya kunawa", emoji:"🧼",
    question:"Mikononi mwako mkiwa na vijidudu au virusi vinavyoleta magonjwa, kwa nini kunawa kwa 'sabuni' ni salama zaidi sana kuliko kunawa kwa maji tu?",
    choices:["Umbo la povu la sabuni huviogopesha vijidudu na kuvifukuza mbali","Sabuni inaweza kuvunja kabisa utando wa mafuta (ganda la nje) unaomzunguka virusi na kuuyeyusha","Sabuni hufanya ngozi ya mikono yako migumu kama chuma hivyo huzuia vijidudu","Harufu ya sabuni huzuia vijidudu kupumua"],
    answerIndex:1,
    explanation:"Uso wa vijidudu na virusi vingi (kama vya homa ya mafua) kwa kweli umelindwa na utando mwembamba wa mafuta uitwao 'lipidi'. Utando huu ndio unaowapa nguvu ya kuvamia mwili wa binadamu. Mafuta hayaondoki kamwe kwa maji peke yake, lakini molekuli za sabuni zina uwezo wa kuyazunguka mafuta na kuyayeyusha majini. Unaposugua mikono kwa sabuni, utando wa mafuta unaolinda virusi huyeyuka vipande vipande papo hapo, virusi havibaki hai tena na huharibiwa kabisa. Kunawa kwa sabuni si kuondoa tu vijidudu mikononi, bali ni 'dawa' yenye nguvu zaidi inayoangamiza adui kisayansi." },
  { id:2, topic:"Kushinikiza moja kwa moja", emoji:"🩹",
    question:"Unapoumia jeraha refu na damu inabubujika, ni 'huduma sahihi ya kwanza (kushinikiza moja kwa moja)' gani ya kufanya kwanza kabisa ili kuokoa uhai?",
    choices:["Kupapasa jeraha mfululizo kwa kitambaa kilicholowekwa maji","Kuweka kitambaa safi moja kwa moja juu ya jeraha na kushinikiza kwa nguvu kutoka juu kwa uzito wa mwili","Kutikisa jeraha kwa nguvu hadi damu isimame","Kufunika jeraha kwa udongo ili kuzuia damu"],
    answerIndex:1,
    explanation:"Kupoteza damu nyingi ni hatari kubwa kuliko zote: oksijeni hukoma kufika kwenye chembe na unaweza kupoteza uhai papo hapo. Msingi wa kitabibu duniani kote unaozuia hilo ni 'kushinikiza moja kwa moja'. Kwa kushinikiza kwa nguvu mshipa uliopasuka kutoka nje, unaziba kimwili njia ya damu kupita. Zaidi, kushinikiza husaidia 'chembe sahani' za damu, timu inayotengeneza kigaga, kukusanyika jeraheni na kuziba tundu. Kupangusa kwa upole nusunusu hakusimamishi damu. Hekima ya kushinikiza kwa nguvu kwa mikono miwili huushika uhai wa mtu." },
  { id:3, topic:"Kuweka banzi kwa mvunjiko", emoji:"🦴",
    question:"Unaposhuku 'mfupa wa mguu au mkono umevunjika (mvunjiko)' baada ya kuanguka, kwa nini usilazimishe kamwe sehemu hiyo kusogea?",
    choices:["Kuusogeza hugeuza mfupa ghafla kuwa mpira mviringo","Ncha kali ya mfupa uliovunjika inaweza kurarua misuli, mishipa na neva muhimu chini ya ngozi, ikasababisha kutokwa damu kwingi au kupooza","Kuusogeza mfupa huufanya uwe mzito mara kumi","Mfupa huogopa na kutoweka mwilini"],
    answerIndex:1,
    explanation:"Mfupa unapovunjika chini ya ngozi, ncha yake iliyovunjika ni kali sana na yenye ncha, kama kipande cha kioo. Ukilazimisha sehemu hiyo kusogea ukijiuliza 'je, naweza kutembea?', kisu hicho cha mfupa husogea ndani ya nguo na misuli, hukata mshipa mnene ulio karibu na kusababisha kutokwa damu ndani, au huumiza neva na kuleta kupooza kusiko pona kamwe. Unaposhuku mvunjiko, weka tawi au ubao mgumu (banzi) na ufunge kwa pamoja kiungo cha juu na cha chini ya mahali pa kuvunjika, ili kisisogee hata milimita moja huku ukisubiri matibabu. Hiyo ndiyo hekima sahihi ya dharura." },
  { id:4, topic:"Kutibu kuungua", emoji:"🔥",
    question:"Unapogusa moto au maji ya moto ukaungua, ni jambo gani la kwanza kabisa la kufanya, kwa haraka sana, kabla ya yote?",
    choices:["Kupaka mafuta au udongo jeraheni ili lisikauke","Kupooza jeraha kwa maji baridi safi, kulishikilia angalau dakika 15, hadi maumivu yapungue","Kung'oa ngozi iliyoungua kwa kucha vizuri","Kulifunika kwa kitambaa cha joto ili kuhifadhi joto"],
    answerIndex:1,
    explanation:"Jambo la kutisha kuhusu kuungua ni kwamba, hata baada ya kuondoa mkono kutoka kitu cha moto, nishati kubwa ya joto iliyobaki juu ya ngozi huendelea kupenya kwa kina (kwenye safu ya ngozi ya ndani na misuli) kama kaa la moto, ikiharibu chembe. Njia pekee ya kulizuia ni kuiba joto hilo haraka iwezekanavyo kwa maji baridi. Kupooza zaidi ya dakika 15 husimamisha wimbi la joto liendalo ndani na kufanya jeraha lisiwe la kina kadiri inavyowezekana. Iwapo kupooza kwa awali hakutoshi, ngozi hufa kwa kina, huacha kovu kubwa maisha yote na hurahisisha vijidudu kuingia. Kupooza kwa maji ni 'breki' ya kisayansi dhidi ya kuenea kwa kuungua." },
  { id:5, topic:"Maji ya kurudisha maji mwilini", emoji:"🥤",
    question:"Kuhara au kutapika kukali kunapoukausha mwili, kwa nini ni bora kisayansi kunywa maji yaliyochanganywa na 'chumvi' kidogo na 'sukari' (maji ya kurudisha maji mwilini) kuliko maji ya kawaida?",
    choices:["Kuchanganya chumvi na sukari hufanya maji yawe matamu na moyo ufurahi","Ukuta wa utumbo mwembamba una mlango maalumu unaonyonya maji kwa kasi kubwa wakati kiini cha chumvi (sodiamu) na cha sukari (glukosi) vinapofika pamoja","Chumvi huchoma na kuua moja kwa moja vijidudu vya kuhara","Kunywa sukari hugandisha tumbo papo hapo na kusimamisha kuhara"],
    answerIndex:1,
    explanation:"Wakati wa kuhara au kutapika kukali, ukuta wa utumbo umejeruhiwa, hivyo hata maji ya kawaida hayanyonywi vizuri na hutoka upande mwingine. Lakini ukuta wa utumbo mwembamba wa binadamu una mlango (SGLT-1): sodiamu na glukosi vinapofika pamoja kwa uwiano wa 1 kwa 2, hunyonya maji ndani ya chembe papo hapo kama pampu yenye nguvu. Kinachotumia hili ni 'maji ya kurudisha maji mwilini', yaliyookoa maisha mengi duniani kote. Maji haya ya kimuujiza, yaliyotengenezwa kwa kuchanganya nusu kijiko cha chai cha chumvi na vijiko vinne na nusu vikubwa vya sukari katika lita moja ya maji, yanaweza kuokoa uhai kutokana na ukosefu wa maji hata pasipo dripu ya mshipani. Hii ndiyo hekima ya tiba." },
  { id:6, topic:"Kumbukumbu ya kinga", emoji:"💉",
    question:"Mtu akishapata ugonjwa fulani mkali, kama surua, ni nadra kupata ugonjwa ule ule tena. Mfumo huu wa ajabu ndani ya mwili huitwaje?",
    choices:["Kuhuisha mifupa","Mfumo wa kumbukumbu wa kinga","Kuwa fuwele kwa damu","Udanganyifu wa ubongo"],
    answerIndex:1,
    explanation:"Ndani ya miili yetu, timu ya kinga, ikiwemo 'chembe nyeupe za damu' zinazopigana na vijidudu na virusi, hudoria saa 24. Virusi vikali vinapovamia kwa mara ya kwanza, huchukua siku nyingi kutengeneza silaha (kingamwili) ya kupigana navyo, na katika muda huo unaweza kuugua sana. Lakini la ajabu kuhusu timu ya kinga ni kwamba huhifadhi kabisa 'umbo na alama' za adui iliyepigana naye mara moja, na kuziweka ubongoni na chembeni. Miaka baadaye, adui yule yule akivamia tena, hutumia kumbukumbu hiyo kutengeneza kiasi kikubwa cha silaha sahihi papo hapo na kumwangamiza kwa pigo moja kabla hujaugua. Teknolojia inayotumia hili, kupanda kumbukumbu tu kwa usalama kabla ya kuugua, ni 'chanjo'." },
  { id:7, topic:"Mnyama akikuuma", emoji:"🐕",
    question:"Mbwa-mwitu, mbweha, popo au mnyama mwingine akikuuma, hata jeraha likionekana dogo, kwa nini lazima ukimbilie kuliosha kwa maji mengi na sabuni, jambo la uhai au kifo?",
    choices:["Rangi ya meno ya mnyama inaweza kuhamia ngozini mwako","Mate ya mnyama yanaweza kuficha virusi vya kutisha kama vya kichaa cha mbwa, vinavyoharibu ubongo na kuua karibu 100% ya wanaoambukizwa","Usipoosha, manyoya mapya yatamea mahali pa kuumwa","Ili kumwonyesha mnyama shukrani yako"],
    answerIndex:1,
    explanation:"Duniani kote kuna ugonjwa wa kutisha uitwao 'kichaa cha mbwa', unaoenea kwa binadamu mnyama mwenye virusi anapomuuma. Virusi hivi vikiingia mwilini na kusafiri kupitia neva hadi ubongoni, basi dalili zikishaonekana, hata tiba ya kisasa karibu kamwe haimwokoi mtu, naye hufa. Hata hivyo, kuna nafasi fupi ya muda kabla virusi haijaingia kwenye neva kutoka jeraheni. Mara baada ya kuumwa, kuosha jeraha kwa nguvu chini ya maji mengi yanayotiririka safi na sabuni zaidi ya dakika 15 huosha kimwili na kupunguza virusi vilivyoshikamana na jeraha na kunaweza kuzuia kufika ubongoni. Mnyama akikuuma, 'osha kwa nguvu kabla ya yote': hii ndiyo kanuni kamili ya tiba inayoamua uhai au kifo." },
  { id:8, topic:"Viumbe wenye sumu", emoji:"🐍",
    question:"Nyoka mwenye sumu, buibui au kiumbe mwingine hatari akikuuma mkono au mguu, ni 'kitendo kibaya' gani usichopaswa kufanya kamwe?",
    choices:["Kutosogeza mahali pa kuumwa na kulala kimya","Kushtuka, kupiga kelele kwa sauti kubwa na kukimbia huku na huko kutoroka","Kumwambia mtu mzima aliye karibu ni kiumbe gani hasa kilichokuuma","Kuweka jeraha chini ya moyo"],
    answerIndex:1,
    explanation:"Kiumbe mwenye sumu akikuuma, ukishtuka kwa woga ukakimbia huku na huku au ukapiga zogo kubwa, mapigo ya moyo wako (mpigo) huongezeka ghafla. Ndipo sumu iliyoingia jeraheni hupanda damu inayokimbia kwa kasi na kusambaa papo hapo kwenye misuli, ubongo na viungo vya ndani vya mwili mzima, hivyo sumu husambaa kwa kasi zaidi sana na unaweza kupoteza uhai. Kitu chenye sumu kikikuuma, sahihi ni kutuliza moyo, usikimbie, usisogee, na ulale kimya bila kusogea. Kwa kuweka jeraha chini kidogo ya moyo, unapunguza kasi ya damu yenye sumu kurudi moyoni. Kubaki mtulivu na bila kusogea ndio ngao yenyewe inayozuia kuenea kwa sumu." },
  { id:9, topic:"Jasho na chumvi", emoji:"💦",
    question:"Siku ya joto baada ya kutoka 'jasho' jingi, hata ukiwa na kiu, kwa nini kunywa kwa pamoja kiasi kikubwa cha 'maji safi yasiyo na chumvi' tu kunakufanya kwa kweli ujisikie vibaya zaidi?",
    choices:["Kunywa maji safi hufanya maji ya tumboni yaoze","Kwa kuwa chumvi (sodiamu) pia hupotea mwilini pamoja na jasho, kunywa maji tu hupunguza kiwango cha chumvi katika damu kupita kiasi, na ubongo na misuli haviwezi kufanya kazi vizuri (sodiamu chini)","Maji mengi huyeyusha mifupa yote ya mwili","Maji safi hubadilisha damu yako kutoka nyekundu kuwa bluu"],
    answerIndex:1,
    explanation:"Maji ya mwili (kama damu) huwa na takriban asilimia 0.9 ya 'chumvi' daima, na kwa sababu ya kiwango hiki sahihi, amri za neva hufika kwa usahihi kwenye misuli na ubongo. Unapotoka jasho jingi, chumvi hii muhimu huvuja nje pamoja na maji. Kisha ukimimina katika mwili huo tupu maji safi yasiyo na chumvi tu, kiwango cha chumvi ndani hupungua zaidi. Ndipo ubongo huhukumu 'kikipungua zaidi ni hatari!' na hukataa maji, au hujaribu kuyatoa nje kama jasho au mkojo. Matokeo yake, miguu hupata mkakamao mkali (mikakamao ya joto), na huja maumivu ya kichwa na kizunguzungu. Unapojaza maji siku ya joto, lazima daima uchukue chumvi kidogo sana kwa wakati mmoja." },
  { id:10, topic:"Kufungua njia ya hewa", emoji:"😮",
    question:"Mtu anapoanguka bila fahamu na pengine hapumui, ni nini lengo halisi la kumweka katika hali ya 'kuinua kidevu juu na kuegesha kichwa nyuma (kufungua njia ya hewa)'?",
    choices:["Kuelekeza uso juu ili mwanga wa jua uingie machoni","Unapopoteza fahamu, msuli mkubwa wa ndani ya koo (shina la ulimi) hulegea na kuanguka chini na kuziba kabisa njia ya hewa; hili huzuia kukabwa pumzi","Kunyoosha mifupa ya shingo ili mtu awe mrefu","Kumsaidia mtu aliyeanguka alale vizuri"],
    answerIndex:1,
    explanation:"Mtu anapopoteza fahamu na kulegea kabisa, msuli wa 'ulimi' wa ndani ya koo nao huzama nyuma kwa kulegea. Hili huitwa 'ulimi kuanguka nyuma'. Koo la mtu aliyelala chali huzibwa kabisa, njia ya hewa huzuiwa na ulimi wake mwenyewe, hivyo hawezi kupumua na hukabwa pumzi. Ili kuzuia hili, huku ukibonyeza paji la uso, tumia mkono mwingine kuinua mfupa wa kidevu kwa nguvu kuelekea angani. Hili hufungua kimwili nafasi ya ndani ya koo iwe pana, na hewa hufika mapafuni kwa urahisi. 'Kufungua njia ya hewa' huku ni hatua ya kwanza ya kuokoa uhai duniani kote, kabla ya kupuliza pumzi au kukandamiza kifua." },
  { id:11, topic:"Jinsi kupumua kunavyofanya kazi", emoji:"💨",
    question:"Tunapovuta na kutoa pumzi, kwa nini mwili wetu lazima utupe nje gesi iitwayo 'kaboni dioksidi'?",
    choices:["Kaboni dioksidi ikijaa mwilini, ngozi hugeuka kijani","Kaboni dioksidi ni taka yenye sumu inayozalishwa wakati chembe zinapochoma virutubisho ili kufanya kazi kwa nguvu, na ikijaa damuni, damu hugeuka tindikali na kuhatarisha uhai","Usipotoa kaboni dioksidi, mwili huvimba kama puto na kuelea angani","Ili kuweka ndani ya mwili baridi"],
    answerIndex:1,
    explanation:"Kama gari linavyochoma petroli na kutoa moshi, ndivyo trilioni za chembe za binadamu zinavyochoma virutubisho vya chakula kwa oksijeni ili kutengeneza nishati ya kuishi, na daima hutengeneza taka ya moshi iitwayo 'kaboni dioksidi'. Gesi hii ikiyeyuka kwa wingi damuni, ina nguvu ya sumu ya kuibadilisha damu kwa kasi kutoka isiyo na tindikali kuwa 'tindikali' hatari. Damu ikiwa tindikali, chembe za ubongo na moyo haziwezi tena kufanya kazi, na mtu hufa. Ndiyo maana haswa moyo huharakisha damu kwenda mapafuni, hutupa kaboni dioksidi sekunde moja mapema kwa kupumua na huchukua oksijeni mpya badala yake, mara kwa mara." },
  { id:12, topic:"Kazi ya moyo", emoji:"❤️",
    question:"Ni nini lengo halisi la 'moyo' upande wa kushoto wa kifua kupiga bila kupumzika, hata sekunde moja, tangu kuzaliwa hadi kufa?",
    choices:["Kusaga na kuvunja chakula tumboni","Kuzungusha 'lori la kupeleka la mwili' linalobeba damu iliyojaa oksijeni na virutubisho kwenda chembe za mwili mzima na kukusanya taka (kama kaboni dioksidi) zinazotolewa na chembe","Kusukuma nje maji ya ziada yaliyojaa mwilini","Kurudisha mwangwi wa sauti yake kuwaambia wenzako ulipo"],
    answerIndex:1,
    explanation:"Moyo ni pampu ya misuli yenye nguvu sana inayosukuma 'damu' inayotiririka mwilini mwetu. Damu hubeba oksijeni iliyopokelewa mapafuni na virutubisho vilivyonyonywa utumboni, na huvipeleka kwa chembe kutoka utosini hadi vidole vya miguu, ikitimiza jukumu la mpelekaji muhimu. Moyo ukisimama ghafla, mtiririko wa damu husimama kabisa. Ndipo chembe za ubongo, zinazohitaji oksijeni nyingi hasa, hupungukiwa nayo ndani ya dakika chache tu na kupata uharibifu wa kuangamiza usio pona kamwe, na hufa. Moyo kuendelea kupiga ni mfumo muhimu zaidi wa kudumisha uhai, unaopeleka 'posho ya kuishi' kwa chembe za mwili mzima." },
  { id:13, topic:"Kuokoa anayezama", emoji:"🆘",
    question:"Unamwona rafiki au mtu akizama mtoni au baharini. Ili kujilinda huku ukimsaidia, ni 'jambo gani usilopaswa kufanya kamwe'?",
    choices:["Kupiga kelele kwa sauti kubwa kwa watu wazima walio karibu, 'Aje mtu! Mtu anazama!' na kuita msaada","Kufikiri unaweza kuogelea na kumwokoa, na kuruka moja kwa moja majini mikono mitupu kumkamata anayezama","Kutupa kamba, fimbo ndefu au chupa ya plastiki tupu (badala ya kiokozi) juu ya maji","Kunyoosha mkono kutoka ardhi imara iliyo karibu"],
    answerIndex:1,
    explanation:"Mtu anayezama na asiyeweza kupumua yumo katika hofu kamili kwa woga wa kufa. Mtu akiogelea kumsaidia, anayezama, kwa nguvu kali isiyoaminika, hukushikilia kutoka juu ya kichwa ili kukutumia kama 'kiokozi' na kukusukuma chini ya maji. Hili likitokea, hata mtu mzima muogeleaji hodari huzama nawe hadi chini, na ajali ya kusikitisha ya watu wawili kuzama hutokea duniani kote bila kikomo. Mtu akizama, ni marufuku kabisa kuingia majini wewe mwenyewe. Piga kelele kwa nguvu kutoka mahali salama nchi kavu na utupe chochote 'kinachoelea', chupa tupu, kipande cha mti, ili akamate. Hii ndiyo kanuni sahihi ya kunusurika." },
  { id:14, topic:"Kuzuia pepopunda", emoji:"🔩",
    question:"Unapokanyaga msumari mkuukuu wenye kutu, au kuumia jeraha refu kwa kifaa cha zamani chenye udongo, kwa nini usipuuze hata baada ya siku, jeraha likishapona?",
    choices:["Chuma chenye kutu hugeuka sumaku ndani ya ngozi yako","Kijidudu kiitwacho bakteria wa pepopunda hupenda mahali pasipo na oksijeni (hewa), kinaweza kuongezeka ndani ya kina cha jeraha na kutoa sumu ya kutisha inayokaza misuli yote ya mwili","Kuacha jeraha refu hufupisha mguu wako miaka baadaye","Kutoka jeraha la zamani humea kucha mpya"],
    answerIndex:1,
    explanation:"Udongo na chuma kikuukuu chenye kutu huficha vijiviu (kama mayai) vya kijidudu kinachosababisha 'pepopunda'. Sifa kubwa ya kijidudu hiki ni kwamba ni 'kisichohitaji hewa': huchukia kugusa hewa. Kwa hiyo, badala ya jeraha la juujuu, mahali pake pendwa ni kina cha jeraha pasipofikiwa na hewa, kama la msumari uliochoma kwa kina. Jeraha likipona, kijidudu huongezeka kwa mlipuko katika giza la ndani ya ngozi na hutoa sumu kali inayoharibu neva za binadamu. Siku hadi wiki baadaye huja ugonjwa wa kutisha ambapo mdomo haufunguki tena, au misuli yote hujikunja nyuma na kupumua kunakuwa hakiwezekani. Unapoumia jeraha refu, lazima uwe na hekima ya kushauriana na hospitali kuhusu matibabu ya pepopunda." },
  { id:15, topic:"Mwanga mkali na macho", emoji:"👁️",
    question:"Baada ya kutazama moja kwa moja 'mwanga mkali', kama jua au cheche kali za kulehemu, kwa nini katikati ya uoni wako huendelea kumeta hata usione, hata ukifumba macho?",
    choices:["Mwanga mkali umevukiza machozi yote machoni mwako","Chembe za skrini muhimu zaidi ya ndani ya jicho inayonasa mwanga (retina) zilipata uharibifu mkubwa kama wa kuungua kwa nishati kupita kiasi, na neva ziko katika hofu","Chembe za mwanga zilinaswa ndani ya jicho na zinavurumika humo","Ubongo wako unakumbuka rangi ya mwanga"],
    answerIndex:1,
    explanation:"Ndani ya jicho la binadamu kuna skrini ya neva nyororo sana iitwayo 'retina', inayobadilisha mwanga unaoingia kuwa ishara za umeme na kuzipeleka ubongoni. Mwanga wa jua na mwanga mkali sana una nishati yenye nguvu ya uharibifu ya kutisha, kama 'miale ya urujuanimno'. Ukiitazama moja kwa moja kwa jicho tupu, kwenye retina yako mwenyewe hutokea sawa na pale kioo cha kukuza kinapokusanya mwanga wa jua kuchoma karatasi. Kumeta ni ushahidi kwamba chembe zinapiga kelele kwa kuwa zimeharibika. Likiwa kali, tundu hufunguka katikati ya retina (retinopathia ya jua), likiongoza kwenye upofu, ambapo uoni haurudi. Kuondoa macho kutoka mwanga mkali ndani ya sekunde moja ni kanuni ya sayansi ya kuyalinda." },
  { id:16, topic:"Meno ya watu wazima", emoji:"🦷",
    question:"Kwa nini usiache kamwe meno ya watu wazima ('meno ya kudumu') yanayoota karibu na madarasa ya juu ya shule ya msingi yapate mashimo (kuoza), sababu inayohusu maisha yote?",
    choices:["Jino la mtu mzima likioza, mifupa yote ya kichwa hulegea","Tofauti na meno ya maziwa, jino la kudumu likishaoza na kung'oka, jino jipya halitaota tena kutoka chini: ni sehemu ya mwili idumuyo maisha yote","Kupoteza jino la mtu mzima maana yake hutaweza tena kuzungumza kabisa","Jino lililooza huanza kusogea lenyewe usiku wa manane"],
    answerIndex:1,
    explanation:"Meno ya utotoni (ya maziwa) hubadilishwa hata yakioza, kwa kuwa meno mapya ya watu wazima husukuma kutoka chini. Lakini 'meno ya kudumu' yanayoota karibu na umri wa miaka 10 ni, kwa maana halisi, toleo la mwisho, yaliyotengenezwa kutumika hadi mwisho kabisa wa maisha. Tofauti na mkia wa mjusi au ngozi ya binadamu, enameli ngumu ya uso wa jino, ikishaharibiwa na kuyeyuka, haitarudi kamwe, asilimia 100, kwa umbo lake la awali kwa nguvu zake. Ukipoteza meno, huwezi tena kusaga chakula, jambo linaloleta uharibifu mkubwa kwa tumbo na utumbo, hudhoofisha lishe ya mwili mzima na hufupisha maisha. Kutunza vizuri meno yako ya mtu mzima ni kujipatia mwenyewe afya yako ya baadaye." },
  { id:17, topic:"Kulinda ubongo", emoji:"🚭",
    question:"Duniani kote, sheria inakataza kwa ukali watoto na vijana wadogo kuingiza miilini mwao 'pombe', 'tumbaku' au dawa za kulevya hatari zinazoharibu ubongo. Sababu ya kisayansi ni ipi?",
    choices:["Vitu hivyo ni haki ya pekee ya watu wazima kufurahia peke yao","Mwili wa mtoto bado unajenga kwa kasi 'mizunguko ya ubongo (mtandao)' hadi karibu miaka 20, na sumu ikiingia, ukuaji husimama kabisa na kumbukumbu na udhibiti wa hisia huvunjika milele","Watoto wakizitumia, rangi ya nguo zote inakuwa nyeusi","Hakuna sababu halisi; ni kanuni tu ambayo watu wazima wameitunga kuwabana watoto"],
    answerIndex:1,
    explanation:"Ubongo wa binadamu hutumia muda mrefu tangu kuzaliwa hadi karibu miaka 20 kila siku ukifanya kazi za kulaza mitandao tata ya chembe za neva, ili uwe na busara zaidi na uweze kudhibiti hisia vizuri zaidi. Sumu kama pombe, nikotini ya tumbaku, au dawa za kulevya kama bangi zikitiririka ubongoni katika kipindi hiki nyeti sana 'cha ujenzi unaoendelea', kazi ya nyaya huharibika kwa machafuko na ukuaji husimama kabisa. Matokeo yake, hata ukiwa mtu mzima huwezi tena kufikiri kwa kina, hulipuka na kusababisha vurugu, au unakuwa mwili wa kusikitisha usiowezi kuishi bila dawa (uraibu). Ili kulinda ubongo wako, shika azimio thabiti la kutokaribia kamwe sumu hizi maisha yako yote." },
  { id:18, topic:"Usingizi husafisha ubongo", emoji:"😴",
    question:"Unapoishi kila siku bila kulala vya kutosha, kwa nini watu huwa rahisi zaidi kuugua na hawawezi kufikiri kwa uwazi?",
    choices:["Usipolala, mifupa ya mwili huwa myepesi zaidi na huvunjika","Mfumo wa usafishaji unaosukuma taka hatari nje ya ubongo, na homoni ya ukuaji inayoponya majeraha ya mwili, vinavyofanya kazi tu wakati wa kulala, husimama kufanya kazi (mfumo wa glimfatiki)","Ukikwepa usingizi, jua hukasirika na kutoa joto","Binadamu asipolala, hugeuka kabisa kuwa roboti katika siku 3"],
    answerIndex:1,
    explanation:"Mchana, tunapoishi kwa kutumia vichwa vyetu, chembe za ubongo hutoa taka nyingi za protini hatari, kama 'beta-amiloidi', zinazojaa ndani ya kichwa. Mtu anapoingia usingizi wa kina usiku, chembe za ubongo hujikunja kidogo kutengeneza nafasi, na kwenye nafasi hizo 'majimaji ya ubongo-uti wa mgongo', maji safi, huingia kama tsunami, na kuanza usafi mkubwa unaosukuma mara moja taka za mchana. Huu ndio mfumo wa usafishaji wa ubongo uliogunduliwa na tiba ya kisasa. Ukikosa usingizi mara kwa mara, taka yenye sumu hubaki imerundikana kichwani, neva hufa na unakuwa mwenye hasira, kinga yako hushuka na hushindwa na kila ugonjwa. Usingizi ni sabuni bora zaidi ya ubongo." },
  { id:19, topic:"Jinsi urithi unavyofanya kazi", emoji:"🧬",
    question:"Katika nchi zote za dunia, na katika historia, kumekuwa na kanuni dhidi ya kuoana na kuzaa watoto na ndugu wa damu wa karibu sana (baba na binti, kaka na dada). Sababu ya kisayansi (ya kijenetiki) inayofanana ni ipi?",
    choices:["Kwa ndugu wa karibu, jina la mtoto atakayezaliwa haliwezi kuamuliwa","Kila mtu hubeba mahali fulani katika jeni zake 'kosa dogo la mchoro (chanzo cha ugonjwa)', na kati ya ndugu wa karibu makosa yale yale huingiliana, hivyo nafasi ya mtoto kuzaliwa na ugonjwa au ulemavu mzito hupanda kwa kasi","Kwa ndugu wa karibu, ndani ya nyumba huwa finyu","Mungu hapendi sura ya aina hiyo"],
    answerIndex:1,
    explanation:"Jeni, ambazo ni mchoro wa mwili wa binadamu, hutengenezwa kwa kupokea seti ya vitabu viwili: nusu kutoka kwa baba na nusu kutoka kwa mama. Kila mmoja hubeba kwa siri makosa machache 'makubwa ya mchoro' mahali fulani katika kitabu kimoja, lakini kama mchoro wa kitabu kingine ni sawa, unaweza kuishi kwa afya bila kuugua. Hata hivyo, binadamu walio karibu kwa damu hurithi michoro yao kutoka kwa mababu wale wale kabisa, hivyo 'mahali pa makosa yao' hufanana sana. Watu hawa wawili wakizaa mtoto, 'mchoro wenye hitilafu mahali pale pale kabisa' kutoka kwa baba na mama hukutana maradufu, kosa haliwezi tena kufunikwa, na mtoto mwenye ugonjwa au ulemavu mzito huzaliwa. Kutokana na uzoefu na hekima, binadamu wameunda kanuni ya kuepuka hatari hii." },
  { id:20, topic:"Kuongezewa damu na makundi", emoji:"🩸",
    question:"Kwa nini usimimine kamwe, kwa uamuzi wako usio wa kitaalamu, 'damu' yako moja kwa moja kwa sindano ndani ya mwili wa mtu aliyejeruhiwa vibaya ili kuigawa (kuongeza damu)?",
    choices:["Damu ya mwingine ikiingia, rangi ya nywele zako huwa kama yake","Damu ina makundi (A, B, O, AB), na aina tofauti zikichanganyika, chembe nyekundu hukataana kwa nguvu ndani ya mwili, hugandamana, huziba mishipa na humuua mtu","Kugawa damu hupunguza uzito wako kwa nusu","Kunywa damu ya mtu mwingine hukuletea maumivu ya tumbo"],
    answerIndex:1,
    explanation:"Damu yote huonekana kioevu chekundu kile kile, lakini uso wa chembe nyekundu una 'antijeni': alama maalumu (funguo na mihuri) zinazoonyesha aina ya damu hiyo. Hii ndiyo kundi la damu (mfumo wa ABO). Kwa mfano, ukimimina kwa kosa damu ya kundi B ndani ya mwili wa mtu wa kundi A, timu ya kinga ya kundi A hushtuka, 'adui nisiyewahi kumwona amevamia!', na hushambulia kwa pamoja chembe nyekundu zote za kundi B zinazoingia, ikizifumbatisha katika fundo gumu kama wavu (mwitikio wa kugandamana). Damu iliyoganda huziba mishipa minene ya mapafu na ubongo na husababisha kifo cha mshtuko papo hapo. Katika tiba, kipimo kinachochunguza kundi la damu ni uthibitisho wa uhai usioweza kuachwa kamwe." },
  { id:21, topic:"Kutafuna vizuri", emoji:"🍽️",
    question:"Unapoweka chakula mdomoni, kwa nini kutafuna vizuri kwa meno (zaidi ya mara 30) kabla ya kumeza husaidia sana kazi ya tumbo na utumbo, sababu ya kisayansi ni ipi?",
    choices:["Ukitafuna vizuri, chakula hutoweka kabisa mdomoni","Kusaga chakula kuwa vipande vidogo huongeza mara nyingi 'eneo la uso' la jumla, hivyo maji ya usagaji ya utumboni hupenya kote upesi na hunyonya virutubisho kwa ufanisi","Kutafuna hupandisha joto la tumbo hadi nyuzi 100","Kuzoeza meno hufanya misuli ya nyayo za miguu kuwa na nguvu"],
    answerIndex:1,
    explanation:"Huu ni utumiaji mzuri wa wazo la hisabati la 'eneo la uso'. Ukitupa donge kubwa la kiazi vile vile tumboni, asidi ya tumbo (asidi ya usagaji) huweza kuliyeyusha kutoka uso tu, hivyo huchukua saa nyingi kufika katikati, tumbo huchoka na hukuharibia tumbo. Lakini ukitumia meno kulitafuna kuwa makombo madogo, donge kubwa moja hugawanyika kuwa vipande maelfu vidogo. Kwa kugawanyika, 'jumla ya eneo' ambapo chakula huweza kugusa maji ya usagaji huongezeka kwa mlipuko. Kwa sababu hiyo, mara likifika tumbo na utumbo, maji hupenya hadi katikati papo hapo, huyeyusha chakula kuwa uji na hunyonya asilimia 100 ya virutubisho vya kuishi bila kuacha chochote. Kutafuna vizuri ni kiwanda cha kwanza cha kupika, kabla ya utumbo." },
  { id:22, topic:"Kukwama kooni (kuokoa)", emoji:"🍖",
    question:"Kipande kikubwa cha chakula kinapokwama kooni mwa mtu naye anakaba pumzi, unamkumbatia kutoka nyuma na kusukuma kwa nguvu juu kwenye tumbo lake (mbinu ya Heimlich). Ni nini lengo halisi la kusukuma tumbo?",
    choices:["Kubonyeza tumbo ndani ili aonekane mwembamba","Kushinikiza tumbo kwa nguvu husukuma juu hewa iliyobaki mapafuni, na kwa shinikizo hilo la hewa (nguvu ya bunduki ya hewa) hurusha nje kwa nguvu kitu kilichokwama kooni","Ili kushtua minyoo iliyo ndani ya tumbo","Ili kusukuma chakula kilichokwama chini, tumboni"],
    answerIndex:1,
    explanation:"Kitu kinapokwama kooni na mtu hawezi kupumua, kwa kweli ndani ya 'mapafu' bado kuna hewa nyingi isiyotolewa. Kati ya kifua na tumbo la binadamu kuna sakafu kubwa ya misuli iitwayo 'kiwambo', inayovimbisha na kukunja mapafu. Unapokumbatia kutoka nyuma na kusukuma kwa nguvu juu kidogo juu ya kitovu, viungo vya tumbo husukumwa juu, na kwa upande wake kiwambo hupiga mapafu kwa nguvu kutoka chini. Ndipo hewa iliyobaki mapafuni hurudi kooni papo hapo kama dhoruba kali na, kama bunduki ya hewa, hurusha nje kipande cha chakula kilichoziba koo. Ni mbinu ya ajabu ya kuokoa, inayotegemea fizikia, inayotumia muundo wa mwili wa binadamu." },
  { id:23, topic:"Vimelea na chakula kibichi", emoji:"🐛",
    question:"Kwa nini usile kamwe nyama mbichi ya wanyama-pori, wala kunywa maji mabichi ya mtoni, bila kuyapasha moto, sababu ya kutisha kuhusu minyoo izaayo ndani ya mwili wako?",
    choices:["Kula kibichi hugeuza mwili wa binadamu kuwa mnyama","Ndani ya miili ya viumbe na maji mabichi hujificha vimelea, vilivyojificha kama mayai yasiyoonekana, vinavyoingia utumboni mwa binadamu, huuma ukuta na huiba virutubisho au hula viungo","Maji mabichi hugeuza mifupa yote ya tumbo lako kuwa uji","Kula nyama mbichi hufanya sauti za wanyama zirudie mwangwi ndani ya tumbo lako"],
    answerIndex:1,
    explanation:"Maji ya mito ya asili, na nyama ya kulungu-pori, nguruwe-pori au nguruwe, huficha karibu asilimia 100 mayai na viluwiluwi vya 'vimelea' vidogo visivyoonekana (kama tegu na chango). Ukivila 'vibichi', hubaki hai hata katika asidi ya tumbo na hufika utumboni. Hapo mayai huangua, na virefu hukua kuwa minyoo mikubwa ya mita kadhaa inayoshikamana na ukuta wa utumbo na kunyonya virutubisho vyote ulivyokula ili kuishi, ikikuacha mwenye utapiamlo. Baadhi hujipenyeza ubongoni au ini na kuyeyusha viungo kuwa uji: minyoo mibaya inayohatarisha uhai wako. Vimelea ni dhaifu sana mbele ya moto (joto), kwa hiyo hekima ya usafi ni lazima kabisa: pika nyama vizuri hadi katikati, na chemsha maji ili kuviangamiza vyote." },
  { id:24, topic:"Maliza dawa yako", emoji:"💊",
    question:"Unapotumia 'antibiotiki' ulizopewa na daktari za kuua vijidudu mwilini, ni kanuni gani ya kutisha ya tiba lazima uifuate bila kukosa?",
    choices:["Homa ikishuka na ukajisikia vizuri, acha mara moja kwa uamuzi wako kwa kuwa dawa ni ghali","Hata dalili zikipungua na kuonekana umepona, zinywe zote hadi mwisho, idadi ya siku ulizoelekezwa, hadi vijidudu vya mwilini vifike sufuri","Badilisha wakati wa kunywa dawa kuwa saa tofauti kila siku kwa hiari","Rafiki akiwa na mafua, mgawie dawa yako iliyobaki"],
    answerIndex:1,
    explanation:"Unapoanza antibiotiki, kwanza vijidudu 'dhaifu na vingi vya kawaida' hufa kwa mpangilio. Baada ya nusu kufa, mwili hujisikia kama umepona kabisa. Ukiacha hapa ukifikiri 'nimepona', vile vichache 'vijidudu vibaya na vikaidi zaidi vilivyostahimili shambulio la dawa' vilivyokuwa bado vinaishi kwa shida hufufuka na kuanza kuzaliana kwa wingi tumboni tena. Kwa kuwa vijidudu hivi vilishapitia shambulio na kunusurika, vimegeuka kuwa vijidudu vya kinyama (bakteria sugu) vyenye ngao yenye nguvu kupita kiasi ambayo dawa haiwezi tena kuishinda. Ndipo, hata ukinywa dawa ile ile, haifanyi kazi kabisa, hakuna tiba iliyobaki, na huongoza kifoni. Kuendelea kunywa dawa bila kulegeza hadi kuviangamiza kabisa, hii ndiyo kanuni ngumu ya tiba inayolinda dunia." },
  { id:25, topic:"Jinsi baridi kali ya ngozi itokeavyo", emoji:"🥶",
    question:"Unapokaa muda mrefu mahali penye baridi kali sana, kama mlima wa theluji au juu ya barafu, kwa nini ncha za vidole vya mikono na miguu hugeuka rangi ya zambarau na kupoteza hisia (baridi kali ya ngozi)?",
    choices:["Upepo baridi hupaka uso wa ngozi yako rangi ya zambarau","Ili kulinda joto la moyo na viungo muhimu zaidi (kitovu cha mwili), ubongo hubana mishipa ya ncha za vidole na hukusanya damu katikati tu","Mahali penye baridi, damu yote ya mwili huganda kwa pamoja na kuacha kusogea","Ncha za vidole vya mikono na miguu zimelala kwa baridi"],
    answerIndex:1,
    explanation:"Huu ni ushahidi wa mfumo wa ulinzi wa kikatili, lakini wa hali ya juu kabisa wa kunusurika, ulio nao ubongo wa binadamu. Mwili mzima unapowekwa kwenye baridi kali ya kuganda, kama damu ingeendelea kutiririka kama kawaida hadi ncha za vidole, damu iliyopozwa pale ingerudi moyoni, ikishusha joto la moyo na ubongo (joto la ndani) na kusababisha kifo cha papo hapo kwa baridi. Ili kuzuia hili, ubongo huamuru: 'Toa kafara ncha za vidole ikibidi, lakini usiache kamwe mwali wa uhai wa moyo wa katikati uzimike!' Ndipo mishipa ya mikono na miguu hufunga kwa nguvu na damu huacha kuzifikia. Ncha za vidole, zisizopata damu (oksijeni), chembe zake hufa na kugeuka zambarau, na katika hali mbaya zaidi huoza na kudondoka (baridi kali ya ngozi). Mahali penye baridi, endelea kusogeza mikono na miguu, badilisha glavu zilizolowa mara moja, na uzuie ubongo kutoa amri ya kuachilia mikono na miguu." },
  { id:26, topic:"Giza na macho", emoji:"🌙",
    question:"Wakati unaingia usiku katika chumba chenye giza totoro kisicho na umeme, huoni chochote, lakini ukisimama kimya hapo kama dakika 10, maumbo ya samani na kuta zinazokuzunguka huonekana kwa ukungu. Kwa nini?",
    choices:["Kutoka jicho la binadamu huanza kutoka wenyewe mwale wa mwanga usioonekana","Tundu jeusi katikati ya jicho (mboni) hufunguka wazi gizani na hubadilisha umbo ili kukusanya kadiri iwezekanavyo mwanga hafifu uliopo karibu (kama wa nyota) (kuzoea giza)","Ubongo hufikiria mwenyewe mandhari ya giza na huonyesha njozi","Muda ukienda, rangi ya giza la usiku hupungua"],
    answerIndex:1,
    explanation:"Tundu jeusi katikati ya jicho la binadamu huitwa 'mboni', na kama tundu la lenzi ya kamera, lina pazia la misuli linalorekebisha lenyewe kiasi cha mwanga unaoingia jichoni. Mahali penye mwanga, kama chini ya jua, mboni hujikunja ndogo kama ncha ya sindano ili mwanga uliozidi usichome jicho. Kutoka hapo ukihamia ghafla mahali penye giza totoro, mwanzoni mwanga hautoshi na huonekana jeusi kabisa. Lakini kwa muda wa kama dakika 10, pazia hili la mboni hufunguka hadi kikomo na huanza kwa juhudi kukusanya chembe hafifu za mwanga, nyembamba mno kuonekana, katika pembe za chumba. Mfumo huu huitwa 'kuzoea giza'. Hata ukiwa katika dhiki gizani, usishtuke: kwa kufumba macho na kusubiri kimya dakika 10, unaweza kurudisha dira ya uoni wako. Hii ni hekima ya mwili wa binadamu." },
  { id:27, topic:"Sayansi ya kuvaa tabaka", emoji:"🧥",
    question:"Ili kujikinga na baridi katika msimu wa baridi sana, kwa nini ni joto zaidi kuvaa tabaka nyingi nyembamba (kwa tabaka) kuliko kuvaa nguo moja nene kubwa?",
    choices:["Nguo nyingi hufanya mavazi mazito, hivyo hunyonya joto kutoka ardhini","Kati ya tabaka na tabaka hutengenezwa tabaka nyingi za hewa tulivu (kizuizi), kitu cha polepole zaidi duniani katika kupitisha joto, zinazozuia kabisa joto la mwili wako lisitoke nje","Nguo nyingi nyembamba zikisuguana, ndani huwaka moto","Kuvaa nguo nyingi hufanya upepo uzizunguke na kuziepuka"],
    answerIndex:1,
    explanation:"Hii pia ni hekima nzuri ya kisayansi inayotumia tabia za maada. Maada yenye nguvu zaidi duniani kwa ugumu wa kupitisha joto (kwa kuzuia joto) ni kwa kweli hewa tulivu (gesi). Hata ukivaa nguo moja nene, joto la mwili lenye uvuguvugu ndani husafiri kupitia nyuzi za nguo na kutoroka nje. Lakini ukivaa nguo nyembamba 3 au 4 kwa tabaka, katika nafasi kati ya nguo hutengenezwa 'vyumba vingi vya hewa iliyofungiwa kabisa isiyoweza kusogea'. Tabaka hili la hewa hutenda kama 'kizuizi', sawasawa na ukuta wa chupa ya joto (thermos), na huwa kizuizi chenye nguvu zaidi kisichoacha joto lako la nyuzi 36 litoke wala hewa baridi ya kuganda iingie. Usipokuwa na nguo, hata kujaza gazeti kavu au majani makavu ndani ya nguo hutengeneza tabaka la hewa lile lile na kunaweza kulinda uhai wako dhidi ya kufa kwa baridi." },
  { id:28, topic:"Pigana au kimbia", emoji:"🏃",
    question:"Mnyama mla-nyama mkali anapotokea ghafla mbele yako, au unapokumbana na janga kubwa, kwa nini moyo wako ghafla hupiga kwa nguvu sana na unatoka jasho baridi, bila wewe kutaka?",
    choices:["Ni ishara kwamba moyo umeshtuka kwa woga, umeharibika na uko karibu kusimama","Ili kunusurika, ubongo huanza kujiandaa 'kupigana sasa hivi au kukimbia kwa nguvu zote', na kwa mlipuko hupeleka kiasi kikubwa cha oksijeni (damu) kwenye misuli ya mwili mzima (mwitikio wa pigana-au-kimbia)","Katika janga, kiasi cha damu mwilini huongezeka maradufu","Ili kufanya moyo uwe na kelele kumshtua adui aliye mbele hadi azimie"],
    answerIndex:1,
    explanation:"Binadamu anapohisi woga au janga la kukata tamaa, kituo cha amri cha dharura kilicho ndani ya ubongo (amigdala) hutambua hatari papo hapo na hutoa kwa pamoja homoni maalumu iitwayo adrenalini damuni. Mara homoni hii ifikapo, pampu ya moyo hubadilika kwenda mwendo wa kasi sana wa nguvu zote, hupandisha mpigo kwa kishindo, na huharakisha kupeleka kiasi kikubwa cha oksijeni (damu) kwenye 'misuli ya miguu na mikono' ya kupigana au kukimbia kutoroka. Wakati huo huo, hubana mishipa ya ngozi ili kupunguza kutokwa damu iwapo utajeruhiwa, hivyo uso hubadilika rangi na jasho baridi hutoka. Katika lugha ya tiba, hii huitwa 'mwitikio wa pigana-au-kimbia'. Moyo wako kupiga kwa nguvu ni ishara bora zaidi ya ulinzi: mwili wako, ili kukulinda, umetoa nishati yake yote na umegeuka kuwa hali ya mapigano." },
  { id:29, topic:"Kazi ya vitamini", emoji:"🍊",
    question:"Hata ukijaza tumbo kila siku kwa wali na viazi vingi, kwa nini huugua (kwa mfano kiseyeye), na damu hububujika kutoka mishipani mwili mzima, ikiwa kwa miezi hutaki kula mboga au matunda mabichi kabisa?",
    choices:["Usipokula mboga, rangi nyekundu yote ya damu hutoweka","Virutubisho vikuu vitatu (kama wanga) havitoshi; vitamini, vinavyotenda kama gundi inayoshikamanisha chembe imara na kama kilainishi kinachosaidia athari za kemikali, hukauka","Mwili wa asiyekula matunda una kanuni ya minyoo kuula kutoka ndani","Tumbo lako huacha kufanya kazi lisipoona rangi ya kijani ya mboga"],
    answerIndex:1,
    explanation:"Binadamu anaweza kunenepa kwa kula wali na mkate (wanga), lakini hilo peke yake haliwezi kamwe kumtunza akiwa na afya. Ili kuweka trilioni za chembe na kuta za mishipa ya mwili katika hali yenye ulaini na afya, lazima kabisa uhitaji 'vitamini' (hasa vitamini C na nyingine), virutubisho-vidogo ambavyo mwili hauwezi kuvitengeneza wenyewe. Vitamini ni vipuri visivyoepukika kwa kutengeneza 'kolajeni (gundi ya chembe)' inayojenga mwili. Vikipungua kwa miezi, gundi ya chembe za mwili mzima hukatika vipande vipande, mishipa midogo sana ya fizi, ngozi na viungo hupasuka kila mahali, na damu huvuja taratibu kutoka ndani: ugonjwa wa kutisha wa 'kiseyeye', na mwishoni hufa. Si kujaza tumbo tu, bali kuchukua kiasi kidogo cha vitamini na madini, hiyo ndiyo kweli ya lishe inayodumisha mfumo wa uhai." },
  { id:30, topic:"Homa ni ulinzi", emoji:"🤒",
    question:"Vijidudu vya mafua au maambukizi vinapoingia mwilini, mwili hutetemeka na homa kali ya zaidi ya nyuzi 38 hutokea. Kwa nini usishushe homa kwa nguvu kwa dawa mara moja, sababu ya kitabibu ni ipi?",
    choices:["Kushusha homa ghafla hugeuza maji yote ya mwili kuwa maji ya moto","Homa ni mwitikio sahihi wa ulinzi: ubongo hupandisha joto kwa makusudi ili timu ya kinga ipigane vizuri zaidi na kusimamisha kuzaliana kwa vijidudu na virusi, ambavyo ni dhaifu kwa joto","Kushusha homa hufanya nywele zote za kichwa zinyonyoke","Unapokuwa na homa kali, kasi yako ya kukimbia huongezeka"],
    answerIndex:1,
    explanation:"Hongera! Kwa hili, maswali 30 ya kwanza ya 'Wise World 3' yamekamilika. Watu wengi huelewa vibaya kwamba 'homa ni kitu kibaya, shusha mara moja', lakini huo ni mkosi mkubwa. Vijidudu na virusi vingi vinavyovamia mwili hupenda joto la kawaida la binadamu la 'karibu nyuzi 36' na huzaliana hapo kwa mlipuko zaidi. Lakini joto linapopanda hadi nyuzi 38-39, msogeo wa virusi hupooza na haviwezi tena kuzaliana. Kinyume chake, timu yetu ya kinga, kama chembe nyeupe za damu, husogea kwa nguvu na kasi mara nyingi zaidi wakati joto la mwili liko juu. Yaani homa ni mkakati wa ubongo wa kupandisha kwa makusudi 'joto la chumba' ili kupata ushindi katika vita. Kupoza kichwa, kuchukua maji mengi, na kuilinda homa ambayo mwili wako unapigania, bila kuishusha kwa nguvu, na kupumzika, hiyo ndiyo hekima bora zaidi ya tiba ya kunusurika ili isiwe ugonjwa mzito." },
  { id:31, topic:"Faida ya mgawanyo wa kazi", emoji:"🛠️",
    question:"Wakati watu wazima wa jamii hawafanyi wote kazi ile ile, bali wanagawanyika katika kazi tofauti kama mkulima, seremala, na daktari ('mgawanyo wa kazi'), faida kubwa zaidi ni ipi?",
    choices:["Wote wakifanya kazi ile ile, inakuwa vigumu kukumbuka nyuso za kila mmoja","Unaondoa kikomo cha muda cha mtu mmoja kujifunza vyombo na ujuzi vyote kutoka sufuri, na kila mtaalamu akishirikiana, uzalishaji wa jamii nzima unalipuka juu","Kufanya mgawanyo wa kazi kunaongeza maradufu saa za kazi kila siku","Kadiri aina za kazi zinavyozidi, ndivyo inavyoonekana yenye shamrashamra na furaha"],
    answerIndex:1,
    explanation:"Kama hapakuwa na mgawanyo wa kazi, ungelazimika kuotesha mwenyewe ngano unayoila, kujenga mwenyewe nyumba unayoishi, na ukiugua, kutengeneza mwenyewe dawa. Hivi saa za siku hazingetosha kamwe, kila kitu kingebaki nusu, na kuishi kwa wingi kungekuwa haiwezekani. Binadamu walibuni hekima kubwa zaidi, 'mgawanyo wa kazi', ambapo kila mmoja anajikita katika kazi moja na kukamilisha ujuzi wake, na kubadilishana bidhaa na huduma zilizotengenezwa. Hii inaruhusu kuzalisha matokeo bora mara nyingi kwa juhudi kidogo, na huunda jamii tajiri ambapo tunashikiliana uhai kwa ufanisi wa juu kabisa." },
  { id:32, topic:"Pesa ni uaminifu", emoji:"💵",
    question:"Noti za karatasi (sarafu) tunazotumia kila siku ni vipande vya karatasi tu, basi kwa nini tunaweza kuzitumia kubadilisha kwa chakula kitamu na vyombo vizuri?",
    choices:["Ndani ya karatasi hiyo kuna kiungo cha kichawi kinachoshibisha tumbo","Kwa sababu kila mtu katika jamii anaweka kwenye noti hiyo 'uaminifu' wa pamoja: 'nikitoa karatasi hii, daima nitaweza kuibadilisha kwa bidhaa za thamani ile ile'","Kwa sababu sheria inasema mchoro wa noti ndio mzuri zaidi duniani","Kwa sababu uzito wa karatasi ni kama bonge la chuma"],
    answerIndex:1,
    explanation:"Asili ya kweli ya pesa (sarafu) si thamani yake kama kitu, bali ni 'mfumo wa uaminifu' kati ya watu. Zamani sana watu walibadilishana dhahabu na fedha zenyewe, lakini zilikuwa nzito na za usumbufu kubeba, hivyo nchi na jamii zilitengeneza chombo cha karatasi cha pamoja, 'noti', ambacho zinakihakikishia uaminifu. Kwa sababu ahadi na uaminifu vilivyo vichwani mwa wote vinapatana - 'hata nikipokea noti, nitaweza kuitumia vivyo hivyo dukani lijalo' - kipande cha karatasi tu kina nguvu yenye uwezo wa kubadilishwa kwa bidhaa. Katika jamii ambayo uaminifu umeporomoka, noti zinabadilika, kihalisia, kuwa vipande visivyo na thamani." },
  { id:33, topic:"Kipimo cha thamani", emoji:"📏",
    question:"Ikilinganishwa na maisha ya kubadilishana bidhaa, mfumo gani rahisi na wa haki ulizaliwa kwa kuingiza 'pesa (sarafu)' katikati ya kununua na kuuza?",
    choices:["Kutumia pesa kunashusha uzito wa bidhaa zote nusu","Thamani ya bidhaa zote inaweza kuonyeshwa kwa rula ya pamoja iitwayo 'namba', hivyo hata bidhaa za aina tofauti zinaweza daima kulinganishwa kwa bei kwa haki na kufanyiwa biashara (kipimo cha thamani)","Kutumia pesa kunamaanisha muuzaji daima anakupa zawadi","Muda wa muamala daima unakuwa sekunde 1 sawasawa"],
    answerIndex:1,
    explanation:"Pesa ina jukumu muhimu la 'kipimo cha thamani', kupima thamani ya bidhaa zote kwa namba. Katika dunia ya kubadilishana bidhaa bila pesa, ungelazimika kujadiliana na mwingine kila mara - 'kondoo huyu ni sawa na samaki wangapi, magunia mangapi ya ngano, mashoka mangapi?' - na hesabu ingekuwa fujo. Lakini pesa, rula ya pamoja, ilipoonekana katikati, kila kitu kingeweza kulinganishwa kwa namba ile ile, kama 'kondoo ni sarafu 10,000, samaki ni sarafu 500'. Kwa hii wote waliweza kufanya biashara kwa haki na kwa wepesi, bila mkanganyiko na bila hasara." },
  { id:34, topic:"Hifadhi ya thamani", emoji:"💰",
    question:"Unapopata chakula kingi kama samaki na mboga, kwa nini ni bora kukibadilisha mara moja kuwa 'pesa (sarafu)' na kukiweka akiba, kuliko kukiweka kama kilivyo?",
    choices:["Kuweka pesa akiba kunafanya nguvu zibubujike zenyewe kutoka ndani ya mwili","Chakula kinaoza katika siku chache na thamani yake inakuwa sufuri, lakini kwa kukibadilisha kuwa pesa unaweza 'kuhifadhi tunda la kazi yako kwa miaka bila kukiacha kioze' (hifadhi ya thamani)","Kukibadilisha kuwa pesa kunaongeza maradufu kiasi cha chakula","Ukiweka pesa mfukoni, inang'aa yenyewe"],
    answerIndex:1,
    explanation:"Kazi kubwa ya tatu ya pesa ni 'hifadhi ya thamani'. Hata ukifanya kazi kwa bidii na kuvuna kiasi kikubwa cha samaki au ndizi, ukiviacha kama vilivyo vinaoza katika siku chache, na fuwele ya juhudi yako inatoweka. Hivi huwezi kuweka akiba ya wingi kwa mgogoro wa baadaye (njaa au jeraha). Lakini kwa kubadilisha mavuno haraka kuwa pesa, 'chombo kisichooza', unaweza kuhifadhi thamani uliyoifanyia kazi, sawasawa, kama kapsuli ya wakati, hata miaka kumi mbele. Pesa ni ghala salama la kulinda nafsi yako ya baadaye." },
  { id:35, topic:"Uhamisho wa thamani", emoji:"👛",
    question:"Katika biashara, badala ya kubeba viazi vizito au ng'ombe kama vilivyo, faida nzuri ni ipi, kwa upande wa kuhama, ya kufanya biashara kwa kutumia 'pesa (sarafu)'?",
    choices:["Kuwa na pesa kunafanya miguu yako ikimbie mara mbili zaidi","Unaweza kuiweka kwenye pochi au mfuko mdogo na 'kubeba thamani ya mali yako kwa wepesi hadi mahali popote pa mbali' (uhamisho wa thamani)","Pesa inaelea juu ya maji, hivyo unaweza kuvuka bahari kwa kuogelea","Kwenda mbali kunafanya thamani ya pesa iongezeke yenyewe"],
    answerIndex:1,
    explanation:"Pesa ina kazi ya 'uhamisho wa thamani'. Ukitaka kwenda mji wa mbali na kununua dawa adimu au chombo imara, bila pesa ungelazimika kuburuza kwa miguu siku nyingi mazao mazito au ng'ombe wa mifugo. Hatari ya kushambuliwa na wezi njiani au ng'ombe kufa ni kubwa sana. Lakini ukibadilisha wingi huo mara moja kuwa umbo jepesi na dogo - noti au sarafu - unaweza kuificha kwenye pochi na kubeba kwa usalama thamani kubwa hadi nchi ya mbali papo hapo na kufanya biashara. Ni miundombinu yenye nguvu ili uchumi uvuke mipaka." },
  { id:36, topic:"Mkataba", emoji:"📝",
    question:"Unapotoa ahadi ya kazi na mtu, au kununua na kuuza bidhaa, kwa nini lazima daima uache 'mkataba' ulioandikwa kwenye karatasi, si ahadi ya mdomo tu?",
    choices:["Kuandika mikataba mingi kunazoeza misuli ya mkono na kukufanya mwenye nguvu","Kumbukumbu ya binadamu inakuwa fifi na kubadilika kwa wakati, hivyo kufunga maudhui ya ahadi kwa maandishi kunazuia baadaye mizozo ya 'ulisema, hukusema' na udanganyifu, na kukulinda","Ahadi iliyoandikwa Mungu anaitimiza kiotomatiki kwa uchawi","Kushikilia hati ya karatasi kunakufanya uonekane muhimu"],
    answerIndex:1,
    explanation:"Mojawapo ya hati muhimu zaidi za kunusurika katika jamii ni 'mkataba'. Hata rafiki wa karibu kiasi gani au mtu mzima aonekane wa kuaminika kiasi gani, hupaswi kumaliza kwa mdomo tu ahadi kama 'nitalipa kiasi hiki cha pesa baada ya miezi kadhaa' au 'nitamaliza kazi hii hadi wakati huo'. Kwa wakati, hakika atatokea mtu anayeandika upya kumbukumbu yake kwa manufaa yake au anayedanganya ili kujiepusha. Kwa kuacha ushahidi ulioandikwa wenye saini na muhuri za wote wawili, hata mwingine akivunja ahadi, unaweza kuomba nguvu ya watu wazima wa karibu au sheria na kujilinda kihalali. Mkataba ni fulana ya kuzuia risasi ya kutembea salama katika ulimwengu wa watu wazima." },
  { id:37, topic:"Mahitaji na ugavi", emoji:"⚖️",
    question:"Sokoni, mavuno ya maharagwe fulani yalishuka sana kwa sababu ya mvua kubwa, na idadi ya maharagwe duniani ikawa ndogo sana. Lakini idadi ya wanaoyataka ni kubwa. Wakati huu, bei ya maharagwe inabadilikaje?",
    choices:["Kwa kuwa ni machache na hakuna anayeweza kununua, bei inakuwa sufuri","Inakuwa mvutano kati ya wanaoyataka, na wanaongezeka wanaokubali kulipa pesa zaidi ili kununua, hivyo bei ya maharagwe 'inapanda ghafla kwa kasi'","Lolote litokee, bei ya bidhaa zote daima ni thabiti duniani kote","Maharagwe yanakua kwa ukubwa na bei inashuka kidogo"],
    answerIndex:1,
    explanation:"Hii ni sheria kamili iliyo msingi zaidi wa uchumi: 'mahitaji (kiasi kinachotakiwa) na ugavi (kiasi kinachouzwa)'. Bei ya bidhaa haiamuliwi kwa hamaki ya mtu, bali kiotomatiki kwa usawa (mizani) wa hivi viwili. Idadi ya wanaotaka kununua (mahitaji) inapokuwa kubwa kupita kiasi kuliko idadi ya bidhaa za kuuza (ugavi), thamani ya bidhaa (thamani ya uadimu) inaruka juu. Ukijua mfumo huu, unaweza kwa utulivu kutabiri mbele - 'kipi kinakosekana sasa na kipi kinatafutwa' - na kuweka mpango wa biashara unaotatua kwa werevu matatizo ya jamii." },
  { id:38, topic:"Maana ya faida", emoji:"📈",
    question:"Ni nini maana ya kweli ya kimsingi katika jamii ya kupata 'faida' kwa kufanya biashara?",
    choices:["Kudanganya wengine pia, kuishi kwa raha na anasa wewe mwenyewe pekee","Kama matokeo ya kutatua kinachowasumbua wengine (usumbufu au wasiwasi) kwa hekima na kazi yako, kupokea kwa haki thamani inayozidi gharama uliyotumia (gharama ya kununua), kama 'malipo ya msaada wako na shukrani yao'","Kupokea pesa kutoka kwa nchi mwenyewe na kuziweka mfukoni","Kufanya jina la duka lako mashuhuri zaidi duniani"],
    answerIndex:1,
    explanation:"Kupata faida katika biashara si jambo baya kamwe, wala kunyang'anya pesa kwa mtu. Faida inahesabiwa kama '(bei ya kuuza) toa (gharama ya kununua au ya kutengeneza)'. Mfano, kwa asiyeweza kwenda chemchemi safi ya mbali, wewe unabeba ndoo na kuteka maji badala yake, na unagawa kwa sarafu 20 maji uliyonunua kwa 10. Faida ya sarafu 10 ya tofauti hii ni malipo ya shukrani ya haki kwa kuwa umeondoa 'usumbufu wake wa kuhama'. Kadiri unavyotatua maumivu ya mtu katika jamii, ndivyo uaminifu uitwao faida unavyokusanyika mikononi mwako." },
  { id:39, topic:"Kazi ya benki", emoji:"🏦",
    question:"Ni nini lengo la kimsingi zaidi ambalo kwalo mahali palipozaliwa zamani liitwalo 'benki' palithaminiwa na watu wa jamii na kuendelea?",
    choices:["Kupamba chumba kwa noti nyingi nzuri na kuzitazama","Kwa kuwa kuweka pesa nyingi nyumbani kunahatarisha kuibwa na wezi, ili pesa 'zihifadhiwe kwa usalama (akiba)' katika sefu imara, na kufanya uhamisho salama (malipo) hadi miji ya mbali","Kuweka pesa akiba kunaongeza ukubwa wa noti yenyewe","Kutangaza kwa wote ni nani mwenye pesa nyingi zaidi na kujivuna"],
    answerIndex:1,
    explanation:"Lengo la kwanza la kuzaliwa kwa benki ni 'hitaji la kuhifadhi kwa usalama'. Kuhifadhi sarafu za dhahabu au noti nyingi nyumbani kwako kuna hatari kubwa za kuteketea katika moto, au kushambuliwa na wanyang'anyi na hata kupoteza uhai. Hivyo ulitengenezwa mfumo wa 'kuweka' pesa mahali penye sefu na ulinzi imara zaidi katika jamii. Ukiweka pesa benki, zinakuwa kumbukumbu ya namba katika kijitabu, na unaweza kulinda mali yako ya thamani 100% dhidi ya wizi. Ni ngome ya hekima inayosimamia pesa kwa usalama si kama 'bonge la karatasi la kimwili', bali kama 'namba zinazoaminiwa'." },
  { id:40, topic:"Deni na riba", emoji:"💸",
    question:"Unapokopa 'pesa (deni)' kutoka kwa mtu mwingine au benki, ni mfumo gani wa kiuchumi wa kutisha usiopaswa kuusahau kamwe?",
    choices:["Kukopa pesa kunafupisha kimo chako kidogo","Si tu kurudisha pesa uliyokopa (rasilimali) kama ilivyo, bali badala ya muda uliokopa, lazima daima uongeze pesa za ziada juu (riba) na urudishe zaidi","Sheria kwamba ukishakopa pesa, huruhusiwi kununua tena kamwe","Kwamba pesa uliyokopa unaweza kuifanya yako bila kuirudisha"],
    answerIndex:1,
    explanation:"Kukopa pesa ni 'kukopa kabla' kazi na uhuru wa nafsi yako ya baadaye. Deni daima lina ada ya kukodi iitwayo 'riba' au 'kiwango'. Mfano, ukikopa sarafu 10,000 na sheria ya riba ni 10%, baadaye lazima urudishe sarafu 11,000. Ukidharau mfumo huu wa riba, kadiri unavyolipa, hesabu ya riba inazidi kuvimba (kama mpira wa theluji), na unaishia maisha kama mtumwa, ukilipa pesa kwa ajili ya wengine maisha yako yote. Isipokuwa una mpango wa hakika wa kukuza pesa, lazima uepuke kabisa deni la urahisi." },
  { id:41, topic:"Uwekezaji na matumizi", emoji:"🌱",
    question:"Kuna njia mbili za kutumia pesa. Tofauti na 'matumizi', kununua peremende unazokula sasa zinazotoweka papo hapo, ni upi mfano halisi wa 'uwekezaji', kutumia pesa kuongeza nguvu na wingi wako wa baadaye?",
    choices:["Kununua nguo nyingi zenye kung'aa za mtindo wa hivi punde","Kununua 'chombo' imara cha kuanzisha kazi mpya yako, au kutumia pesa kwa 'vitabu (kusoma)' ili kupata maarifa","Kumwaga pesa zako zote kwenye kamari ya kasino au michezo","Kuweka pesa juu ya sahani na kuzikodolea macho tu"],
    answerIndex:1,
    explanation:"Ukitumia pesa tu (matumizi/ubadhirifu), pesa zinatoweka tu kutoka mikononi mwako na mwisho. Lakini mwenye hekima anatumia pesa kama 'mbegu (uwekezaji) ya kuzidisha nguvu yake ya baadaye mara nyingi'. Mfano, aliyekuwa akichonga mbao kwa mkono akiweka akiba na kununua shoka bora (chombo), kuanzia kesho anaweza kutengeneza kuni mara 10 kwa muda ule ule, na pesa zinazoingia zinaongezeka kwa kasi. Pia kununua na kusoma vitabu vya tiba au sayansi ni 'uwekezaji binafsi' wenye nguvu zaidi, unaobadilisha ubongo wako kuwa chombo bora cha kuchuma. Sogea ukihesabu utumie pesa kwa nini ili mustakabali wako uwe tajiri." },
  { id:42, topic:"Kodi na bidhaa za umma", emoji:"🌉",
    question:"Kwa nini mfumo ni wa lazima kabisa ambapo kila mtu katika kijiji au mji anachangia kidogo kidogo sehemu ya pesa anayochuma - 'kodi' au pesa zinazokusanywa (fedha za jamii)?",
    choices:["Kutumia pesa zilizokusanywa na kufanya sherehe kubwa kila siku wote pamoja","Kudumisha wote pamoja 'kisima cha pamoja, barabara imara, madaraja makubwa, na hospitali zinazookoa wagonjwa (bidhaa za umma)' ambazo pesa za mtu mmoja hazingeweza kamwe kutengeneza, na kulinda jamii","Kukusanya pesa nyingi na kuzizika ndani sana ardhini","Kufanya nyumba ya kiongozi fulani muhimu ya kifahari kama kasri"],
    answerIndex:1,
    explanation:"Kama jamii haingekuwa na kodi wala pesa zinazochangwa pamoja (fedha za umma) kabisa, hakuna mtu mmoja angeweza kulipa pesa kubwa kujenga daraja kubwa au kusakafia barabara ndefu. Barabara zikiwa mbovu, hakuna anayeweza kuhama kwa hofu ya kuumia, na biashara na maisha vinaporomoka kabisa. Ndio maana wote wanachangia kidogo na kuzikusanya, kujenga na kudumisha 'miundombinu ya pamoja ambayo hakuna anayeweza kuijenga peke yake (bidhaa za umma)'. Mfumo huu wa kusaidiana (usalama wa kijamii na msaada wa umma) ndio msingi wenyewe wa ustawi unaolinda usalama wa dunia." },
  { id:43, topic:"Thamani ya kufanya kazi", emoji:"💪",
    question:"Ni nini thamani ya kimsingi na kubwa zaidi, kama binadamu, ya 'kufanya kazi (kuhangaika)' katika jamii?",
    choices:["Kuamriwa na mtu na kusogeza mwili tu kama roboti","Kutumia nishati yako nzuri ya 'muda, ujuzi, na hekima' kutatua 'usumbufu au tatizo (maumivu)' la mtu katika jamii na kufanya dunia bora kuliko jana","Kufanya kazi saa zaidi ya wengine, kuvunja mwili, na kujivuna","Kupata ruhusa ya kufanya lolote mradi unapokea pesa"],
    answerIndex:1,
    explanation:"Sura ya kweli ya kufanya kazi si kazi ya kupokea pesa tu. Ni kitendo cha kuumba thamani: kutoa kwa jamii muda wako wa thamani wa uhai na ujuzi wako na kubadilisha 'niko taabani!' la mtu kuwa 'asante Mungu!'. Mkulima akitengeneza chakula kitamu anafuta njaa, na daktari akitoa matibabu anafuta maumivu. Kupitia kufanya kazi, unahitajika ndani ya jamii na kuwa kipande muhimu cha fumbo kinachoshikilia uhai wa mtu. Kujua lengo la kufanya kazi kwa usahihi kunaimarisha fahari ya maisha yako na miguu ya kujitegemea kwako." },
  { id:44, topic:"Hatari ya ukiritimba", emoji:"👑",
    question:"Wakati kuna 'duka moja tu' linalouza dawa fulani muhimu sokoni (ukiritimba), kwa nini ni hatari sana kwa mnunuzi?",
    choices:["Kwa duka moja tu, kukumbuka jina la duka kunakuwa usumbufu","Kwa kuwa hakuna mshindani wa kushindana, hata mwenye duka akipandisha bei kwa udhalimu hadi 'bei kubwa mno', mnunuzi hana chaguo ila kulipa pesa hiyo kubwa ili aishi","Kwa duka moja, umbo la dawa linabadilika kuwa pembetatu lenyewe","Hakuna hatari; duka moja ni salama zaidi daima"],
    answerIndex:1,
    explanation:"Hali isiyokuwa na mshindani hata mmoja sokoni inaitwa 'ukiritimba'. Ukiritimba ukitokea, mizani nzuri ya mahitaji na ugavi inavunjika, na muuzaji anaweza kudhibiti bei kwa uhuru kama mungu. Hata dawa inayopaswa kuuzwa sarafu 10 ikiambiwa 'ni sarafu 10,000; kama hupendi, usinunue na uugue', unyonyaji unatokea ambapo mali yako yote inanyang'anywa ili uishi. Ndio maana jamii yenye afya inalinda mfumo wa 'ushindani', ambapo kuna maduka kadhaa yanayouza bidhaa zinazofanana na kushindana, na kuweka kizuizi ili bei zisipande kwa udhalimu." },
  { id:45, topic:"Mtego wa kizuri mno", emoji:"🎣",
    question:"Mtu mzima asiyejulikana alikupa mwaliko mtamu: 'Ukinisaidia kazi hii, nakupa papo hapo kiasi kikubwa cha pesa ambacho hujawahi kuona'. Ufanye nini?",
    choices:["Kwa kuwa ni fursa ya kupata kiasi kikubwa, kusaidia mara moja bila kufikiri","Kukataa kabisa na kuondoka mahali hapo. Katika dunia hii, 'kazi isiyo na hatari ambapo unapata kiasi kikubwa kwa urahisi' 100% haipo kamwe; ni mtego wa kukufanya ubebe sehemu ya uhalifu na kuharibu maisha yako","Kualika marafiki wengi na kufanya kazi hiyo wote pamoja","Kutengeneza papo hapo mkataba wa karatasi wa kiasi utakachopokea"],
    answerIndex:1,
    explanation:"Sheria baridi na kamili ya uchumi ni 'ukubwa wa malipo (pesa unayopokea) ni sawia kabisa na ukubwa wa thamani uliyotoa na ukubwa wa hatari unayobeba'. Nyuma ya hadithi ya kumpa mtoto asiye na ujuzi maalum wowote kiasi kikubwa papo hapo, 100% umefichwa mtego wa uhalifu mkali - 'kusafirisha dawa za kulevya' au kuwa 'mpokeaji wa ulaghai unaodanganya watu na kuchukua pesa zao' - unaokufanya ukamatwe na polisi mara moja na kumaliza kabisa maisha yako. Hekima ya kutahadhari kwa jicho la mantiki dhidi ya anayekaribia kwa maneno matamu na kukataa kabisa inalinda uhuru wako maisha yote." },
  { id:46, topic:"Mfumuko wa bei", emoji:"🎈",
    question:"Wakati 'kiasi cha jumla cha pesa' kinachozunguka duniani kinachapishwa kati ya nchi na benki kwa kiasi cha kupita kiasi na kuongezeka mno, kinachotokea kwa bei za jamii nzima (bei ya vitu) ni nini?",
    choices:["Kwa kuwa pesa imeongezeka sana, bei ya vitu vyote inashuka hadi sarafu 1","Kwa kuwa thamani ya uadimu ya pesa (uadimu wake) inashuka na kukaribia kipande cha karatasi, kwa uwiano 'bei ya vitu vyote inapanda ghafla kwa kasi (mfumuko wa bei)'","Hata kiasi cha pesa kibadilike, bei ya vitu haibadiliki kamwe duniani","Vitu vinaanza kubadilika kuwa umbo la noti"],
    answerIndex:1,
    explanation:"Huu ni mfumo wa 'mfumuko wa bei', ugonjwa wenye nguvu wa uchumi. Ingekuwaje kama nchi ingechapisha noti bila kikomo na kuzigawa kwa wote? Kwa kuwa wote wana pesa nyingi, sasa unatokea mvutano wa 'vitu'. Kisha unatokea mtukio wa kutisha ambapo mkate uliouzwa jana kwa sarafu 100 hauwezi kununuliwa siku inayofuata bila sarafu 10,000, na kesho kutwa bila sarafu 1,000,000. Thamani ya pesa inaporomoka, na nguvu ya pesa uliyoiweka akiba kwa shida inakuwa takataka papo hapo. Kujua usawa wa 'kiasi' cha pesa na 'idadi' ya vitu kunakupa mtazamo mpana wa dunia." },
  { id:47, topic:"Mtego wa kulipa baadaye", emoji:"💳",
    question:"Ni upi mtego mkubwa zaidi uliofichwa wa mfumo (mkopo) ambapo 'sina pesa sasa, lakini nikionyesha kadi hii (au nikitoa ahadi) naweza kununua sasa na kulipa mwezi ujao'?",
    choices:["Mwezi ujao, chombo ulichonunua kinatoweka chenyewe","Kwa kuwa pesa haipungui kutoka pochi yako sasa, hisia yako ya kiasi gani unavyozidi kuwa maskini sasa inaganda ganzi, na unaishia kubeba deni ambalo nafsi yako ya baadaye haitaweza kulilipa kamwe","Ukipoteza kadi, jina lako linabadilika kabisa","Wakati wa kununua, uzito wa mwili wako wote unaongezeka maradufu"],
    answerIndex:1,
    explanation:"Kadi za mkopo na kuandika deni (mkopo) ni vyombo rahisi sana, lakini pia mtego hatari unaopiga sehemu dhaifu ya ubongo wa binadamu. 'Noti' zinapopungua kimwili kutoka pochi, binadamu anahisi maumivu makali (hofu ya kupoteza) na anaweza kukanyaga breki, lakini kwa ahadi ya namba (kulipa baadaye) ubongo hauhisi maumivu kabisa. Hivyo unatumia kwa wepesi 'pesa ambayo nafsi yako ya baadaye inapaswa kuchuma kwa kazi ngumu'. Mwezi ujao, ukishindwa kulipa, riba inaongezwa na unafilisika papo hapo. Kuishi ndani ya mipaka ya fedha taslimu mkononi ndio msingi wa kujitegemea kiuchumi." },
  { id:48, topic:"Gharama ya fursa", emoji:"⏳",
    question:"Una 'saa 1' ya muda, au 'sarafu 1,000' za pesa. Unapochagua ufanye nini nayo, dhana ya kiuchumi usiyopaswa kuisahau kamwe, 'gharama ya fursa', inamaanisha nini?",
    choices:["Ada maalum unayopaswa kulipa nchi kila unaponunua","Kuchagua chaguo moja kunamaanisha wakati huo huo kwamba 'unaachilia na kutupa fursa au thamani nyingine nzuri ambayo ungeweza kuipata kama usingelichagua' (mbadala)","Mfumo ambapo kutumia chombo kwa muda mrefu kunaongeza thamani yake chenyewe","Inamaanisha muda unaolala nyumbani bila kufanya chochote haugharimu hata sarafu moja"],
    answerIndex:1,
    explanation:"Rasilimali zetu, kama muda na pesa, ni 'zenye kikomo kabisa (zina mipaka)' kwa kila mtu duniani. Ukinunua mchezo kwa sarafu 1,000, fursa ya kununua kitabu cha kusoma kwa sarafu 1,000 hizo inatoweka milele. Ukitumia saa 1 kuchezea, fursa ya kutumia saa hiyo kufanya kazi au kusoma inatoweka. 'Thamani nyingine kubwa zaidi unayoitolea muhanga kwa siri nyuma ya pazia kwa kuchagua kitu' inaitwa 'gharama ya fursa'. Mwenye hekima anayejua hili, anapoamua kitu, anapima 'kwa kufanya hili, ninapoteza nini badala yake?' na anaweza kuchukua chaguo lisilo baya sana." },
  { id:49, topic:"Kuchangia pamoja", emoji:"🤝",
    question:"Wakulima wa kijiji wanataka sana kutumia 'mashine kubwa ya kilimo (trekta)' iliyo ghali mno kwa mtu mmoja kuinunua, ni ipi hekima ya kiuchumi yenye busara zaidi ya kuipata kwa kuunganisha nguvu?",
    choices:["Kuomba kila siku na kusubiri mtu awe tajiri na akununulie zawadi","Wote wachangie kidogo kidogo na kuzikusanya (ushirika), wanunue mashine moja kama chombo cha pamoja cha wote, na waitumie kwa zamu kwa ratiba ya haki","Kunyemelea usiku kwenye shamba la mji mwingine na kuiba mashine kimya kimya","Kuacha kununua mashine na wote kufanya kwa mkono maisha yote"],
    answerIndex:1,
    explanation:"Hata mtaji wa mtu mmoja (pesa aliyo nayo) ukiwa mdogo, watu wengi wakikusanyika kwa lengo lile lile na kuchangia pesa kufanya bonge moja lenye nguvu, mfumo huu wa kiuchumi unaotatua tatizo kubwa unaitwa hekima ya 'ushirika' au 'fedha ndogo'. Ukitumia mashine iliyonunuliwa kwa pesa zilizokusanywa, mavuno ya shamba la wote yanaongezeka mara nyingi, na inarudi kwa wote pesa zaidi ya walizochangia. Badala ya kutegemea tajiri mwenye nguvu, wanyonge wanaamua sheria kama walio sawa, wanachangia fedha pamoja, na kuzalisha wingi kwa kujitegemea: mfumo mzuri zaidi wa eneo la kiuchumi." },
  { id:50, topic:"Muamala kati ya walio sawa", emoji:"🛒",
    question:"Unaponunua na kulipa pesa, ni upi uhusiano sahihi, kama binadamu, kati ya 'upande unaolipa (mnunuzi)' na 'upande unaouza (muuzaji)' anayepokea noti na kukabidhi bidhaa?",
    choices:["Mteja anayelipa ni mkubwa kama mungu, hivyo anaweza kumdhulumu muuzaji","Muuzaji anatoa 'bidhaa ya thamani nzuri' na mnunuzi anatoa 'pesa ya kuaminika ya thamani ile ile' - ni 'washirika walio sawa kabisa na walingana' wenye msingi wa makubaliano ya pande mbili","Duka linalouza bidhaa ni kubwa zaidi, hivyo mnunuzi sharti daima ainame na kutii","Yupi mkubwa zaidi inaamuliwa na hali ya hewa ya siku hiyo"],
    answerIndex:1,
    explanation:"Kosa baya la kawaida sana katika jamii ni dhana potofu kwamba 'upande unaolipa unaruhusiwa kujivuna'. Biashara si juu-chini ya nguvu, bali 'ubadilishanaji ulio sawa na wenye thamani sawa' wa thamani ya kila mmoja. Bila chombo rahisi alichotengeneza muuzaji kwa shida, sarafu yako ya 100 inabaki bonge la chuma tu. Kinyume chake, bila pesa yako, muuzaji hawezi kununua vitu vingine. Kila mmoja kuonyeshana heshima - 'asante kwa kuuza', 'asante kwa kununua' - ndio mafuta ya kulainisha jamii na msingi bora wa kuendeleza eneo la kiuchumi lenye upole." },
  { id:51, topic:"Kuona ndani ya matangazo", emoji:"📺",
    question:"Uliona 'tangazo' kwenye TV, mtandao, mabango, n.k., likionyesha bidhaa kuwa ya kuvutia mno. Ujihadhari na nini unapoliona?",
    choices:["Linalosemwa na tangazo ni kweli kamili 100%, hivyo unapaswa kuamini yote na kununua mara moja","Kwa kuwa lengo la tangazo ni 'kukufanya utumie pesa ili wapate faida', tilia shaka mara moja muonekano na maneno yaliyopambwa vizuri, na hesabu kwa utulivu kama lina thamani ya msingi unayohitaji kweli","Ukiona tangazo, waambie marafiki wote 'usiponunua hii utaugua'","Wote wanaotokea katika matangazo ni watu wabaya, hivyo unapaswa kukasirika daima"],
    answerIndex:1,
    explanation:"Mbinu za matangazo na masoko zimetengenezwa kuchunguza kwa kina hisia za binadamu 'naitaka!' na 'wote wanayo, mimi pia nataka kujivuna!' (sehemu dhaifu ya saikolojia), ili kukufanya ufungue pochi. Hata kibonzo cha kupendeza au mtu mashuhuri akisema 'ni bora', hiyo ni kauli tu wanayoisema baada ya kupokea pesa ya tangazo. Anayemeza taarifa ya vyombo vya habari kama ilivyo (bila uelewa wa vyombo vya habari) anachezeshwa maisha yote kwa faida ya wengine, na pochi yake inaachwa tupu. Kuwa na werevu wa kuona 'lengo lililo nyuma' ya taarifa." },
  { id:52, topic:"Jinsi bima inavyofanya kazi", emoji:"🛡️",
    question:"Tunauita nini mfumo wa kusaidiana wa pamoja duniani ambapo, dhidi ya mgogoro mkubwa wa bahati mbaya kama 'jeraha kubwa, ugonjwa mkubwa, au moto mkubwa wa nyumba' ambao hakuna anayejua lini na kwa nani utatokea, wote wanachangia kidogo kidogo kujiandaa?",
    choices:["Manunuzi","Bima (ushirika wa kusaidiana)","Ukiritimba","Akiba"],
    answerIndex:1,
    explanation:"Kama unaishi peke yako na ghafla unapata ugonjwa mkubwa unaohitaji mamilioni ya sarafu za gharama za matibabu, hauwezi kulipa na unapoteza uhai hivi hivi. Hivyo binadamu walibuni 'bima', ngao ya kiuchumi inayookoana kwa upole. Tangu wakiwa na afya, watu wengi wanachangia pesa kidogo - kama sarafu 100 kila mwezi - katika sefu kubwa moja na kuziweka akiba. Kisha mmoja wa wanachama anapopata kwa bahati mbaya jeraha kubwa, kutoka sefu hiyo inatolewa pesa kubwa kugharimia matibabu. Ni hekima nzuri zaidi ya binadamu ya kusambaza hatari: 'mmoja kwa wote, wote kwa mmoja'." },
  { id:53, topic:"Uvuvi kupita kiasi na uendelevu", emoji:"🐟",
    question:"Mvuvi, akisema 'nikivua wengi sasa naweza kupata faida kubwa', alivua kila siku kwa mpigo samaki wote wa baharini, bila kuacha hata mmoja, hadi samaki wadogo wachanga (uvuvi kupita kiasi). Kwa nini biashara hii itashindwa hakika baada ya miaka kadhaa na kuwa na njaa?",
    choices:["Kuvua samaki wengi mno kunamkasirisha mungu wa bahari na kubadilisha noti zote kuwa mchanga","Rasilimali za asili (mimea na wanyama) zina 'kasi ya kuzaliana' ya kuzaa watoto na kuongezeka, na ukiizidi na kuwaangamiza, utakachouza baadaye kinatoweka kabisa (kuporomoka kwa uendelevu)","Kuvua samaki wengi mno kunawafanya wazito mno hata mashua inaelea angani","Idadi ya samaki ikishuka, joto la maji ya bahari linapanda hadi nyuzi 100 na linakuwa hatari"],
    answerIndex:1,
    explanation:"Dhana isiyoweza kupuuzwa kamwe ili uchumi udumu milele ni 'uendelevu'. Baraka za asili za Dunia si chemchemi ibubujikayo bila kikomo. Kanuni kubwa ni kutumia samaki na miti ya msitu ndani ya mipaka ya kasi wanavyoongezeka kiasili, kama kupokea kidogo 'riba'. Mfanyabiashara mpumbavu anayefikiria faida ya papo hapo tu anaharibu kwa mikono yake asili, msingi, na baada ya miaka kadhaa anawafanya wote wawe na njaa na kujiangamiza. Kuwa na mtazamo mpana wa kuishi kwa busara huku ukiacha rasilimali kwa watoto wa baadaye." },
  { id:54, topic:"Ujuzi adimu", emoji:"🧠",
    question:"Mtu anayepokea 'mshahara (malipo)' mwingi kwa kazi yake katika jamii si mtu mwenye mwili mkubwa tu au anayejivuna, bali mtu wa sifa gani?",
    choices:["Mtu anayepiga kelele zaidi ya wote kila siku akiomba pesa","Mtu mwenye 'maarifa maalum, ujuzi wa juu, uzoefu wa kina' ambao hakuna mwingine anaweza kuiga kwa urahisi, na anayeweza kutatua matatizo makubwa ya jamii (kipaji adimu)","Mtu aliye bora zaidi duniani kwa kuzubaa katika saa za kazi","Mtu asiyetoka nje ya nyumba kila siku na analala tu kimya"],
    answerIndex:1,
    explanation:"Kanuni inayoamua kiasi cha mshahara nayo kwa kweli inasonga kulingana na sheria ya 'mahitaji na ugavi'. Kazi rahisi ambayo yeyote anaweza kuiga kwa sekunde 1 ina maelfu kwa maelfu ya watu duniani wanaoweza kuifanya badala yako, hivyo mshahara ni mdogo. Lakini mtu mwenye 'maarifa ya kitaalamu (ujuzi)' aliyopata kwa miaka mingi ya kusoma na juhudi - kama 'naweza kufanya upasuaji na kuponya ugonjwa huu mgumu' au 'naweza kutengeneza mfumo rahisi ambao hakuna anaweza' - anakuwa 'kipaji adimu chenye thamani kubwa' bila mbadala duniani. Ukitaka kupokea pesa nyingi, jibu sahihi si kupiga kelele, bali kunoa kichwa na ujuzi wako na kuwa kiumbe wa pekee anayetafutwa na jamii." },
  { id:55, topic:"Faida ya ushindani", emoji:"🏁",
    question:"Katika barabara ile ile yalitokea maduka mawili yanayouza nyama, 'Duka A' na 'Duka B' (ushindani). Maduka haya mawili kushindana yanaleta faida gani nzuri kwa wanunuzi (raia)?",
    choices:["Kwa maduka mawili, ladha ya nyama inabadilika yenyewe kuwa ladha ya chokoleti","Ili mnunuzi achague duka lao, kila moja linaanza kujitahidi kwa nguvu 'tufanye bei iwe rahisi zaidi' na 'tufanye nyama iwe mbichi na tamu zaidi'","Maduka mawili yanapigana ngumi vikali kila siku na unaweza kutazama","Kununua nyama daima kunachukua muda mara mbili"],
    answerIndex:1,
    explanation:"Washindani wanaouza bidhaa ile ile sokoni kushindana kunaitwa 'ushindani'. Kwa ushindani, wenye maduka hawawezi kuzubaa. Kama Duka A lingeuza nyama mbaya kwa bei kubwa, wateja wote wangeenda Duka B, na Duka A lingefilisika. Ndio maana kila moja linatumia kichwa kwa nguvu na kurudia jitihada za 'jinsi ya kuwafikishia wote vitu vya bei rahisi na bora zaidi'. Nishati hii ya ushindani ni injini inayofanya teknolojia, tiba, na ubora wa huduma za jamii nzima viendelee kuboreka zaidi na zaidi kila siku." },
  { id:56, topic:"Kuongeza uzalishaji", emoji:"🚜",
    question:"Tunauita nini, kwa lugha ya uchumi, maendeleo makubwa zaidi ya kuingiza 'vyombo vya chuma na matrekta (mashine)' vilivyotengenezwa kwa hekima, kutoka maisha ya kulima shamba kwa mkono?",
    choices:["Upanuzi wa matumizi","Kuongezeka kwa uzalishaji","Kufufuka kwa kubadilishana bidhaa","Kukamilika kwa ukiritimba"],
    answerIndex:1,
    explanation:"Hata kwa muda ule ule na nguvu ile ile ya kazi ya binadamu, kuongeza kiasi cha matokeo unayoweza kuzalisha mara nyingi au mara kumi kwa kutumia vyombo, mashine, na mifumo bora kunaitwa 'kuongezeka kwa uzalishaji'. Mtu aliyekuwa akichukua siku nzima kwa mkono kuchimba kiazi kimoja anaweza, kwa trekta, kuvuna viazi 100 kwa saa moja. Uzalishaji ukipanda, chakula na utajiri vinafurika kwa wingi katika jamii, na hata bila wote kufanya kazi saa nyingi wakitoka jasho kama watumwa, unaweza kuumbwa muda huru (mapumziko) ambapo wote wanaishi kwa usalama, kwa utulivu, na kwa wingi. Hekima inarahisisha kazi." },
  { id:57, topic:"Biashara na usambazaji", emoji:"🚢",
    question:"Ni nini maana nzuri ya mfumo wa 'biashara' au usambazaji, ambapo unabadilisha chumvi au dawa adimu isiyopatikana kamwe katika eneo lako, kwa nguo walizo nazo watu wa eneo la mbali tofauti?",
    choices:["Kwenda mbali kunachanganya majina ya nchi za kila mmoja na kuyafanya yatoweke","Kwa kubadilisha vilivyotengenezwa kwa kutumia 'nguvu za rasilimali na hali ya hewa ambazo kila ardhi ya Dunia inazimudu', wote wanaweza kufurahia kwa usawa utajiri ambao eneo moja peke yake lisingeupata kamwe","Kufanya biashara kunapunguza ukubwa wa Dunia nusu","Sheria kwamba kununua vitu vya mbali daima kunafanya ukungu uote kwenye noti"],
    answerIndex:1,
    explanation:"Duniani daima kuna kutokuwa na usawa wa rasilimali kulingana na eneo: maeneo ya baridi, maeneo ya joto, maeneo yenye milima mingi, maeneo karibu na bahari. Ukijifungia katika kijiji kimoja ukiishi kwa kujitegemea, watu wa maeneo yasiyopatikana chumvi wanaugua na kufa. Binadamu waliendeleza hekima ya 'usambazaji na biashara', kuunganisha na kubadilishana na maeneo ya mbali bidhaa maalum zilizotengenezwa kwa kutumia nguvu ya kila ardhi. Kwa hii imeundwa mtandao wa kusaidiana wa kiwango cha dunia, ambapo binadamu wote wa dunia wanagawana baraka za Dunia nzima na wanaweza kupata utajiri kwa usalama popote walipo." },
  { id:58, topic:"Kutolingana kwa taarifa", emoji:"🔍",
    question:"Unapokwenda kununua chombo, kwa nini hupaswi kununua mara moja kwa bei uliyoiona dukani la kwanza tu, bali kuzunguka maduka mengine kadhaa na soko kuona bei zao (kukusanya taarifa)?",
    choices:["Kutembea sana kunaimarisha msuguano wa nyayo za viatu vyako na kukufanya ukimbie haraka zaidi","Kama kuna 'pengo la taarifa (hali ambayo upande mmoja tu unajua ukweli)' kati ya muuzaji na mnunuzi, kuna hatari ya kufanywa ununue kwa bei kubwa isiyo ya haki (uchukuzi) juu ya bei ya soko na kupata hasara kubwa","Kuzunguka maduka mengi kunabadilisha rangi ya noti kuwa dhahabu nzuri","Sheria kwamba kununua dukani moja kunamhuzunisha mtu wa duka"],
    answerIndex:1,
    explanation:"Katika biashara daima kuna watu wabaya ambao, wakitumia ukweli kwamba mnunuzi hajui thamani halisi au bei ya soko (bei ya wastani) ya bidhaa, wanapandisha bei mara 10 ya kawaida na kujaribu kulaghai. Kwa lugha ya uchumi hii inaitwa 'kutolingana kwa taarifa'. Ili usiingie mtego huu, kabla ya kufungua pochi, kukusanya mwenyewe 'data za taarifa' kwa kufungua vitabu au kuzunguka maduka kadhaa ndio kizuizi chenye nguvu zaidi. Asiye na maarifa pesa yake inanyang'anywa, na mwenye taarifa sahihi anaweza kujilinda: huu ndio ukweli mgumu wa jamii." },
  { id:59, topic:"Mchango na kutoa", emoji:"🎁",
    question:"Bila kutaka malipo yoyote, kitendo cha kushiriki pesa au chakula chako na mtu asiye na pesa kweli aliye taabani, au mtu aliyejeruhiwa asiyeweza kufanya kazi (mchango au kutoa), ni ipi hekima yake ya kweli katika jamii?",
    choices:["Kutupa pesa tu mfereji na kujifanya maskini kwa makusudi kwa burudani","Kwa kuondoa katika jamii 'watu ambao katika kukata tamaa hawana ila kugeukia uhalifu' au 'watu wanaokufa njaa', na kuinua usalama (utulivu) na upole wa mji mzima, unaweza kulinda, kwa kurudi, kwa uhakika zaidi uhai wako mwenyewe na usalama wako wa baadaye","Kumpa mtu mwingine pesa kunafanya pesa mpya iangukie kutoka angani siku inayofuata","Kujivuna mbele ya mtu aliye taabani na kujihisi umekuwa mungu mkubwa"],
    answerIndex:1,
    explanation:"Asili ya kweli ya 'mchango au kutoa' bila malipo si kujitolea kwa kujitoa muhanga tu. Ni uwekezaji katika 'wavu wa usalama wa kijamii (mstari wa ulinzi)' wenye busara zaidi, kuzuia kuporomoka kwa kutisha kwa utulivu ambapo chini ya jamii inabomoka na watu maskini hawawezi kuishi bila kutenda uhalifu. Pesa ya upole uliyoitumia leo kuokoa maumivu ya mwingine inakurudia, kwa kurudi, kama thamani kubwa zaidi ya mji salama ambapo kesho wewe mwenyewe hushambuliwi na wezi. Kuzungusha upole ni hekima kubwa zaidi ya kijamii ya binadamu ya kunusurika bila kujiangamiza." },
  { id:60, topic:"Kuwa bwana wa pesa", emoji:"🧭",
    question:"Ukishajifunza katika Pakiti ya 2 ya programu hii 'Wise World 3' kuhusu mfumo wa uaminifu ulio nyuma ya uchumi mwingi na noti, ni lipi lengo la mwisho la kweli katika maisha yako mwenyewe?",
    choices:["Kulundika pesa nyingi zaidi duniani na kuwa mfalme anayeamuru wengine na kuwatawala kwa pesa","Si kuwa mtumwa wa pesa, chombo cha namba, bali kuona kwa usahihi 'mfumo wa uaminifu na shukrani' ulio nyuma ya noti, kutumia hekima yako kutawala pesa kwa upole, na kuimudu kulinda haki za binadamu na furaha yako na ya walio karibu nawe","Kununua hadi kikomo kila siku na kujaza nyumba takataka, mwisho","Kupata kombe kwa kujibu yote kwa usahihi na kuacha kabisa kusoma"],
    answerIndex:1,
    explanation:"Hongera! Kwa hii maswali 30 ya Pakiti ya 2 yote yamekamilika. Pesa, ukiitumia hatua moja vibaya, inabadilika kuwa mnyororo wa kutisha wa shetani unaowafanya watu watilie shaka, unaowafanya wasaliti, na kunyang'anya uhuru wa watu maisha yote. Lakini ukiwa na 'dira ya hekima ya kiuchumi' uliyojifunza katika maswali haya, hutadanganywa tena na namba za noti. Pesa si zaidi ya chombo rahisi kinachofanya 'nishati ya uaminifu' - inayozaliwa unapotatua tatizo la mtu - rahisi kubeba. Badala ya kutawaliwa na pesa, tumia hekima yako kuwa 'bwana anayeidhibiti kwa upole'. Na, kwa usawa na haki na wenzako duniani kote, shirikiana kujenga kwa mikono yako dunia yenye upole ambapo hakuna anayekufa njaa. Dunia nzima inashangilia kujitegemea kwako kwa busara!" },
  { id:61, topic:"Kasi dhidi ya usalama", emoji:"🛣️",
    question:"Unaelekea nyumbani kabla ya giza. Kuna 'njia ya kuzunguka iliyo salama na pana' inayochukua saa 1 kwa miguu, na 'njia ya mkato hatari' inayokufikisha nyumbani kwa dakika 10 lakini ardhi yake inaporomoka na kuna hatari ya kuanguka kutoka mwamba. Uchague ipi?",
    choices:["Nataka kufika nyumbani na kucheza haraka, kwa hiyo nakimbia kwa njia ya mkato hatari","Hata kama itachukua muda zaidi na kunichosha, narudi nyumbani kwa kutembea salama kupitia 'njia ya kuzunguka iliyo salama na pana', yenye hatari ndogo zaidi ya kupoteza maisha","Nafumba macho na kuamua ipi ni bora huku nikikimbia","Nakaa kwenye njia ya mkato na kupumzika hadi giza"],
    answerIndex:1,
    explanation:"Hili ni swali la msingi kuhusu 'kubadilishana' kati ya muda (kasi) na usalama, ambapo kupata kimoja maana yake ni kuachia kingine. Njia ya mkato ya dakika 10 inavutia, lakini ikiwa ardhi itaporomoka na ukaanguka kutoka mwamba, unaweza kuumia vibaya au kupoteza maisha na usiweze kamwe kurudi nyumbani. Kitendo chenye hatari kwamba 'mara 99 uko salama, lakini kushindwa mara moja kunamaliza maisha yako' ni chaguo baya zaidi kabisa, kiuchumi na kwa nafasi za kuishi, na hakipaswi kamwe kuchaguliwa. Hata ukilipa gharama ya muda wa ziada na miguu iliyochoka, kuchagua njia salama ambapo nafasi zako za kuishi ziko karibu na asilimia 100 ndiyo hekima ya kweli ya usimamizi wa hatari." },
  { id:62, topic:"Kuhifadhi chakula", emoji:"🧂",
    question:"Baada ya mavuno makubwa, una nyama na samaki wabichi zaidi ya mtu mmoja anavyoweza kula. Lakini vyote vitaoza ndani ya siku chache. Ni kitendo gani chenye busara na hatari ndogo zaidi hapa?",
    choices:["Ni hasara kuviacha vioze, kwa hiyo navila vyote mwenyewe sasa hivi hadi tumbo karibu lipasuke","Nashiriki na marafiki na familia tule pamoja, au nachukua muda na juhudi ya kuvipika na kuvigeuza 'chakula cha kuhifadhi' kwa kuviwekea chumvi au kuvikausha","Naviacha chumbani hadi vioze, na navila vikianza kunuka","Navizika ardhini vilivyo na kuvificha"],
    answerIndex:1,
    explanation:"Hili ni kubadilishana kati ya kuchagua 'kushiba kwa papo hapo mbele yako (matumizi)' au kuchukua juhudi ya kuvisindika ili kuvihifadhi kwa ajili ya baadaye, 'usalama wa baadaye (uwekezaji)'. Kujilazimisha kula vyote peke yako kunahatarisha sumu kali ya chakula inayoharibu tumbo na inayoweza kukugharimu maisha. Kwa kuchukua juhudi ya kuweka chumvi na kukausha (kutengeneza chakula kikavu), unaondoa maji yanayohitajiwa na vijidudu vinavyosababisha kuoza, ukivigeuza ngao inayoweza kuliwa kwa miezi. Na kwa kushiriki na marafiki na kupata shukrani yao (uaminifu), unajenga wavu bora wa usalama: watakusaidia utakapokuwa na njaa baadaye." },
  { id:63, topic:"Shinikizo la kundi", emoji:"🗳️",
    question:"Wenzako watano mnafanya kazi pamoja. Mnapojadili jinsi ya kuendelea, watu 4 wanasema, 'Njia hii ni rahisi zaidi, kwa hiyo tupuuze sheria na tuendelee.' Lakini kwa mtazamo wako, njia hiyo ina hatari kubwa (hitilafu, hatari ya ajali). Utende vipi?",
    choices:["Maoni ya wengi watu 4 (umati) lazima yawe sahihi kila wakati, kwa hiyo natii kimya kimya","Naogopa kuchukiwa na marafiki, kwa hiyo hata nikijua ni hatari sisemi lolote na nafuata wote","Bila kujali idadi ya watu, naeleza kwa utulivu 'ushahidi wa hatari' wa kisayansi na kimantiki, na nawashawishi wote wabadilike kwenda njia salama inayofuata sheria","Nakasirika na kukimbia peke yangu mahali fulani"],
    answerIndex:2,
    explanation:"Mwelekeo wa binadamu kubebwa na maoni ya umati na kufanya uamuzi mbaya unaitwa 'shinikizo la kundi (shinikizo la kufuata wengi)' au 'mtego wa fikra za kundi'. Kupiga kura kwa wingi ni mfumo wenye manufaa, lakini katika ulimwengu wa sayansi na usalama, 'watu wangapi wanakubali' si ushahidi wa usahihi hata milimita moja. Hata watu 4 wakisema 'ni salama', kupuuza sheria za fizikia au kanuni za usalama maana yake ajali ni hakika kwa asilimia 100 na wote wananaswa. Ikiwa unathamini kweli maisha ya wenzako, alama ya kiongozi mwenye busara ni ujasiri wa kushinda hofu ya kuchukiwa (gharama) na, kwa msingi wa ushahidi imara, kupaza sauti na kusema 'hili ni hatari'." },
  { id:64, topic:"Kuamua gizani", emoji:"🌑",
    question:"Ukiwa safarini katika msitu mzito au ardhi isiyojulikana, jua linazama kabisa na kunakuwa giza totoro (bila mwanga wowote). Pia unasikia milio ya wanyama wa porini. Ni njia gani isiyo mbaya zaidi ya kutenda?",
    choices:["Nikiamini hisia zangu za ndani, nasonga mbele kwa haraka kwa miguu gizani nikitafuta njia ya kutoka","Kutembea kwa kujilazimisha kuna hatari kubwa mno ya kuanguka kutoka mwamba au kupotea, kwa hiyo najikinga nyuma ya jiwe imara au juu ya mti, naangalia mazingira kwa tahadhari, na 'nasubiri kwa utulivu asubuhi ifike'","Nakimbia gizani kwa kasi yote huku nikipiga kelele","Najilaza chini mikono na miguu wazi, naachilia tahadhari kabisa, na nalala fofofo"],
    answerIndex:1,
    explanation:"Hili ni swali la usimamizi wa hatari ambapo unapima 'hatari ya kusonga mbele' dhidi ya 'hatari ya kubaki pale pale'. Kuhama gizani totoro ni kama kuvuka uwanja wa mabomu macho yamefungwa: nafasi za kupotea au kuanguka zinaruka juu. Kubaki kuna hatari ya kukutana na wanyama wa porini au baridi, lakini ukijificha nyuma ya jiwe, ukificha uwepo wako, na ukabaki macho ukishika tawi kama silaha, unaweza kudumisha nafasi zako za kuishi juu. Katika hali ya kuona kidogo ambapo huwezi kuhesabu hatari ya hatua moja mbele, kanuni ya dhahabu ya dunia nzima ni 'usisonge, vumilia, na subiri taarifa (mwanga wa mchana)'." },
  { id:65, topic:"Kutabiri mafuriko ya ghafla", emoji:"🌊",
    question:"Mvua kali mwishowe inasimama ghafla na jua linatokea. Mto ulio mbele yako bado unaonekana kama kawaida, lakini unataka kwa hali yoyote kuvuka mto huu hadi ng'ambo sasa hivi. Utaamua vipi?",
    choices:["Mvua imesimama na hali ya hewa ni nzuri, kwa hiyo naamua naweza kuvuka salama sasa hivi na naruka ndani","Mara tu baada ya mvua kusimama, kiasi kikubwa cha maji kilichonyesha juu ya milima kuna uwezekano mkubwa kije kikikukimbilia kwa kuchelewa (mafuriko ya ghafla), kwa hiyo najiweka mbali na mto kwa saa kadhaa na naangalia hali","Naenda katikati ya mto na nasimama kuangalia kama maji yanaongezeka","Nadhani nitakuwa salama nikivuka kwa kukimbia kwa papo hapo"],
    answerIndex:1,
    explanation:"Ubongo wa binadamu una hitilafu hatari ya fikra inayoitwa 'upendeleo wa hali ya kawaida', ambapo unajihisi salama kwa urahisi ukitegemea tu hali iliyo mbele, ukifikiri 'mvua imesimama, kwa hiyo ni salama sasa'. Lakini ukiangalia sababu na matokeo ya kisayansi, maji ya mvua kali yanaingia ardhini, yanakuwa mkondo mkali wa mto, na daima kuna 'ucheleweshaji wa saa kadhaa' kabla ya kukufikia kuelekea chini ya mto. Hata anga likiwa wazi, hofu ya mto ndiyo inaanza tu. Jifunze kuelewa jinsi maumbile yanavyofanya kazi kama data kwenye mstari wa wakati, na kuweka breki kwenye mawazo ya ubongo wako." },
  { id:66, topic:"Mtego wa pesa rahisi", emoji:"📦",
    question:"Mtu mzima usiyemjua anasema, 'Ukibeba mzigo huu hadi mji ule pale, nitakupa sasa hivi pesa za kutosha kuishi na kucheza mwaka mzima.' Hauruhusiwi kuona kilicho ndani. Utaamua vipi?",
    choices:["Ni nafasi kubwa ya kuwa tajiri, kwa hiyo nakubali kwa furaha mzigo na nauubeba","Kuficha kilichomo na kutoa pesa nyingi zisizo za kawaida kwa kazi ya mtoto kunanifanya nione kwa mantiki kwamba 'kuna asilimia 100 uhalifu nyuma ya mtego huu', kwa hiyo nakataa kabisa na nakimbia mara moja","Najadiliana mara nyingine ngapi nitalipwa","Nachukua nusu ya mzigo tu na najaribu kuubeba"],
    answerIndex:1,
    explanation:"Kama ulivyojifunza katika uchumi wa Kifurushi cha 2, ukubwa wa tuzo na ukubwa wa hatari vinalingana kabisa. Unapoulizwa kupewa pesa nyingi zisizo za kawaida kubeba mzigo ambao kilichomo kimefichwa, kilichomo kuna uwezekano mkubwa ni 'dawa za kulevya haramu' au 'mali iliyoibwa'. Ukiubeba bila kujua na ukakamatwa, unalipa gharama ya kuangamiza: kufungwa kama mhalifu gerezani la giza kwa miaka, ukipoteza uhuru wote wa maisha yako. Ishara mbili 'sijui kilicho ndani' na 'pesa bila sababu' zikipatana, hiyo ni kengele ya asilimia 100 ya mtego hatari. Tumia macho yako ya hekima na ulinde maisha yako mwenyewe." },
  { id:67, topic:"Vipaumbele vya kuhama", emoji:"🎒",
    question:"Tetemeko kubwa la ardhi au mafuriko yanapiga na lazima uhame nyumbani kwako sasa hivi. Nyumbani kwako kuna kichezeo cha thamani, sanduku zito la pesa, na kumbukumbu nyingi zilizojaa hisia. Ni uamuzi gani sahihi kuhusu cha kuchukua unapohama?",
    choices:["Sitaki kupoteza hazina zangu, kwa hiyo nashindilia vitu vizito hadi mwisho ndani ya begi, nabeba mgongoni, na nakimbia","Mzigo mzito unanizuia kukimbia na unaweza kunigharimu maisha, kwa hiyo nachukua tu 'vitu vyepesi vya chini kabisa vinavyohitajika kabisa kuishi', kama maji, chakula kidogo, na vifaa vya matibabu, na nakimbia mikono yote miwili wazi","Natumia saa nzima kukusanya vitu vyangu kwa utulivu kabla ya kuondoka","Sichukui chochote ila kichezeo changu kimoja ninachokipenda zaidi na nakimbia"],
    answerIndex:1,
    explanation:"Hii ni kubadilishana wakati wa dharura kati ya 'mali ya kimwili' na 'maisha yako mwenyewe (muda na kasi ya kuhama)'. Kukimbia na begi zito mgongoni kunafanya kasi yako ya kutembea ishuke sana, kwa hiyo huwezi kutoroka jengo linaloporomoka wala kukimbia kutoka maji yanayosonga. Pia, mikono yote miwili ikiwa imeshikilia ukiangukia, unaweza kupiga kichwa vibaya na kushindwa kusonga. Hata kitu kikiwa ghali kiasi gani au kumbukumbu ya thamani kiasi gani, usipoishi, thamani yake yote inakuwa sufuri. Wakati wa dharura, fanya kwa sekunde moja uamuzi wa baridi na sahihi: 'tupa kila kitu isipokuwa maisha'." },
  { id:68, topic:"Kutoeneza maambukizi", emoji:"🤧",
    question:"Unapoamka asubuhi unajisikia vibaya kidogo, na kikohozi. Leo ni siku ya kazi muhimu (au mtihani shuleni) ambapo unakutana na wenzako wote wa thamani kujenga jengo kubwa. Utende vipi?",
    choices:["Sitaki kuwa mzigo kwa wote, kwa hiyo naficha kuwa najisikia vibaya, naenda kazini kama kawaida, na najilazimisha hadi jioni","Nafikiria 'hatari ya kuwaambukiza wenzangu ugonjwa wangu na kuangamiza timu nzima', nawaambia kwa ukweli watu wa nyumbani au kiongozi, na napumzika kimya nyumbani ili kupona","Nashika pumzi muda wote ili nisikohoe, na naendelea kufanya kazi","Katikati ya kazi, narudi nyumbani kimya bila kumwambia yeyote"],
    answerIndex:1,
    explanation:"Hili ni swali la juu la usimamizi wa hatari linalopima 'hisia yako mwenyewe ya wajibu (hisia kwamba lazima uende)' dhidi ya 'hatari ya kueneza maambukizi' ya timu nzima. Kujilazimisha kwenda kazini kunaonekana kustahiwa kwa mtazamo wa kwanza, lakini kwa mtazamo wa kitabibu, virusi unavyovipumua vinaweza kuwaambukiza wenzako mmoja baada ya mwingine, na siku chache baadaye timu nzima inaanguka kwa ugonjwa na mradi unasimama kabisa, maafa ya pili mabaya zaidi. Unapojisikia vibaya, 'kupumzika ndilo tendo lenye wajibu zaidi kuliko yote kwa jamii'." },
  { id:69, topic:"Kuzuia uvumi", emoji:"📢",
    question:"Kijijini unasikia uvumi: 'Kutoka mji jirani, dudu la kutisha lenye ugonjwa mbaya linakimbilia huku sasa hivi!' Kila mtu anapata hofu na vurugu kubwa. Ni tendo gani unapaswa kufanya kwanza?",
    choices:["Ni tukio zito, kwa hiyo nakimbia kuwaambia marafiki na familia wote, 'Dudu linakuja, kimbieni!'","Hata nikisikia uvumi wa kutisha, natuliza moyo mara moja, naangalia kwa utulivu kama kuna 'chanzo (nani alisema kwanza)' au 'ushahidi imara wa kisayansi', na nahakikisha sibebwi na uvumi wa uongo","Naamini uvumi na navunja samani zote za nyumbani kwa ghadhabu","Ili kushinda dudu, nachukua silaha peke yangu na nakimbia kutoka mjini"],
    answerIndex:1,
    explanation:"Tukio ambapo uongo usio na msingi au hofu ya kutoelewana zinaenea kwa mlipuko kutoka mtu hadi mtu wakati wa maafa au dharura linaitwa 'uvumi (taarifa za uongo)' au 'hofu ya umati'. Mtu ambaye ubongo wake unatawaliwa na hisia ya hofu anakuwa 'mbeba uvumi', akiueneza kwa wengine bila kuthibitisha. Hili likitokea, barabara za kuhama zinazohitajika kweli zinaziba, mapigano yanazuka, na jamii inajiangamiza. Unaposikia uvumi, kwanza fanya kijiti cha taarifa 'kisimame kabisa' kwako. Kisha angalia vitabu au data za watu wazima wa kuaminika, na inua ngao ya kuthibitisha ukweli." },
  { id:70, topic:"Hatari ya kukopesha", emoji:"🪓",
    question:"Rafiki anaomba kukopa, kwa siku chache, 'shoka (chombo)' kikali sana anachokithamini. Lakini rafiki huyo daima anashika vyombo kwa ukatili na amevunja vitu mara nyingi zamani. Utajibu vipi?",
    choices:["Kukataa kungeharibu uhusiano wangu na rafiki, kwa hiyo namkopesha bado nikitabasamu, nimekubali kitavunjwa","Chombo kikivunjika siwezi kufanya kazi yangu na maisha yangu yapo hatarini, kwa hiyo kwa msingi wa data ya zamani naeleza sababu zangu kwa upole na ama naweka sharti salama kama 'unaweza kukitumia tu ukiwa pamoja nami', au napendekeza njia isiyokiharibu","Namfukuza nikipiga kelele kwa nguvu zote, 'Wewe daima unavunja vitu, kwa hiyo hapana!'","Nadanganya kumkopesha, lakini namkabidhi shoka lililovunjika lisilokata kabisa"],
    answerIndex:1,
    explanation:"Hili ni tatizo gumu kati ya 'uhusiano wako na rafiki (hamu ya kukopesha)' na 'ulinzi wa mali yako ya thamani (hatari ya kuvunjwa)'. Kukopesha bado huku ukipuuza data ya hatari, kwa sababu tu hutaki kumuumiza mwingine, ni kuachana tu na kufikiri. Chombo kikivunjika kweli, rafiki anajisikia vibaya, chombo chako kinapotea, na unafika mwisho mbaya zaidi. Usimamizi wa hatari si kumkataa mwingine tu, bali kutumia kichwa kubuni 'mpango mbadala (njia nyingine)' unaopunguza hatari yako mwenyewe huku ukikidhi mahitaji ya mwingine, na kujadiliana kwa usawa." },
  { id:71, topic:"Kuchemsha maji", emoji:"🚰",
    question:"Una maji uliyoyateka kutoka kisima cha karibu. Yanaonekana wazi kabisa na yang'aayo kwa usafi. Lakini maji haya ni ya baada ya mvua kali ya jana. Unapokunywa maji, ufanye nini?",
    choices:["Yanaonekana wazi na nina kiu sana, kwa hiyo nayanywa kwa fundo sasa hivi yalivyo","Hata nikilipa 'muda na mafuta ya kuyachemsha hadi yachemke kwa mawimbi', nahakikisha naangamiza asilimia 100 ya vijidudu visivyoonekana kabla ya kuyanywa salama","Naweka jiwe zuri ndani ya maji kabla ya kunywa","Naomba dua kwa maji kabla ya kuyanywa"],
    answerIndex:1,
    explanation:"Hii ni kubadilishana kati ya 'kasi ya kuzima kiu sasa hivi' na 'hatari ya kitabibu ya kuharibu tumbo na kuugua vibaya baadaye'. Kama ulivyojifunza tena na tena, maji baada ya maafa, yawe mazuri kiasi gani, yana vitu vyenye madhara na vijidudu kutoka ardhini vilivyochanganyika. Anayebana gharama ya awali akifikiri 'kuwasha moto ni usumbufu' au 'kuni (mafuta) ni hasara', na akayanywa mabichi, analipa gharama ya hali mbaya zaidi mara makumi ya maelfu zaidi: kufa siku chache baadaye kwa kuhara kukali. Usisite kulipa gharama sahihi kwa ajili ya usalama." },
  { id:72, topic:"Kuvutwa hatarini", emoji:"🕳️",
    question:"Kundi la marafiki linakudhihaki: 'Twende kuchunguza ndani ya pango lile lenye kina karibu kuporomoka! Asiyekuja ni mwoga!' Kila mtu yuko karibu kuingia. Utatenda vipi?",
    choices:["Inauma kuitwa mwoga, na kwa kuwa kila mtu anaenda, naingia pangoni nao pia","Matusi na dhihaka hazina msingi wa kisayansi hata milimita moja, kwa hiyo nazipuuza kabisa, sijaingii kamwe mwenyewe mahali pa hatari, na kwa nguvu zangu zote nawazuia wengine pia nikisema 'kweli ni hatari, tusiende'","Mimi siingii, lakini nasimama kusubiri pembeni kabisa ya mlango wa pango","Nakasirikia marafiki zangu na nawatupia mawe"],
    answerIndex:1,
    explanation:"Mtu anayewachochea wengine kwa makusudi kwenye tabia ya hatari kwa kuchochea hofu ya kutengwa au kwa kuchoma kiburi kwa matusi (kama 'mwoga') anaitwa 'mshawishi wa hatari'. Sababu ya kawaida zaidi ya ajali kati ya umri wa miaka 9 hadi 12 ni kushindwa na shinikizo hili la kundi na kuumia vibaya wakati wa kujaribu 'kuonekana mzuri'. Mtu mwenye busara anatenganisha kabisa, akilini mwake, matusi ya maneno (hisia) na hatari ya kimwili ya pango linalokaribia kuporomoka (ukweli) anapoamua. Ujasiri wa kweli si kujitupa kwenye changamoto ya kizembe, bali kuwa na moyo imara na huru unaoweza kusema 'HAPANA' kwa hatari." },
  { id:73, topic:"Kufanya kazi hovyo na usalama", emoji:"🏗️",
    question:"Unaunganisha paa la nyumba yako, au daraja la mbao kwa wote kuvuka. Unataka kumaliza haraka na kucheza, kwa hiyo ni sawa kufanya kazi hovyo (kuweka misumari michache, kutumia mbao nyembamba) ili kuongeza kasi?",
    choices:["Kumaliza sasa hivi kunafurahisha, kwa hiyo nafanya hovyo mahali pasipoonekana na namaliza haraka","Kufanya hovyo kunasababisha 'ajali kubwa inayoporomoka kwa papo hapo na kumuumiza vibaya mtu' wakati upepo mkali unavuma au mtu mzito anapanda baadaye, kwa hiyo hata ikichukua muda naijenga imara kufuata sheria","Naifanya ionekane imekamilika, kisha nasimamisha kazi katikati na naenda kucheza","Naangalia tu kwa makini kama watu wengine wanafanya hovyo"],
    answerIndex:1,
    explanation:"Hii ni kubadilishana kati ya 'uvivu wako mwenyewe unaotaka kupumzika sasa' na 'kuanguka kwa usalama wa baadaye'. Muundo wa jengo na nguvu za fizikia ni waaminifu sana: wakati uvutano au nishati ya upepo inapojikusanya kwenye sehemu dhaifu (hitilafu) ya kazi ya hovyo aliyoipuuza binadamu, uharibifu unapiga mara moja kwa mlio. Anayeumia wakati huo anaweza kuwa wewe mwenyewe, au familia yako ya thamani. Kazini, hekima ya fundi ya 'kujenga msingi usioonekana kwa uaminifu na imara, hata wakati hakuna anayetazama' inalinda uaminifu wa jamii na maisha ya wote kwa muda mrefu." },
  { id:74, topic:"Kutumia na kuwekeza", emoji:"🧰",
    question:"Ulifanya kazi kwa bidii na kuweka akiba ya pesa za matumizi (bajeti) unazoweza kutumia kwa uhuru. Dukani kuna 'kichezeo cha kung'aa' unachoweza kujivunia kwa marafiki sasa hivi, na 'chombo cha kazi imara' kitakachofanya kasi yako ya kazi ya baadaye iwe mara 3 zaidi. Ni kipi cha busara kununua?",
    choices:["Nataka marafiki waniite wa ajabu sasa hivi, kwa hiyo nanunua kichezeo cha kung'aa","Badala ya kujivunia sasa, nanunua 'chombo cha kazi imara (uwekezaji)' kinachoinua tija yangu ya baadaye na kunipatia pesa zaidi salama","Situmii pesa kabisa; nazizika ndani sana ardhini na nazisahau","Sinunui chochote na badala yake nanunua vitafunio hadi kikomo na navila vyote kwa siku moja"],
    answerIndex:1,
    explanation:"Hili ni chaguo la juu kati ya 'matumizi' na 'uwekezaji' lililotokea pia katika uchumi wa Kifurushi cha 2. Kununua kichezeo kunaleta furaha ya wakati huo (matumizi), lakini pesa za matumizi zinatoweka na uwezo wako haubadiliki kabisa. Kununua chombo cha kazi, kwa upande mwingine, kinakuwa mbegu (uwekezaji) inayoinua 'tija (kiasi cha utajiri unaoweza kuzalisha katika saa moja)' yako ya baadaye mara nyingi. Mtu mwenye busara hatumii tu pesa zilizopo mkononi, bali anazitumia kuboresha ujuzi na vyombo vyake mwenyewe, akiimarisha zaidi miguu ya uhuru wake. Fanya pesa kuwa chombo chako cha kuamuru." },
  { id:75, topic:"Kuzuia maafa ya pili", emoji:"🚨",
    question:"Jengo kuukuu lililo mbele yako linaporomoka kwa tetemeko la ardhi au moto. Katika eneo la hatari karibu kabisa na jengo hilo, rafiki yako ameumia, ameanguka, na analia. Ni 'uamuzi wa dharura' gani wa kwanza kabisa unapaswa kuufanya?",
    choices:["Nataka kumwokoa rafiki haraka, kwa hiyo bila kuangalia mazingira, narukia moja kwa moja mahali alipoanguka","Nikifikiria hatari kwamba nikirukia, jengo linaporomoka kutoka juu na kutuzika sote wawili (maafa ya pili), kwanza naangalia 'usalama wa mazingira (juu na nyuma)' kwa sekunde 3, nahakikisha usalama au naita msaada wa mtu mzima, na ndipo nakaribia","Naogopa, namuacha rafiki, na nakimbia","Naendelea kumpigia kelele rafiki aliyeanguka, 'Haraka, kimbia huku!'"],
    answerIndex:1,
    explanation:"Katika tiba ya dharura na kuokoka, Kanuni ya 1 kuu inayofundishwa kwa ukali zaidi dunia nzima ni 'kuangalia usalama wa mazingira'. Mtu anapoanguka mbele yako, unataka kukimbilia kwa hofu, lakini ikiwa mahali hapo ni 'chini ya ukuta unaokaribia kuporomoka' au 'ndani ya shimo ambamo gesi yenye sumu imejaa', wakati unapokaribia wewe pia unananaswa na kuanguka, waokoaji wanakuwa sufuri, na wote wanakufa. Hili linaitwa 'maafa ya pili'. Unapomsaidia mtu, kwanza jiweke salama kabisa mwenyewe; hii ni kanuni ya dhahabu ya baridi lakini sahihi." },
  { id:76, topic:"Hatari ya wanyama wa porini", emoji:"🐻",
    question:"Msituni unakuta 'mtoto wa dubu wa porini au mnyama mwingine mlaji', mdogo sana na wa kupendeza, akitembea peke yake kwa hatua ndogo. Humwoni mama dubu popote. Utatenda vipi?",
    choices:["Ni wa kupendeza, kwa hiyo nakaribia kumbembeleza au kumpa chakula kutoka mfukoni mwangu ili tuwe marafiki","Sijakaribia kamwe; naficha uwepo wangu na naondoka mahali hapo haraka na kimya. Karibu kabisa na mtoto, 'mama mnyama wa kutisha', aliyekuwa mkali sana ili kumlinda mwanawe, hakika anavizia gizani","Nampeleka mtoto wa mnyama nyumbani na namfanya mfugo","Namfukuza mtoto wa mnyama huku nikipiga kelele"],
    answerIndex:1,
    explanation:"Huu ni usimamizi wa hatari unaotegemea kujua tabia (ushahidi) za viumbe wa porini. Mtoto wa mnyama mlaji akiwa peke yake, haimaanishi mama amepuuza ulezi na kutoweka. Anatafuta chakula gizani karibu, au anakuangalia kwa makini. Wakati binadamu anapokaribia mwanawe, mnyama wa porini anamhukumu kama 'adui aliyekuja kumuua mwanangu', anawasha swichi yake ya kipori hadi upeo, na anashambulia kukuua, akihatarisha maisha yake mwenyewe. Usidanganywe na 'upendezi (hisia)' wa muonekano; tabiri 'uhalisia wa silika ya ulinzi (ukweli)' wa ulimwengu wa maumbile, na dumisha umbali salama." },
  { id:77, topic:"Mgawanyo wa haki wa rasilimali", emoji:"🤲",
    question:"Maafa makubwa au ukame unapiga, na 'maji ya kunywa' na 'dawa' za thamani za kijijini zinapungua sana, mbali na kutosha kwa wote. Katika janga hili, ni uamuzi gani usio mbaya zaidi?",
    choices:["Ili niishi mwenyewe, natumia nguvu kunyang'anya kwa nguvu sehemu ya maji na dawa ya watu wengine","Kunyang'anyana kunafanya kuwe na waliojeruhiwa na jamii inajiangamiza, kwa hiyo wote tunajadiliana na kuamua kanuni ya haki ya kugawa kwa mpangilio, kuanzia walio dhaifu zaidi, kama 'watoto wadogo, wajawazito, na wagonjwa', na tunashiriki","Namwaga maji na dawa zote ardhini ili asiweze kuyatumia yeyote","Nakata tamaa, na wote tunakaa pale pale na kulia"],
    answerIndex:1,
    explanation:"Huu ni usimamizi wa hatari wa jamii katika hali ya hatari kuu (janga) ambapo rasilimali zinapungua hadi kikomo. Ukiondoa hapa kanuni na kuruhusu ulimwengu wa vurugu (sheria ya msitu) ambapo mwenye nguvu ananyang'anya dhaifu, vita vya kuuana vinazuka kijijini na, mwishowe, wote wanaangamia kwa majeraha au ugonjwa. Binadamu ana hekima haswa ili, katika janga kama hilo, waweze kubuni 'kanuni (mkataba wa kijamii)' zinazoongeza nafasi za kuishi za kundi zima. Mfumo wenye huruma na akili wa kugawa kwa mpangilio, kuanzia maisha dhaifu zaidi tunayopaswa kuyalinda zaidi, ndio uliofanya wanadamu waokoke kupitia historia ngumu." },
  { id:78, topic:"Kuheshimu faragha", emoji:"🔒",
    question:"Mtandaoni au katika mazungumzo, mtu fulani anajiburudisha akijaribu kueneza bila ruhusa 'data za siri au kumbukumbu ya kushindwa kwa zamani ya aibu' ya rafiki yako wa thamani. Utatenda vipi?",
    choices:["Inasikika ya kufurahisha, kwa hiyo najiunga na naieneza siri hiyo kwa wengine wote pia","Kueneza bila ruhusa siri au taarifa zisizopendwa za mtu mwingine kunaumiza sana moyo na haki za binadamu zake; ni 'vurugu (uonevu)' inayoharibu kabisa uaminifu na haipaswi kamwe kufanywa, kwa hiyo kwa hasira nawazuia wasimame","Najifanya sikuona, na naandika tena siri ya rafiki yangu kwenye daftari langu","Namdhihaki rafiki yangu nikisema, 'Aibu kweli siri yako kuvuja'"],
    answerIndex:1,
    explanation:"Hii inahusu hatari ya kushughulikia 'faragha (siri)' ya mtu mwingine kama mzaha nusu. Nguvu ya kueneza ya maneno na mtandao ni ya kutisha hasa: mara uvumi wa aibu wa mtu mwingine ukienea, hauwezi kamwe kukusanywa wote tena na kufutwa. Anayepatwa nayo anaweza kuanguka katika kukata tamaa na kuugua akilini, au kupoteza nguvu ya kuishi. Kuwa mtu anayeweza kufikiria maumivu ya mwingine kama yake mwenyewe na kuweka breki kwa kundi linalojiburudisha, ukisema 'hilo ni baya, acheni'. Kulinda heshima ya wengine kunazunguka na kurudi kwako kujenga ulimwengu salama ambapo kila mtu anakulinda wakati uko katika janga." },
  { id:79, topic:"Kanuni ya aliyepotea", emoji:"🧍",
    question:"Katika jiji kubwa usilolijua, jangwa pana lisilo na mwisho, au msitu, unatengana na familia au wenzako na unakuwa 'umepotea'. Hakuna karibu yeyote anayeonekana tayari kukusaidia. Utatenda vipi?",
    choices:["Ili kumtafuta familia yangu, napiga kelele na naendelea kuzunguka kwa kichaa kwa pande zote chochote kitokeacho","Kuzunguka kunanizidisha tu mbali na kunifanya mgumu zaidi kupatikana, kwa hiyo natuliza moyo, naweka miguu imara mahali 'salama ambapo kwa hakika nilikuwa mara ya mwisho na familia yangu', na nasubiri bila kusonga nipatikane","Napanda mti mrefu pale pale na napitisha usiku peke yangu","Namfuata kimya nyuma kabisa ya mtu mzima nisiyemjua na natembea"],
    answerIndex:1,
    explanation:"Huu ni ushahidi wa kuokoka kwa wakati umepotea (hatari ya kusonga dhidi ya hatari ya kusubiri). Ukitengana, mtoto akipata hofu na kuzunguka kwa pande zote, anapishana na njia ya utafutaji ya familia, anazidi kuwa mbali, na anapotea kabisa. Familia na timu za utafutaji daima zinatafuta zikilenga 'mahali ulipotengana mara ya mwisho'. Ndiyo maana hasa, ukipotea lazima ufuate kanuni ya dhahabu ya uokoaji ya dunia nzima ya 'usisonge hatua moja kutoka mahali (Hug a Tree: kumbatia mti na usubiri)'. Hekima ya uvumilivu ya kutosonga inaongeza nafasi ya kuungana tena na familia yako haraka iwezekanavyo." },
  { id:80, topic:"Kuzima moto", emoji:"🧯",
    question:"Baada ya moto wa kambini ulioutumia kupika au kujipasha joto, moto umezimika kabisa na kumebaki tu makaa meusi na majivu. Kabla ya kurudi nyumbani au hemani kwako, ni kitu gani cha mwisho cha kufanya?",
    choices:["Hazionekani ndimi nyekundu za moto, kwa hiyo naamua umezimika kabisa, naiacha ilivyo, na naondoka","Ili kuzuia hatari kwamba 'kaa lenye joto kali sana' lisiloonekana lililofichwa ndani sana ya makaa liwe moto mkubwa wakati upepo unavuma baadaye, namwaga ndoo za maji tena na tena na nahakikisha umepoa kabisa","Narundika majani makavu mengi juu ya makaa ili kuyaficha","Napuliza majivu kwa nguvu kwa fimbo ya kupuliza moto na kuyatawanya kwa upepo"],
    answerIndex:1,
    explanation:"Huu ni ushahidi wa kifizikia wa baridi wa kushughulikia moto. Baada ya moto wa kambini, uso unapofunikwa na makaa meusi na majivu meupe, jicho la binadamu linajihisi salama kwa urahisi (upendeleo wa hali ya kawaida), likifikiri 'tayari umezimika'. Lakini ndani ya makaa, 'kaa' kali la mamia ya nyuzi joto linaishi kwa saa, likihifadhi joto kama chupa ya thermos kwa kuzuia hewa kuingia. Ukiondoka hivyo, wakati upepo mkali usiku unapoingiza oksijeni, makaa yanawaka tena kwa mlipuko na yanasababisha moto mkubwa (moto wa porini) unaoteketeza msitu na hema za karibu hadi sufuri kwa papo hapo. Hekima ya kumwaga maji hadi sauti ya kufoka isimame kabisa inalinda maumbile na maisha dunia nzima." },
  { id:81, topic:"Muda na pesa", emoji:"⏰",
    question:"Kitendawili cha ununuzi. Katika soko la mbali la 'saa 1 kwa miguu' kutoka nyumbani kwako, viazi vinauzwa sarafu 50. Katika duka 'karibu kabisa' na nyumbani kwako, viazi vilevile vinauzwa sarafu 100. Ni wapi pa busara zaidi kununua?",
    choices:["50 bila shaka ni namba ndogo zaidi, kwa hiyo chochote kitokeacho, daima unapaswa kutembea saa 1 hadi soko la mbali","Unapima 'saa 2 za kwenda na kurudi, ambazo ni muda wako mwenyewe wa thamani wa maisha' na 'nguvu unayoitumia kutembea', unahesabu kama inafaa kutumia saa hizo 2 kwa kitu kingine kama kusoma au kufanya kazi, na unachagua mwenyewe chaguo bora","Unaenda duka ghali zaidi na unamlipa muuzaji zaidi","Hujui ipi ni bora, kwa hiyo unaacha kununua viazi"],
    answerIndex:1,
    explanation:"Hili ni swali la juu la kupima kati ya namba za pesa na 'muda wako mwenyewe (gharama ya fursa)'. Kuokoa sarafu 50 kunavutia, lakini ili kufanya hivyo unalipa gharama ya kutoa kafara saa '2' za kwenda na kurudi. Ukiweza kupata sarafu 500 kwa kufanya kazi katika saa hizo 2, basi kutumia saa 2 kuokoa sarafu 50 maana yake, kwa kutoa, unapata 'hasara kubwa ya sarafu 450'. Kwa upande mwingine, ikiwa leo huna lolote la kufanya na muda umebaki bila kikomo, basi kwenda mbali kwa mazoezi kidogo na kuokoa sarafu 50 inakuwa jibu sahihi. Hakuna jibu sahihi moja tu. Kuza ubongo wa mtu mzima unaobadilisha muda kuwa pesa na kuhesabu." },
  { id:82, topic:"Tahadhari kwa kisichojulikana", emoji:"🍒",
    question:"Msituni unakuta 'tunda zuri la aina mpya kabisa, lisilojulikana kabisa, ambalo halimo kabisa katika kitabu chochote au fundisho lolote la mtu mzima ulilowahi kuona'. Una njaa kali sana. Utatenda vipi?",
    choices:["Linaonekana tamu na lina rangi nzuri, kwa hiyo nalila lote sasa hivi kujaza tumbo","Nikifikiria hatari kwamba chakula kisichojulikana kinaweza kuficha sumu kali inayoharibu viungo vya binadamu kwa papo hapo, 'siweki kamwe kinywani' chochote kisichothibitishwa kuwa salama kwa asilimia 100 kisayansi","Namwacha rafiki ale kidogo tu na nafanya jaribio kuona kama tumbo lake litaharibika","Naliosha tunda mara moja kwa maji, kisha namlimeza zima kwa pamoja"],
    answerIndex:1,
    explanation:"Hii ni hekima ya tahadhari kwa 'kisichojulikana (hatari)' katika kuokoka. Mmea au tunda la maumbile likiwa na rangi nzuri au harufu tamu, si ili binadamu walione tamu. Badala yake, kuna uwezekano mkubwa ni 'silaha kali ya ulinzi ya sumu' iliyobadilika yenyewe ili wanyama wasilile. Kanuni ya mwokokaji mwenye busara si 'kula tu unachojua ni salama', bali fikra kali ya kutoa: 'shughulikia kama sumu chochote kisichothibitishwa salama kwa asilimia 100'. Usishindwe na njaa ya papo hapo na kucheza kamari na maisha yako." },
  { id:83, topic:"Pole pole ndio mwendo", emoji:"🪵",
    question:"Kuna mafungu 10 ya kuni nzito. Ulipojilazimisha kubeba yote 10 kwa pamoja, ulipepesuka, ukaangusha mzigo mara nyingi, na ikachukua dakika 30. Ulipogawa katika safari 5 za mafungu 2 kila safari, ulimaliza kubeba salama kwa dakika 10. Ni hekima gani unayojifunza kutoka matokeo haya?",
    choices:["Kwamba kubeba vingi kwa pamoja kunazoeza misuli na kunaonekana kuzuri","Pole pole ndio mwendo (kadiri unavyoharakisha, ndivyo unavyotumia njia salama na ya hakika). Kuhesabu kwa usahihi kikomo cha mwili wako na kugawa mzigo, mwishowe, ni haraka zaidi na 'tija zaidi'","Kwamba kutobeba mzigo na kuuacha pale pale kunachukua muda mfupi zaidi","Kwamba kuanzia sasa, unapaswa kumfanya mtu mwingine abebe yote"],
    answerIndex:1,
    explanation:"Hii ni kubadilishana kati ya 'haraka ya kutaka kumaliza kwa pamoja' na 'makosa (kushindwa) yanayosababishwa na vikomo vya kimwili vya mwili'. Kadiri binadamu anavyoharakisha, ndivyo anavyotaka kukadiria nguvu zake kupita kiasi na kulenga pigo moja la kizembe (njia ya mkato), lakini mara nyingi anapoteza usawa, anashindwa vibaya, anapaswa kuanza upya kutoka mwanzo, na anapoteza muda na nishati mara nyingi. Kutazama kwa baridi data ya vikomo vyako mwenyewe na kugawa kazi katika vipande vidogo vya hakika ili kurundika, njia ya hatari ndogo, kunafanya kasi ya jumla (tija) iwe ya haraka zaidi sana." },
  { id:84, topic:"Mavazi kama ulinzi", emoji:"🦟",
    question:"Siku ya joto ya kiangazi, unaenda kufanya kazi kwenye kichaka chenye miiba au msitu mzito ambapo wadudu wenye sumu wa kutisha (mbu na kupe) wanavizia kwa wingi. Ni mavazi gani ndiyo chaguo sahihi zaidi kwa usimamizi wa hatari?",
    choices:["Ni joto sana, kwa hiyo naenda na mikono mifupi, kaptula yenye baridi na rahisi kusogea, na miguu peku","Hata nikilipa gharama ya kutoka jasho kwa joto, ili miiba mikali na miiba ya wadudu isifikie ngozi yangu moja kwa moja, navaa 'mikono mirefu, suruali ndefu, na viatu imara' vya kitambaa kizito, nikificha ngozi kabisa","Ni hasara kuchafua nguo zangu, kwa hiyo naenda uchi bila chochote","Navaa nguo ya kifahari na nzuri zaidi niliyo nayo nyumbani"],
    answerIndex:1,
    explanation:"Hili ni tatizo gumu kati ya 'starehe ya kutaka kupoa sasa hivi (hisia)' na 'ulinzi wa ngozi yako (usalama)'. Ukiacha ngozi wazi kwa sababu ni joto na ukaingia kwenye kichaka kizito, si tu miiba inaacha ngozi yako ikiwa na damu, bali mbu na kupe wabebao virusi vya magonjwa ya kutisha (kama malaria na homa ya dengue) wanakuuma kwa wingi, na unaanguka siku chache baadaye na homa ya nyuzi 40, ukibeba hatari mara makumi ya maelfu ya kutisha zaidi. Mavazi ni 'kizuizi cha kwanza na chenye nguvu zaidi cha kitabibu', kwa ukuta wa kifizikia wa nyuzi za kitambaa. Kwa ajili ya usalama, kuwa na hekima ya kuvumilia usumbufu wa sasa (joto)." },
  { id:85, topic:"Kudhibiti hasira", emoji:"😤",
    question:"Katikati ya kazi au mazungumzo na rafiki, mwenzako anakuambia jambo baya lisilo na haki, au kwa uzembe anavunja chombo chako cha thamani. Kifua chako kinawaka kwa hasira, na unataka kumpiga ngumi. Utatenda vipi?",
    choices:["Nikiwa nimebebwa na hisia ya hasira, napiga kelele kwa nguvu na namrudishia ngumi kwa nguvu zangu zote","Hasira ikiteka ubongo wangu siwezi kuhesabu kwa utulivu, na napata hasara kubwa kama kusababisha tukio la vurugu na kukamatwa na polisi, kwa hiyo nafumba macho mara moja, 'navuta pumzi ndefu mara 3' ili kupoza ubongo, na natoa ukweli kwa maneno","Nimeudhika, kwa hiyo narudi nyumbani na napiga ukuta wa chumba changu kwa nguvu zangu zote hadi uvunjike","Bila kusema lolote, kwa siri nashindilia mawe mengi ndani ya viatu vya mwenzangu"],
    answerIndex:1,
    explanation:"Huu ni udhibiti juu ya 'hisia yako mwenyewe ya hasira (msukumo)' na 'utabiri wa matokeo mabaya zaidi yanayofuata' (kudhibiti hasira). Wakati binadamu anaposikia hasira, sehemu ya kale ya ubongo (amygdala) inafanya kazi kwa nguvu zote, na swichi ya lobe ya mbele ya ubongo, inayotawala akili, inazimika kabisa kwa muda. Ukifanya vurugu kwa hisia ya 'sekunde chache ambazo kichwa chako kimekuwa kipumbavu' hizo, unalipa gharama mbaya zaidi: kumuumiza vibaya mwenzako, kuwa mhalifu, au uaminifu uliojenga kutoweka kwa papo hapo. Sekunde chache za uvumilivu za kuvuta pumzi ndefu, kupeleka oksijeni kwenye ubongo wako, na kuwasha tena akili zinaokoa maisha yako kutoka uharibifu." },
  { id:86, topic:"Maisha kuliko vyombo", emoji:"⛰️",
    question:"Kwa bahati mbaya unaangusha 'kisu cha chuma (chombo)' ghali sana na cha thamani unachokitumia kwa kazi za mikono na kazi, ndani ya vichaka chini ya mwamba wenye kina unaomomonyoka. Utaamua vipi?",
    choices:["Sitaki kupoteza chombo changu ghali na cha thamani, kwa hiyo hata bila kamba, naharakisha, nateleza chini ya mteremko wa mwamba, na nashuka kukiokota","Chombo kinaweza kununuliwa tena siku moja nikilipa, lakini maisha yangu mwenyewe hayawezi kamwe kununuliwa tena. Ikiwa ardhi ni hatari, naacha kwenda kukiokota kwa kujilazimisha, au naita mtu mzima mwenye vyombo salama anisaidie","Kutoka juu ya mwamba, naendelea kupigia kelele kisu, 'Rudi'","Natupa mawe mazito mengi kuelekea mahali kisu kilipoangukia"],
    answerIndex:1,
    explanation:"Hii ni kubadilishana ya mwisho kati ya 'thamani ya pesa' ya chombo na 'usalama wa kimwili' wako mwenyewe. Unapopoteza kitu ghali, ubongo wa binadamu unajaa haraka na hamu ya kutotaka kupata hasara (upendeleo wa kuchukia hasara), na hatari ya karibu inakuwa isiyoonekana. Lakini kwa sheria za fizikia, unaweza kuhesabu kwa asilimia 100 kwamba binadamu asiye na kamba anayeshuka mwamba unaomomonyoka ataanguka kichwa kwanza, atavunja fuvu, na atapoteza maisha. Chombo ni 'kipande kinachoweza kubadilishwa' ambacho pesa au kazi vinaweza kukirejesha daima, lakini maisha yako ni 'siri kuu isiyoweza kubadilishwa' pekee ambayo kuna moja tu duniani. Usichanganye kamwe uzito wa kitu na uzito wa maisha." },
  { id:87, topic:"Ushahidi kuliko mamlaka", emoji:"📚",
    question:"Kuhusu jinsi ya kuponya ugonjwa fulani, watu wazima wawili wa kijijini wanatoa ushauri tofauti kabisa. Mtu A anasema, 'Kwa kuwa ni usemi wa zamani sana, unapona ukisoma uchawi huu', na mtu B anasema, 'Kitabu cha sayansi kinasema ukichemsha mmea huu wa dawa na kuunywa, kiungo chake kinafanya kazi'. Utamwamini yupi?",
    choices:["Mtu A ni mzee zaidi na ana ndevu ndefu zaidi, kwa hiyo naamini anachosema mtu A","Bila kudanganywa na usemi wa zamani au muonekano wa msemaji (mamlaka), naamini na natekeleza 'ushauri wa kitabu cha mtu B', wenye data halisi ya matibabu na ushahidi wa majaribio (ushahidi wa kisayansi)","Nachanganya maoni yote mawili na nakula mmea wa dawa mbichi huku nikisoma uchawi","Siwezi kumwamini yeyote, kwa hiyo naghadhibika na kupiga kelele chumbani"],
    answerIndex:1,
    explanation:"Huu ni usimamizi wa hatari kuhusu kama kuhukumu 'usahihi' wa taarifa kwa umri au muonekano wa msemaji (mamlaka), au kwa 'data imara za ukweli (ushahidi)'. Miongoni mwa misemo ya zamani kuna hekima ya ajabu, lakini umechanganyika pia uchawi wa makosa na mawazo hatari ambayo kwa kweli yanazidisha ugonjwa. Katika uamuzi wa kitabibu au kisayansi ambapo maisha ya binadamu yapo hatarini, ni wale tu wenye macho ya kimantiki, wanaosisitiza kwa baridi 'kama kuna duniani takwimu au ushahidi (data) kwamba kweli kiliponya mtu' - si nani aliyesema - wanaoweza kuepuka mtego na kuokoka." },
  { id:88, topic:"Kutibu majeraha madogo", emoji:"🦶",
    question:"Katikati ya kazi ya nje, mwiba mdogo unachoma kwenye unyayo wa mguu wako na damu kidogo inatoka. Lakini sasa hivi uko katikati ya kucheza kwa furaha na wote (au katikati ya kazi yenye haraka). Utafanya nini na jeraha hili dogo?",
    choices:["Ni aibu kuwaambia wote jeraha dogo hivi, kwa hiyo nalificha na naendelea kusonga, naliacha hadi usiku","Nikifikiria hatari kwamba vijidudu vya tope visivyoonekana vinaingia kupitia jeraha dogo na baadaye mguu wangu wote unaoza hadi nishindwe kutembea, nasimama mara moja, naliosha mara moja kwa maji safi, na nalitibu kwa kuua vijidudu","Nafuta kwa makusudi damu ya jeraha kwa kuisugua na tope","Nasukuma mwiba wa unyayo wa mguu wangu zaidi ndani kwa kidole"],
    answerIndex:1,
    explanation:"Hili ni tatizo la kuacha hitilafu, ambapo unaacha hatari ndogo ukifikiri 'ah, ni sawa' na unaiacha ikue kuwa janga lisiloweza kurekebishwa baadaye. Ukiangalia historia ya tiba, hata binadamu mwenye afya na nguvu kiasi gani, kumekuwa na ajali mamilioni ambapo vijidudu (pepopunda au sepsis) vilivyoingia kupitia jeraha dogo vilienea katika damu ya mwili mzima siku chache baadaye na, katika mazingira yasiyo na daktari, mguu ulikatwa au maisha yalipotea. Siri ya usimamizi wa hatari iko katika tabia ya kila siku ya kujihudumia kwa bidii: 'katika hatua ya mapema zaidi (sasa hivi), wakati hatari iko ndogo zaidi na rahisi zaidi kuiponda, itibu kwa hakika na uikate mizizi'." },
  { id:89, topic:"Ishara za maafa", emoji:"🌋",
    question:"Unaishi karibu na volkeno au mto mkubwa. Siku moja, mngurumo wa kutisha wa ardhi ambao haujawahi kuusikia unavuma, na wanyama wa porini wa karibu wote wanakimbia kutoka mlimani kwa pamoja. Lakini watu wazima wengine wanacheka bila wasiwasi, wakisema, 'Ni kama kawaida, kwa hiyo ni sawa.' Utatenda vipi?",
    choices:["Watu wazima wa karibu wanacheka, kwa hiyo nami natulia na nalala nyumbani kama kawaida","Naamini ishara wazi ya maafa makubwa (data ya tahadhari) inayotumwa na ulimwengu wa maumbile, sibebwi na uzembe wa watu wa karibu, na hata tukiwa familia yangu na mimi tu, nakusanya vitu mara moja na nahama mapema kwenda nyanda za juu salama","Nasubiri bila kusonga pale pale hadi watu wazima wakimbie","Nawafuata wanyama na naingia ndani sana mlimani"],
    answerIndex:1,
    explanation:"Punde kabla ya maafa makubwa, binadamu wengi wanajishawishi kwamba 'mimi tu niko salama' au 'wengine hawasogei, kwa hiyo bado ni sawa', wanachelewa sana kukimbia, na wanaangamia wote pamoja. Hitilafu mbaya zaidi ya ubongo wa kundi hii inaitwa 'ujinga wa wingi' au 'upendeleo wa hali ya kawaida'. Viumbe wa maumbile makubwa, kwa hisia kali kuliko binadamu, wanashika mitetemo midogo hatari ya dunia na harufu ya gesi (data) na wanachukua hatua ya kujilinda kwa sekunde moja. Usiangalie 'hali ya kibinadamu (hisia)' ya karibu; amini tu data ya 'ishara za kifizikia (ukweli)' za maumbile, na uwe mwokokaji mwenye busara anayeweza kukimbia kuhama kama pengwini wa kwanza, mapema kuliko yeyote." },
  { id:90, topic:"Muhtasari wa usimamizi wa hatari", emoji:"🦉",
    question:"Swali kwako, uliyemaliza Kifurushi cha 3 cha programu hii 'Wise World 3'. Ni nguvu ya aina gani kiini cha kweli cha 'usimamizi bora wa hatari (kutabiri hatari)' kwa kuishi ulimwengu kwa usalama, kwa busara, na kwa kujitegemea?",
    choices:["Nguvu ya kulia kwa sauti kubwa baada ya jambo kutokea na kusaidiwa na mtu","Nguvu ya kutodanganywa na hisia au dhana iliyo mbele, kutumia data ya kisayansi kusoma mbele, katika mifumo mingi kichwani mwangu, njia ya baadaye ya sababu na matokeo ya 'nikifanya hili, ni matokeo gani mabaya zaidi yanayotokea baadaye', na kuamua mwenyewe njia salama na kusonga kabla ya kuwa hatari","Nguvu ya kufanya misuli yangu minene kuliko wengine na kuangusha kila hatari kwa ngumi","Nguvu ya kuendelea kuamini bila wasiwasi kwamba haliwezi kamwe kunitokea jambo baya"],
    answerIndex:1,
    explanation:"Hongera! Kwa hili, maswali 30 ya Kifurushi cha 3 yamekamilika. Ulimwengu halisi si mahali palipo salama na pa upole kila wakati, kama hadithi ya kubuni. Maafa ya ghafla, mitego ya maneno matamu, shinikizo la kundi la umati: hatari zinazojaribu kukuvuta kwenye uharibifu daima zinavizia. Lakini ukishikilia 'dira ya kubadilishana na usimamizi wa hatari' uliyojifunza katika kifurushi hiki, hakuna tena cha kuogopa. Usimamizi wa hatari si kuwa mwoga na kujifungia chumbani; bali ni kujifunza vizuri umbo halisi la hatari (sheria za fizikia na hitilafu za saikolojia ya binadamu), kuihifadhi kama data kichwani mwako, kuepuka kwa ujanja maeneo ya hatari, na kuanza safari kubwa kupitia ulimwengu kwa uhuru na nguvu: 'ngao kubwa na yenye nguvu zaidi ya hekima'. Kwa kutumia akili ya busara ya kuokoka iliyowashwa kichwani mwako, endelea kulinda kwa hakika maisha yako mwenyewe na maisha ya baadaye ya wenzako wa thamani. Ulimwengu mzima unashangilia kutoka moyoni mafanikio ya safari yako ya kujitegemea!" },
  { id:91, topic:"Algoriti", emoji:"📋",
    question:"Unaitaje 'mfuatano sahihi na uliopangwa wa amri' unaompa kompyuta au AI ili amalize kazi kwa ufanisi zaidi na bila hitilafu (makosa)?",
    choices:["Nenosiri","Algoriti","Intaneti","Upakuaji"],
    answerIndex:1,
    explanation:"'Utaratibu kamili au kanuni ya hesabu' ya kumaliza kazi huitwa 'algoriti'. Kwa mfano, mapishi ya chakula, au hatua za kuangalia ramani ili usipotee mlimani, ni aina ya algoriti. Kompyuta ni za kasi sana, lakini ikiwa binadamu hapangi algoriti hii vizuri anapoamuru, husogea bila ufanisi na kuganda, au hutoa matokeo mabaya (hitilafu) na kusababisha hasara kubwa. Uwezo wa kujenga mambo kimantiki na kufikiria hatua zinazotoa matokeo makubwa zaidi kwa muda na nishati ndogo zaidi utakuwa silaha yenye nguvu ya kuokoka enzi inayokuja." },
  { id:92, topic:"Jinsi intaneti inavyofanya kazi", emoji:"🌐",
    question:"Simu na kompyuta za dunia nzima huunganishwa kama wavu na kufikisha data mbali kwa papo hapo. Ni nini nguvu kubwa zaidi ya jinsi 'intaneti' inavyofanya kazi?",
    choices:["Imeunganishwa kwa mstari mmoja mkubwa tu, kwa hiyo ukikatika mahali popote, mawasiliano ya dunia nzima yanasimama kwa pamoja","Inageuza data kuwa 'pakiti (mizigo)' midogo iliyotawanyika na kutuma kila moja kupitia njia tofauti kati ya njia zisizohesabika duniani, kwa hiyo mawasiliano hayakatiki hata sehemu ya njia ikivunjika (mtandao uliosambaa)","Kutumia intaneti hufanya uzito wa mashine zote uwe nusu","Kadiri unavyowasiliana zaidi, ndivyo pesa zinavyoongezeka kiotomatiki"],
    answerIndex:1,
    explanation:"Intaneti si kituo kimoja kikubwa kinachotawala dunia; ni mtandao 'uliosambaa' ambao kompyuta zisizohesabika zinaunganishwa kwa usawa. Picha au maandishi unayotaka kutuma si donge moja, bali yanagawanywa vizuri kuwa 'pakiti', chembe ndogo zisizoonekana, na kila moja husafiri hadi mashine lengwa kupitia njia tofauti iliyo wazi. Na zinapofika, zinaungana tena kuwa umbo safi la asili. Kwa sababu ya mfumo huu, hata maafa makubwa mahali fulani yakikata mstari wa mawasiliano, pakiti hujipata njia nyingine kiotomatiki na kuizunguka, hivyo kuzuia mawasiliano ya dunia nzima yasipooze kabisa." },
  { id:93, topic:"Nenosiri imara", emoji:"🔑",
    question:"Ili kulinda akaunti muhimu ya intaneti dhidi ya wezi (wadukuzi), ni njia gani ya kutengeneza 'nenosiri gumu kuvunjwa' iliyo salama zaidi?",
    choices:["Kutumia siku yako ya kuzaliwa au kama '123456': nambari rahisi na rahisi kukumbuka","Kuifanya 'mfuatano mrefu unaochanganya herufi za Kiingereza kubwa na ndogo, nambari, na alama' ambao hakuna anayeweza kubahatisha na haupo katika kamusi yoyote, na usitumie ileile katika programu nyingine","Kuandika jina lako kama lilivyo kwa Kiingereza","Kuandika nenosiri kwenye karatasi na kuibandika kando ya skrini ya kompyuta"],
    answerIndex:1,
    explanation:"Nenosiri la akaunti ni 'ufunguo' unaolinda nyumba yako ya kidijitali. Watu wabaya hutumia kompyuta kujaribu 'maneno ya kawaida' na 'michanganyiko rahisi ya nambari' mara mamilioni kwa sekunde ili kufungua kufuli (shambulio la nguvu butu). Ukitumia siku yako ya kuzaliwa au nenosiri rahisi unalotumia tena, linavunjwa kwa papo hapo na pesa zako za thamani na taarifa binafsi zote zinaibwa. Kutengeneza ufunguo usiotabirika wenye herufi 12 au zaidi zilizochanganywa kwa nasibu, na kuandaa ufunguo tofauti kwa kila huduma, ni mstari wa kwanza wa ulinzi unaozuia kwa hakika madhara ya uhalifu wa kidijitali." },
  { id:94, topic:"Ulaghai wa kuvua data", emoji:"🎭",
    question:"Kwenye skrini yako linatokea taarifa: 'Akaunti yako imesimamishwa. Ndani ya dakika 10, bonyeza URL (kiungo) hii na ujaze nenosiri na jina lako kuthibitisha.' Unaamuaje?",
    choices:["Itakuwa mbaya akaunti yangu ikipotea, kwa hiyo naharakisha kubonyeza kiungo hicho na kujaza taarifa zangu zote","Naona hii kuna uwezekano mkubwa ni 'ulaghai wa kuvua data', unaowadanganya watu kwa skrini bandia na kuwapora pesa, kwa hiyo sibonyezi kiungo kamwe, nafunga skrini mara moja, na nakagua kutoka tovuti rasmi halisi","Natuma nakala ya skrini hii kwa marafiki wote na tunajaribu kuingia pamoja","Napiga kelele kwa skrini"],
    answerIndex:1,
    explanation:"Hii ni mtego wa uhalifu wa woga sana unaoitwa 'ulaghai wa kuvua data', unaoweka 'hisia zako za haraka na hofu' katika mshtuko, kukufanya upoteze akili, na kukufanya wewe mwenyewe ujaze nenosiri kwenye tovuti bandia. Benki halisi au kampuni rasmi haitakutisha kamwe, asilimia 100, kwa barua pepe au taarifa ya kutilia shaka ili 'uingie sasa hivi na ujaze taarifa binafsi'. Ukiangalia kwa makini URL inayoonyeshwa, ni mfuatano bandia uliotengenezwa kufanana na jina halisi la kampuni (herufi moja tu tofauti, kwa mfano). Ukiona maneno yanayoharakisha, kwanza weka breki kwenye ubongo wako na tumia 'ujuzi wa kidijitali' wa kutilia shaka taarifa ili kuepuka mtego kabisa." },
  { id:95, topic:"Chapa ya kidijitali", emoji:"👣",
    question:"Ni sababu gani kubwa zaidi kwa nini usichapishe ovyo jina lako halisi, picha ya uso, mahali pa nyumbani, au njia ya kila siku ya shule yako kwenye mitandao ya kijamii au programu za intaneti?",
    choices:["Kuchapisha picha mtandaoni humaliza ghafla betri ya simu","Mara data inapowekwa hadharani mtandaoni, watu wengine huinakili (kuihifadhi) kwa papo hapo na huenea dunia nzima, kwa hiyo haiwezi kufutwa kabisa kamwe na inaweza kutumiwa vibaya maisha yote katika uhalifu kama ufuatiliaji wa kinyume au utekaji nyara (chapa ya kidijitali)","Kuandika maandishi mengi huvunja kioo cha skrini","Kuna sheria kwamba watoto hawaruhusiwi kuandika maandishi katika dunia ya mtandao"],
    answerIndex:1,
    explanation:"Taarifa unayoandika mtandaoni hubaki katika bahari ya mtandao kama chapa isiyofutika kamwe, ndiyo maana inaitwa 'chapa ya kidijitali'. Hata picha ya uso au data ya mahali uliyochapisha 'ukikusudia kuionyesha marafiki tu' inaweza kutumwa tena kwa papo hapo, kwa kitufe kimoja, kwa mamia ya mamilioni ya wageni dunia nzima, na kutumiwa vibaya na watu wabaya katika uhalifu wa kutisha kama utekaji nyara, ambapo wanakutambua na kukuvizia. Taarifa zako binafsi ni siri ya juu zaidi ya kulinda maisha na uhuru wako mwenyewe. Chonga akilini mwako kanuni baridi ya dunia ya kidijitali: ukishaiweka, ni vigumu kurudisha nyuma muda na kuifuta." },
  { id:96, topic:"Uthibitisho wa ukweli", emoji:"🔎",
    question:"Ukiwa unatafuta mtandaoni, unakuta makala ya kushangaza: 'Inasemekana kula nyama inayouzwa katika duka lile kubwa kunakufanya uwe na akili zaidi na kunaponya magonjwa yote!'. Ni njia gani isiyo mbaya zaidi ya kushughulikia taarifa hii?",
    choices:["Ni ugunduzi mkubwa wa ajabu, kwa hiyo naamini mara moja na naenda kununua nyama hiyo kwa wingi","Nakagua kutoka pande nyingi nani aliyeandika makala (mtaalamu, au shajara ya mtu binafsi tu) na kama vitabu vingine vya sayansi au data za kuaminika vina ukweli (ushahidi) uleule (uthibitisho wa ukweli)","Nanakili makala hii na kuieneza kwa kundi langu lote la marafiki nikisema 'kula haraka au utakufa'","Najifanya sikuona makala na natupa simu yangu chini"],
    answerIndex:1,
    explanation:"Bahari ya taarifa ya intaneti ina si tu maarifa sahihi kama almasi, bali pia mafuriko ya uongo wa ovyo (taarifa potovu), kutoelewa, na takataka iliyotengenezwa kwa makusudi kudanganya watu kwa faida. Hasa kwa sababu yeyote anaweza kueneza uongo kwa kitufe kimoja, anayemeza maandishi anayoona kama yalivyo huwa 'mtenda' anayeeneza taarifa za uongo, au 'mwathiriwa' anayeporwa pesa bure. Unapokutana na taarifa, hekima ya 'uthibitisho wa ukweli' - kuchunguza kutoka njia nyingi 'chanzo ni kipi?' na 'kuna data za ushahidi imara?' - inalinda usalama wa ubongo wako." },
  { id:97, topic:"Kiputo cha kichujio", emoji:"💬",
    question:"AI ya intaneti na mitandao hujifunza historia yako ya zamani ya utafutaji na kiotomatiki hukusanya kwenye skrini yako tu 'maoni unayoonekana kupenda' na 'hadithi utakazotaka kukubaliana nazo'. Ni nini mtego mkubwa zaidi uliofichwa wa hali hii (kiputo cha kichujio)?",
    choices:["Kwa kuwa unaona tu unachopenda, watu wote duniani wanaweza kuwa na furaha","Maoni yaliyo kinyume nawe na data sahihi za sayansi (ukweli) hukoma kufikia macho yako, kwa hiyo unajishawishi kwamba mtazamo wako pekee ndio sahihi asilimia 100, ubaguzi wako unaimarika, na unafanya maamuzi mabaya","Maandishi yote ya skrini yako yanabadilika kuwa Kiingereza","Kutoka simu yanaruka vitafunwa kiotomatiki"],
    answerIndex:1,
    explanation:"Ili kupata faida ya matangazo kwa kukufanya utazame skrini muda mrefu, AI ya mtandao inakufungia ndani ya kiputo cha taarifa tu zinazopendeza zilizolingana na ladha yako. Hii inaitwa 'kiputo cha kichujio' au 'jambo la chumba cha mwangwi'. Ndani ya kiputo hiki, unaangukia udanganyifu kwamba kila mtu duniani anafikiri kama wewe, na mtazamo wako unabana sana. Ili kushika picha kamili sahihi na kufanya uamuzi bora, unahitaji uwiano amilifu wa fikra: kufungua kwa makusudi, kwa mkono wako mwenyewe, chumba cha 'maoni tofauti na yako' na 'data baridi za sayansi'." },
  { id:98, topic:"Usimbaji wa data", emoji:"🔐",
    question:"Unapotuma ujumbe muhimu kwa mtu mwingine, unaitaje teknolojia inayogeuza maandishi kuwa msimbo tata uliotawanyika ili maudhui yasiweze kabisa kufichuliwa hata mwizi akiyaiba njiani?",
    choices:["Kuchakata tena","Usimbaji (usimbaji wa data / E2EE)","Usanisinuru","Mfumuko wa bei"],
    answerIndex:1,
    explanation:"Ngao yenye nguvu zaidi ya kutembea kwa usalama mtandaoni ni teknolojia ya 'usimbaji'. Kwa mfano, unapotuma maandishi 'habari', data inageuzwa papo hapo, kabla ya kupita njia ya intaneti, kuwa mfuatano wa herufi usio na maana kabisa kama 'x9F2m7q'. Hata jasusi mbaya anayeiba mawasiliano njiani akifaulu kuiba data, ikiwa imesimbwa maudhui hayawezi kusomwa. Na ni pale tu inapofika kwenye mashine ya rafiki yako lengwa ndipo inaporejeshwa kwa usafi kuwa 'habari' ya asili kwa 'ufunguo sahihi (ufunguo wa siri)' anaoumiliki rafiki yako. Kwa sababu ya teknolojia hii, tunaweza kununua na kuwasiliana kwa utulivu tukilinda faragha." },
  { id:99, topic:"Nakala rejea", emoji:"💾",
    question:"Ili kujikinga na kufuta kwa makosa data au mafaili ya jaribu ya thamani uliyotengeneza kwa bidii, au mashine kuharibika, unaitaje tendo la kuhifadhi nakala kamili katika mahali pengine salama (folda nyingine, USB, n.k.)?",
    choices:["Kusasisha","Nakala rejea (backup)","Utatuzi wa hitilafu","Uandishi wa programu"],
    answerIndex:1,
    explanation:"Data za kidijitali ni rahisi sana kwa sababu hazina umbo la kimwili, lakini sambamba hubeba hatari mbaya (udhaifu) kwamba 'hitilafu ya mashine au kosa la uendeshaji laweza kufanya kila kitu kitoweke kabisa kwa papo hapo'. Hekima pekee inayozuia msiba mkubwa wa hazina iliyotengenezwa kwa siku nyingi kuwa sufuri kwa papo hapo ni 'nakala rejea'. Kwa kuhifadhi nakala kamili ya data katika diski ngumu nyingine au seva ya mahali pa mbali (wingu), hata mashine yako kuu ikiungua kwa moto au kuharibika, unaweza kurejesha na kufufua hali tajiri ya asili asilimia 100 kwa sekunde moja. Ni tabia ya msingi ya jamii ya taarifa: kusambaza hatari ili kujiandaa na yasiyotarajiwa." },
  { id:100, topic:"Kutokujulikana mtandaoni", emoji:"🕵️",
    question:"Uliandika matusi au uvumi wa uongo kuhusu mtu kwenye ubao wa matangazo au mtandao wa kijamii wa intaneti. Je, ni kweli kwamba hakuna atakayejua kamwe ni nani aliyeandika maadamu unatumia 'jina la kutokujulikana (jina la uongo)'?",
    choices:["Maadamu unaghushi jina lako, hata polisi wa dunia na nguvu ya sheria haviwezi kujua kamwe, asilimia 100","Si kweli kabisa. Kila mawasiliano kupitia mtandao daima huacha alama ya 'anwani ya IP (anwani)' inayorekodi kwa usahihi data ilitumwa kutoka mashine ipi ya nyumba ipi, kwa hiyo mhalifu anaweza kutambuliwa na kukamatwa wakati wowote","Usiku ukifika, data uliyoandika hutoweka kiotomatiki","Ukiandika herufi kinyume kutoka nyuma, hakuna atakayeweza kujua kamwe"],
    answerIndex:1,
    explanation:"Hongera! Kwa hili unafikia hatua muhimu ya swali la '100' la mfululizo mzima. Anayetumia 'jina la kutokujulikana' kufanya fujo kwa matusi au vitisho katika dunia ya mtandao anadhani amevaa joho la kutoonekana, lakini huo ni udanganyifu mkubwa. Njia ya intaneti (mtoa huduma) hurekodi kiotomatiki, asilimia 100 kwa usahihi, saa 24, alama ya kielektroniki kamili (kumbukumbu, anwani ya IP) ya 'saa, dakika, na sekunde ngapi, na kutoka mashine ya anwani gani ya Dunia, pakiti ilitumwa'. Ukiandika maneno yanayomuumiza mtu, kupitia kesi na taratibu za sheria jina lako halisi na nyumba yako vinatambuliwa kwa pigo moja, na unalipa matokeo mabaya zaidi: faini nzito au kukamatwa. Jua mfumo uliofichwa wa mtandao na utumie maneno yenye uwajibikaji." },
  { id:101, topic:"Mbinu za utafutaji", emoji:"⌨️",
    question:"Ukitumia injini ya utafutaji ya intaneti, ni njia gani ya utafutaji yenye ufanisi zaidi ya kupata kwa papo hapo data sahihi za sayansi unazozitaka kweli, bila kuzuiwa na takataka ya taarifa isiyofaa?",
    choices:["Kuingiza sentensi zako za hisia kama zilivyo, ndefu, kama 'tumbo linauma, nisaidie, nifanyeje'","Kuchagua maneno 2 au 3 ya msingi (maneno muhimu) ya kile unachotaka kujua na kuyachanganya, yakitenganishwa kwa 'nafasi', kama 'jinsi tumbo linavyofanya kazi  asidi ya tumbo  asidi'","Kuingiza nambari moja tu mara kwa mara kwenye kisanduku cha utafutaji","Kufumba macho na kupiga vitufe vingi vya kibodi ovyo"],
    answerIndex:1,
    explanation:"Hekima ya algoriti ya kuvuta almasi inayohitajika kutoka bahari ya taarifa kwa kasi zaidi inaitwa 'utafutaji wa maneno muhimu (utafutaji wa NA)'. Ukitafuta kwa maneno ya hisia kama 'nisaidie', linatokea furiko la shajara za uongo zenye hisia na kelele sawa, na muda wako unapotea. Kwa kupanga maneno kadhaa ya 'majina mahususi kamili na maneno ya sayansi' ya kile unachotaka kujua, yakitenganishwa kwa nafasi, injini ya utafutaji inabana kwa usafi na kukuletea tu 'vitabu na data halisi za hali ya juu zinazomo maneno yote kwa pamoja'. Kubobea jinsi ya kutafuta taarifa (uwezo wa utafutaji) kunapelekea ongezeko la tija linalozalisha muda wa maisha mara nyingi zaidi." },
  { id:102, topic:"Uchumi wa uangalifu", emoji:"🎰",
    question:"Mitandao na michezo mingi hufanya taarifa mpya zitokee unapovuta skrini chini, au hujaribu kukufanya ubonyeze kitufe cha 'napenda (tathmini)' mara nyingi. Ni nini lengo kubwa zaidi lililofichwa (mtego) la muundo huu wa skrini?",
    choices:["Ni kazi ya kujitolea ya wema ya kuharakisha akili za watoto na kuwafanya mahiri","Inachunguza kisaikolojia hitilafu katika ubongo wa binadamu unaohisi raha unapokutana na bahati ya kibahati nasibu (kutolewa kwa dopamini), inakufanya ushindwe kuachana na programu, na inakupora 'muda wako wa thamani wa maisha (uangalifu)' kupata faida ya matangazo (mtego wa uchumi wa kitabia)","Kusafisha kiotomatiki uchafu wa skrini ya simu","Hakuna lengo maalum; ni umbo lililotengenezwa ovyo"],
    answerIndex:1,
    explanation:"Huu ni mtego wa kutisha wa 'uchumi wa uangalifu (biashara ya kupora muda)' uliowekwa na makampuni makubwa ya teknolojia ya leo. Kama mashine ya kamari ya kasino, wakati ubongo wa binadamu unakabili hali ya 'nikisogeza skrini, sijui hadithi gani ya kufurahisha (bahati) inakuja baadaye', ubongoni hutoka kwa wingi dutu ya raha dopamini, na hauwezi tena kuacha kwa nguvu ya utashi wako mwenyewe. Bila kujua umepoteza masaa mengi, nguvu yako ya kusoma na kufanya kazi imeporwa, na maisha yako yananyonywa kwa faida yao. Ona kwa utulivu 'mtego wa saikolojia unaokufanya mraibu' nyuma ya skrini, na rudisha mamlaka ya muda wako mkononi mwako." },
  { id:103, topic:"Virusi vya kompyuta", emoji:"🦠",
    question:"Mtandaoni, ukifungua bila tahadhari kiambatisho cha barua pepe kutoka kwa mtu usiyemjua, au faili la kutilia shaka linalosema 'pakua hili ucheze michezo ya kulipia bure', ni nini huingia ndani ya mashine na kuiharibu?",
    choices:["Vijidudu vya kutu ya chuma","'Virusi vya kompyuta (programu hasidi)' inayoteka mfumo wa mashine kutoka nyuma, au kuteka data za ndani mateka na kuziharibu","Uchawi unaofanya maji yafurike","Maandishi tupu tu, yasiyohusiana kabisa"],
    answerIndex:1,
    explanation:"Bahari ya intaneti imetawanywa kwa wingi programu hasidi - 'virusi vya kompyuta (programu hasidi)' - zilizotengenezwa kuharibu simu na kompyuta za wengine au kuiba nenosiri na data za pesa za ndani. Wanavaa barakoa ya maneno matamu kama 'ni bure' au 'programu inayotoa pesa nyingi', na wanavizia ili wewe mwenyewe ubonyeze kitufe cha kuruhusu upakuaji. Pale unapolifungua kwa uzembe, mashine yako inatekwa na virusi na kufanywa 'mbeba virusi (kompyuta zombi)' inayotuma pakiti za virusi kwa mashine za marafiki kwa nia yake yenyewe. Tekeleza kwa ukamilifu kanuni ya chuma ya ulinzi: usifungue kamwe faili ambalo chanzo chake si cha kuaminika asilimia 100." },
  { id:104, topic:"Vipengele viwili", emoji:"📲",
    question:"Unapoingia kwenye akaunti muhimu, baada ya kuingiza nenosiri ulilopanga awali, unaitaje mfumo wa usalama unaokufanya zaidi uingize 'msimbo wa nambari wa matumizi ya mara moja (msimbo wa uthibitisho)' uliofika kwenye simu yako?",
    choices:["Biashara ya kubadilishana bidhaa","Uthibitishaji wa vipengele viwili (uthibitishaji wa hatua mbili / 2FA)","Marufuku ya ukiritimba","Kufuta algoriti"],
    answerIndex:1,
    explanation:"Mfumo wa usalama wenye nguvu zaidi, unaopandisha kwa pamoja usalama wa akaunti zaidi ya mara elfu kumi, ni 'uthibitishaji wa vipengele viwili'. Hata nenosiri ulilotengeneza (kipengele cha kumbukumbu) likiibwa na mwizi anayejaribu kuingia kutoka upande mwingine wa dunia, mfumo huu ukiwepo, mwizi hawezi kuingia. Kwa sababu mlango wa nyumba haufunguki isipokuwa uingize nambari ya siri inayofika kwa wakati halisi kwenye simu yako halisi (kipengele cha umiliki) na kutoweka kwa papo hapo. Kwa akaunti zako muhimu, kuwa na hekima ya kuweka daima mstari huu wa pili wa ulinzi." },
  { id:105, topic:"Taarifa kupita kiasi", emoji:"🌀",
    question:"Kila siku, kutoka televisheni na intaneti, kiasi kisichohesabika cha taarifa, maandishi, na video kinakimbilia simu yako. Kama njia ya kutumia kichwa kuokoka kwa hekima bahari hii kubwa ya taarifa (taarifa kupita kiasi), ni uamuzi gani sahihi?",
    choices:["Unapaswa kuingiza kichwani kila video na makala inayotiririka, bila kukosa neno moja, saa 24","Kubali kwamba taarifa ina asilimia 99 ya kelele (takataka isiyofaa na uvumi), chagua kwa hekima tu data 'zenye manufaa makubwa (zenye msaada)' kama almasi zinazokufurahisha, puuza kabisa kelele zilizobaki, na linda nguvu ya ubongo wako","Kuandika maoni ya hasira kwa kelele kuhusu kila taarifa","Kuamini taarifa zote za mtandao na kupata hofu kila siku"],
    answerIndex:1,
    explanation:"Jamii ya kisasa ni enzi ya 'taarifa kupita kiasi', ambapo data inayozidi mbali kikomo cha uwezo wa kuchakata wa ubongo wa binadamu inafurika. Ukijihusisha kihisia na kila habari na uvumi unaotiririka - 'lo, nifanyeje!' 'huyo ni mbaya!' -, nishati ya thamani ya ubongo wako (uamuzi wa lobe ya mbele) inaisha kwa muda mfupi, na haikubaki nguvu ya kufanya maamuzi muhimu ya maisha yako mwenyewe. Hekima ya kutoa kwa baridi 'ishara (maarifa yanayohitajika kweli)' kutoka 'kelele (malalamiko ya wengine na taarifa potovu)', na kuacha kelele zipite bila hata kuziweka mtazamoni mwako, inakuza zaidi afya na uhuru wa ubongo wako." },
  { id:106, topic:"Chanzo huria", emoji:"🐧",
    question:"Unaitaje mfumo wa ushirikiano wa ajabu ambapo waandishi mahiri wa programu dunia nzima hawafichi msimbo chanzo (mchoro wa programu) wa programu yenye manufaa waliyoitengeneza kwa bidii, bali wanau'chapisha bure kwa kila mtu' mtandaoni ili kila mtu aweze kuubadilisha na kuuboresha kwa uhuru?",
    choices:["Mfumo wa ukiritimba","Chanzo huria (OSS)","Mfumuko wa bei","Kuficha ufunguo wa siri"],
    answerIndex:1,
    explanation:"Badala ya kampuni moja kuficha mchoro kwa siri kuujenga (chanzo funge), kuuchapisha mchoro kabisa kwa makumi ya maelfu ya waandishi wa programu duniani, wanaopata hitilafu na kuuboresha pamoja, kunakamilisha mfumo wa haraka zaidi na wa ajabu zaidi. Mfumo huu unaitwa 'chanzo huria'. Mifumo inayoendesha intaneti dunia nzima (kama Linux), zana zenye manufaa za uundaji, na hata teknolojia ya msingi ya programu hii, kwa kiasi kikubwa imetengenezwa kwa 'hekima ya ushirikiano' ya binadamu iliyo chanzo huria. Kushiriki na kuendeleza kwa ajili ya utajiri wa wote, badala ya kumiliki peke yako faida yako, ni utamaduni mzuri zaidi wa kusaidiana wa dunia ya kidijitali." },
  { id:107, topic:"Wingu", emoji:"☁️",
    question:"Badala ya kuhifadhi picha na data ndani ya simu au kompyuta yako mwenyewe, unaitaje mfumo wa kukabidhi data kwa usalama kwa 'vituo vya data vikubwa mno vya dunia nzima (sanduku za chuma)' ndani sana ya njia ya intaneti, ili uweze kuziondoa kutoka popote?",
    choices:["Tundu la soketi ya umeme","Wingu (hifadhi ya wingu)","Sanduku la kubadilishana bidhaa","Sahani ya analogi"],
    answerIndex:1,
    explanation:"Ukiweka data ndani ya mashine yako mwenyewe tu (ndani), pale unapoidondosha na kuivunja au kuipoteza, data ya hazina pia inapotea kwa papo hapo. Lakini kwa kutumia teknolojia ya 'wingu' (maana yake mawingu), data yako inahifadhiwa kwa usalama, kupitia intaneti, kwenye seva za vituo vya data vikubwa imara zaidi na vya nakala rejea kamili zaidi duniani. Kwa sababu ya hili, hata simu yako ikiharibika na ukanunua mpya, kwa kuingia tu kutoka mashine mpya unaweza kuiondoa data ya asili, kama ilivyokuwa, kwa sekunde moja, kana kwamba hakuna lililotokea. Ni miundombinu ya kidijitali inayozidi mipaka ya kimwili ya data na kufanya kamili uhifadhi wa mali yako." },
  { id:108, topic:"Ujifunzaji wa mashine na AI", emoji:"🤖",
    question:"Miaka ya hivi karibuni, kwa kuiga jinsi ubongo wa binadamu unavyofanya kazi na kuifanya isome data kwa wingi (uzoefu), 'AI (akili bandia)' kiotomatiki hujifunza kutofautisha picha na kutengeneza sentensi. Unaitaje teknolojia hii?",
    choices:["Ujifunzaji wa mashine (ujifunzaji wa kina)","Matumizi ya hesabu ya kuhesabu miti","Hesabu ya analogi","Utengenezaji wa nenosiri kiotomatiki"],
    answerIndex:0,
    explanation:"Mfumo unaofanya AI iwe na akili huitwa 'ujifunzaji wa mashine'. Badala ya binadamu kuandika amri mstari kwa mstari, AI huangalia kwa makini (hujifunza kutoka) mamilioni ya 'data za picha za mbwa' kwa nia yake yenyewe, kiotomatiki hupata kwa hesabu sifa zinazofanana kwa mbwa (mifumo ya umbo la masikio na mchoro wa pua), na inapoona picha mpya inaweza kuamua kwa kujitegemea 'huyu ni mbwa kwa uwezekano wa asilimia 99'. Kwa kujua mfumo huu wa AI, badala ya kuiogopa au kuiabudu kama mungu wa kichawi, unaweza kuwa na mtazamo wa kibinadamu mkomavu wa kuimudu kwa utulivu kama 'shoka la kizazi kijacho lenye manufaa zaidi (chombo)' kwa kufanya mambo kuwa na ufanisi wa hali ya juu kwa kutumia data." },
  { id:109, topic:"Unyanyasaji wa mtandaoni", emoji:"🗯️",
    question:"Katika gumzo za intaneti au michezo, kwa nini unyanyasaji (unyanyasaji wa mtandaoni) - kuandika maneno makali (kufa, mjinga, toweka, n.k.) kwa marafiki au wageni, au kueneza uvumi wa uongo mbaya - ni uhalifu mbaya kama vurugu ya dunia halisi?",
    choices:["Kuandika maandishi mengi huziba mstari wa mtandao na kuufanya mzito","Wembe wa maneno huleta jeraha kubwa na zito kwenye ubongo na moyo (akili) ya mtu mwingine, na una nguvu halisi ya kutisha ya kuharibu, inayoweza kumzamisha katika kukata tamaa na kuchukua maisha yake","Maandishi ya mtandao huchafua kioo cha skrini","Hakuna sababu maalum; mtandaoni uko huru kusema chochote"],
    answerIndex:1,
    explanation:"Fikra 'kwa kuwa damu inayoonekana haitoki, kusema mabaya kwa maandishi si kitu kikubwa' ni, kitabibu na kisayansi, kosa kubwa kabisa. Ubongo wa binadamu anayeendelea kunyunyiziwa maneno makali na maneno ya unyanyasaji ya kuendelea kutoka skrini una 'eneo lilelile la ubongo (mtandao wa neva za maumivu)' linalopiga kelele kwa nguvu na kuumia, kama anapopigwa shambulio kali la kimwili (ngumi au teke), na seli zake zinakufa. Maneno wakati mwingine huwa silaha hatari inayoharibu maisha ya mtu vipande vipande, kwa kina zaidi na muda mrefu zaidi kuliko vurugu ya kimwili. Kulipa heshima kwa moyo na haki za binadamu za wengine, na kuzungusha nishati ya maneno mazuri, ni maadili kamili ya jamii ya mtandao." },
  { id:110, topic:"Vidakuzi", emoji:"🍪",
    question:"Unapovinjari tovuti yoyote ya intaneti (kununua, kusoma, n.k.) kwa simu au kompyuta, daima hubadilishwa kwa siri nyuma ya pazia kati ya mashine, 'data ya kumbukumbu ya alama za miguu na mapendeleo ya mashine yako'. Unaitaje hii?",
    choices:["Ufunguo wa nenosiri","Kidakuzi (Cookie)","Maandishi ya msimbo","Alama ya kuchakata tena"],
    answerIndex:1,
    explanation:"Kuna mfumo wa taarifa unaoitwa 'kidakuzi (Cookie)', jina lilelile la biskuti ya kidakuzi. Ni kama 'karatasi ndogo ya maandishi ya kumbukumbu' ambayo mwendeshaji wa tovuti huacha kwa siri ndani ya kivinjari cha mashine yako. Kwa sababu ya karatasi hii, unapata manufaa rahisi (faida) kama kuingia kiotomatiki siku inayofuata kwenye tovuti uliyoingia mara moja, bila kuingiza kitambulisho chako, au bidhaa kwenye kikapu cha ununuzi kutotoweka. Lakini sambamba, data ya tabia kuhusu 'tovuti gani unaziangalia na una shauku gani' inavuja kwa makampuni nyuma ya pazia, na unafanywa lengo la matangazo: hatari ya faragha (hasara). Elewa vizuri mwanga na kivuli vya mfumo huu." },
  { id:111, topic:"Masharti ya matumizi", emoji:"📜",
    question:"Unapoanza programu au mchezo mpya, ni hatari gani ya kiuchumi ya kubonyeza moja kwa moja kitufe cha 'nakubali' bila kusoma 'masharti ya matumizi', yaliyoandikwa kwa herufi ndogo mno na yanayotokea kwa urefu mwanzoni mwa skrini?",
    choices:["Usiposoma masharti, rangi ya skrini ya simu inabadilika yote kuwa waridi","Kuna kupuuza (hitilafu) ndani ya hati, na kwa kweli, hata ukiwa umefanyizwa kukubali ahadi isiyofaa (mkataba) kwamba 'kampuni inaweza kuuza kwa uhuru dunia nzima taarifa zako binafsi na picha kwa faida', unakabidhi haki zako za binadamu bila kujua","Kuna sheria kwamba wasiosoma masharti hawawezi kupanda ngazi katika mchezo","Pale unapoanza programu, umeme wote wa nyumba yako unazimika"],
    answerIndex:1,
    explanation:"Kama ulivyojifunza katika uchumi wa Kifurushi cha 2, kubonyeza kitufe cha 'nakubali' kuna uzito uleule wa 'kupiga muhuri na kutia saini kwenye mkataba wa karatasi' katika dunia ya watu wazima: tendo kali la kisheria. Miongoni mwa programu mbaya daima kuna zinazoingiza kwa makusudi sharti la kutisha ndani sana ya herufi ndogo asizosoma yeyote: 'tutanyonya anwani zote na data za picha za simu yako na kuzitumia kwa uhuru'. Hata kama ni vigumu kusoma yote kikamilifu, kuwa na tahadhari ya hekima ya angalau kutumia macho ya hekima na kusogeza kwa kidole kukagua vyumba muhimu vinavyoandikwa 'ushughulikiaji wa taarifa binafsi' na 'kanuni za pesa (malipo ndani ya programu)'." },
  { id:112, topic:"Dunia ya 0 na 1", emoji:"🔢",
    question:"Dunia ya binadamu ina herufi nyingi, rangi tata, na muziki mzuri, lakini ndani ya kichwa cha kompyuta (kidijitali), taarifa zote zinaonyeshwa na kuhesabiwa kwa 'mchanganyiko wa nambari mbili' tu. Ni nambari zipi mbili hizo?",
    choices:["1 na 2","0 na 1 (binari / msingi 2)","9 na 10","100 na 1000"],
    answerIndex:1,
    explanation:"Nyuma ya mzunguko wa kielektroniki wa kompyuta kwa kweli unaweza kutofautisha tu mifumo miwili: 'hali ambapo umeme unapita (ON / 1)' na 'hali ambapo haupiti (OFF / 0)'. Mfumo wa kubadilisha herufi zote, rangi za picha, na mitetemo ya muziki kuwa data za nambari na kuzichakata kwa mchanganyiko huu wa swichi za 0 na 1 tu unaitwa 'kidijitali (msingi 2 / binari)'. Hata mfumo wa jiji kubwa au mchezo wa ubora wa juu ukionekana tata kiasi gani, ukizama hadi msingi wake wa msingi, kila kitu kimejengwa kwa 'upatano (mantiki) rahisi na mzuri wa 0 na 1' huu tu. Kujua mzizi wa mfumo ni hatua ya kwanza ya kutawala kidijitali." },
  { id:113, topic:"Chambo cha mibofyo", emoji:"🖱️",
    question:"Unaitaje makala hasidi ya intaneti inayoweka kwa makusudi kichwa (kichwa cha habari) kikali na cha kuchochea udadisi - kama 'Mshtuko! Shujaa wa anime ile maarufu sana kumbe alijeruhiwa vibaya na kutoweka!?' - ili kukufanya ubonyeze kiungo?",
    choices:["Makala ya chanzo huria","Chambo cha mibofyo (makala ya kuvua / ulaghai wa mibofyo)","Makala ya uthibitisho wa ukweli","Taarifa ya nakala rejea"],
    answerIndex:1,
    explanation:"Kichwa cha kuvua kinachodukua hisia za binadamu za udadisi na mshtuko - 'lo, nina udadisi!' 'kweli?!' - ili kukufanya 'ubofye' kiungo kwa namna yoyote kinaitwa 'chambo cha mibofyo'. Lengo lao si hata milimita moja kukufikishia ukweli sahihi. Lengo lao pekee ni kukufanya ubonyeze kiungo, kuonyesha matangazo ya tovuti yao kwenye skrini yako, na kupata faida ya matangazo (pesa). Ukifungua, mara nyingi kuna mstari mmoja tu wa uongo wa kipuuzi au uvumi usio na maana. Ukiona kichwa kikali, kiangalie kwa baridi kwa macho ya mantiki - 'aha, hii inajaribu kunivua na kupata pesa' - na weka breki ya hekima ya kukipuuza." },
  { id:114, topic:"Ulaghai wa ushindi", emoji:"🎉",
    question:"Ukifungua intaneti na herufi kubwa zinatokea: 'Hongera! Wewe ni mshindi wa bahati uliyechaguliwa kati ya watu 1,000,000 wa dunia nzima! Bonyeza hapa sasa na upokee simu ya kifahari ya kisasa zaidi bure (sarafu 0)!'. Unaamuaje?",
    choices:["Ni bahati kubwa zaidi duniani, kwa hiyo kwa furaha kubwa nabonyeza kitufe na kuingiza anwani ya kupelekea na nambari ya simu ya nyumbani","Naona kwa mantiki ni asilimia 100 mtego bandia wa uhalifu (ulaghai wa ushindi), nabonyeza kitufe cha msalaba kwenye skrini, na nakipuuza kabisa. Kwa sababu duniani hapa hakuna kabisa mgeni mwema anayempa mtoto asiyemjua kitu cha kifahari bure, bila sababu","Ili kujivuna kwa marafiki, napiga picha ya skrini hii na kuiweka kwenye mtandao wa kijamii","Ili kuona kama kweli naweza kupata, nagusa skrini mara 10,000 mfululizo"],
    answerIndex:1,
    explanation:"Huu ni mtego wa 'ulaghai wa ushindi' wa kawaida sana na mbaya zaidi, ambapo mamilioni ya watu duniani wananaswa. Ukibonyeza kitufe, unaambiwa kitu kama 'lipa sarafu 100 tu za usafirishaji kwa kadi', na pale unapoiingiza, data zote za msimbo za kadi ya mkopo ya nyumba yako zinaibwa na mamia ya maelfu ya sarafu zinatumiwa bila ruhusa, kuifanya nyumba yako ifilisike. Kama ulivyojifunza katika uchumi wa Kifurushi cha 2 na usimamizi wa hatari wa Kifurushi cha 3, utajiri wa bure unaoanguka ghafla kutoka angani, mahali pasipo na kazi au ubadilishanaji sawa wa thamani, ni asilimia 100 mwajibu mustahili. Fagia mtego unaolenga 'hisia yako ya tamaa' kwa mantiki ya sayansi." },
  { id:115, topic:"Deepfake", emoji:"🎬",
    question:"Kwenye televisheni au intaneti, unaona [video] ya habari ya kiongozi maarufu akisema kwa sauti kubwa: 'Kuanzia sasa, wachukulie marafiki wote kama wezi na muwapore chakula chao chote!'. Je, ni sawa kuamini video hii ni asilimia 100 halisi?",
    choices:["Kuna ushahidi wa video ninayoiona kwa macho na sauti ninayoisikia kwa masikio, kwa hiyo ni asilimia 100 halisi","Usiamini kamwe kama ilivyo. Kwa teknolojia ya AI ya sasa (deepfake), 'video ya uso' bandia au 'sauti ya kuzungumza ya uongo' isiyotofautishika na halisi inaweza kughushiwa kwa sekunde moja, kwa hiyo unapaswa kuthibitisha ukweli (ukweli) ulio nyuma ya video","Mtu wa kwenye video akivaa nguo za kuvutia, ninapaswa kuamini","Lililo sahihi ni kutupa jiwe kwenye video kuiharibu"],
    answerIndex:1,
    explanation:"Zamani za kale, 'video au picha zilizoonekana kwa macho' zilikuwa ushahidi kamili wa ukweli. Lakini katika enzi ya kisasa ambapo teknolojia ya AI imebadilika kwa mlipuko, teknolojia inayoitwa 'deepfake' inayosanisi video na sauti bandia zinazofanana kabisa na halisi inatumiwa vibaya. Matukio ambapo wanasiasa wabaya au walaghai, ili kushusha heshima ya mpinzani au kuanzisha vita, wanafanya video iseme 'sentensi ya uongo isiyowahi kusemwa' kwa kufanana kabisa na mtu halisi ili kudanganya watu, yanatokea sana dunia nzima. Hasa kwa sababu tunaishi katika enzi ambapo hata video iliyoonekana kwa macho si tena asilimia 100 ukweli, 'ngao ya taarifa' ya hali ya juu - kukagua data rasmi na ushahidi wa tovuti kadhaa za uthibitisho wa ukweli kabla ya kukasirika kihisia - ni muhimu kabisa." },
  { id:116, topic:"Hakimiliki", emoji:"🎨",
    question:"Kunakili bila ruhusa muziki mzuri, msimbo wa programu wa ajabu, au mchoro au maandishi pendwa (kazi yenye hakimiliki) iliyotengenezwa na mtu mwingine kwa bidii, kudanganya kwamba ni yako na kuisambaza mtandaoni (kama kusambaza nakala bandia), kwa nini ni uhalifu usiopaswa kufanya kamwe?",
    choices:["Kunakili kitu cha mtu mwingine hufanya simu yako iwe na uzito mara mbili","Kunakosa heshima kwa wabunifu wanaozalisha thamani (hekima) mpya ya ajabu, na kunaharibu mfumo wa motisha ambao kwao wanapata malipo ya haki ya kazi yao, kukasimamisha mageuzi ya jamii nzima (ukiukaji wa hakimiliki)","Kunakili bila ruhusa hufanya rangi yote ya maandishi ibadilike kuwa wazi","Kuna sheria kwamba kila mtu anaweza kutumia kwa uhuru chochote walichotengeneza marafiki"],
    answerIndex:1,
    explanation:"Mali ya hekima ya kipekee anayozalisha mtu kwa kutumia kichwa inaitwa 'mali ya kiakili', na ngao ya kisheria inayoilinda inaitwa 'hakimiliki'. Ukifanya dunia (msitu usio na sheria wa mwenye nguvu kumla mnyonge) ambapo yeyote anaweza kwa uhuru kuiba na kusambaza bure bila ruhusa chochote walichotengeneza wengine, wabunifu waliotafiti kwa juhudi kwa miezi kutengeneza programu na muziki wa ajabu hawataweza kula, na hakuna atakayetengeneza tena zana mpya zenye manufaa. Ili kutosimamisha kijiti cha mageuzi ya jamii, linda kwa haki thamani ya hekima ya wengine na ulipe heshima. Hii ni ahadi ya upole ya wote katika jamii ya taarifa yenye hekima." },
  { id:117, topic:"Utatuzi wa hitilafu", emoji:"🐞",
    question:"Ukiwa unaunganisha msimbo wa programu, kosa (hitilafu) linatokea na programu haifanyi kazi kama ulivyotaka. Wakati huu, ni utaratibu gani wenye mantiki, wa haraka, na wa hekima zaidi wa 'kubaini chanzo (utatuzi wa hitilafu)'?",
    choices:["Nikipiga kelele 'haifanyi kazi! mbaya zaidi!', nafuta msimbo wote kwa papo hapo na kuuandika upya kutoka sufuri ovyo","Nasoma kwa utulivu maandishi ya ujumbe wa kosa, na kwa kupima kisanduku baada ya kisanduku kwa mpangilio, nabaini 'hadi wapi programu inafanya kazi kawaida na kutoka mstari upi (data ipi) mgongano unaanza' (utatuzi wa hitilafu)","Napiga skrini ya kompyuta kwa nguvu kwa ngumi","Nakasirika na kuwalaumu watu wa karibu, nikidai mtu mwingine aliuandika upya msimbo bila ruhusa"],
    answerIndex:1,
    explanation:"Tendo la kupata na kurekebisha hitilafu (kosa) ya programu linaitwa 'utatuzi wa hitilafu'. Hitilafu inapotokea, anayepata hofu, anayeamua 'yote ni mabaya', anayetegemea hisia, na kuandika upya ovyo huzalisha mwenyewe hitilafu mpya nyingi zaidi na hupoteza muda bila kikomo. Mfumo wa kompyuta ni waaminifu sana na husogea tu kwa kanuni za sababu na matokeo. Hitilafu kutokea maana yake daima, mahali fulani, kuna 'mgongano wa mantiki (amri ya ajabu)' uliofichwa kama mkengeuko wa milimita moja. Kusawazisha hisia kabisa na kugawanya data moja baada ya nyingine kubaini mpaka - 'hadi hapa OK, kutoka hapa NG' - ni njia bora zaidi ya kutumia kichwa, fikra ya mantiki ya kutoa inayofaa si kwa uandishi wa programu tu, bali kwa kutatua matatizo yote ya maisha." },
  { id:118, topic:"Mwanga wa buluu na usingizi", emoji:"🛌",
    question:"Usiku, ukiwa kitandani katika chumba cha giza, tabia ya kutazama skrini ya simu (mwanga wa buluu) hadi muda mfupi kabla ya kulala huharibu hadi kuangamiza nguvu ya mwili na ubongo wako. Ni sababu gani ya kisayansi?",
    choices:["Kutoka skrini ya simu yanaruka wadudu wadogo wasioonekana wanaokula ubongo wako","Mwanga mkali wa buluu kutoka skrini huchochea neva ndani ya macho yako na kufanya ubongo wako udanganyike sana (hitilafu) - 'sasa ni mchana, saa sita, anga limeng'aa wazi!' -, kwa hiyo husimamisha kabisa utoaji wa homoni muhimu ya kulala (melatonin)","Kutazama skrini usiku hufanya mashine ya simu iote kutu na kuharibika","Kuna kanuni kwamba ukiangalia mwanga gizani, kucha zote za miguu yako zinang'oka"],
    answerIndex:1,
    explanation:"Ndani sana ya ubongo wa binadamu kuna mfumo wa saa (mdundo wa siku) unaodhibiti joto la mwili na usingizi, ukisema 'sasa ni asubuhi, sasa ni usiku', sambamba na kalenda ya saa 24 ya mzunguko mmoja wa Dunia. Binadamu wa zamani waligundua usiku kwa kuona wekundu wa mwanga wa jua na kuanza kujiandaa kulala. Lakini 'mwanga wa buluu' kutoka skrini ya simu una urefu wa wimbi uleule kabisa wa mwanga wa jua wa mchana. Ukiooga mwanga huu kwa umbali wa karibu gizani usiku, kihisi cha saa ya ubongo wako kinarusha hitilafu kali - 'aha! sasa ni mchana! lazima niamke!' - na kuzima kabisa 'swichi ya usingizi mzito' ya kusafisha ubongo na kurekebisha mwili. Matokeo yake, hakuna uchovu unaoondoka hata ukilala, siku inayofuata kichwa chako kinakuwa na ukungu na hasira, na nishati yako ya uhuru inashuka kwa nguvu. Kufunga skrini saa moja kabla ya kulala ni hekima ya sayansi ya matengenezo ya kila siku ili usiharibu ubongo wako wa thamani, chombo chako cha siri ya juu zaidi." },
  { id:119, topic:"Mtandao uliosambaa", emoji:"🕸️",
    question:"Ikilinganishwa na mfumo wa 'serikali kuu' unaokusanya data zote na mamlaka za dunia kwenye kompyuta (seva) moja kubwa ili kuzisimamia, ni faida gani kubwa zaidi, kwa mtazamo wa ulinzi, ya mfumo (P2P / mtandao uliosambaa) ambapo kompyuta ndogo za dunia zinaunganishwa zikishirikiana data kwa usawa?",
    choices:["Kufanya seva moja kuu kuwa kubwa zaidi kunaonekana kuvutia zaidi na imara zaidi","Kwa kuwa hakuna mfalme wa kati, hata mwizi au dikteta mbaya akilipua au kuteka kituo kimoja, ni asilimia 100 mwajibu mustahili kuharibu mfumo mzima au kufuta data kabisa: una uimara usioshindika (ustahimilivu)","Kusambaza kunafanya matumizi ya umeme yawe sufuri kila wakati","Mashine ndogo zinaweza kuchapa nambari kubwa zaidi kwenye noti za pesa"],
    answerIndex:1,
    explanation:"Huu ni ushahidi wa hekima kubwa zaidi wa 'kusambaa', msingi wa Web3 na mitandao ya kizazi kijacho. Mfumo wa serikali kuu, pale kompyuta kuu zaidi ya kati (mfalme) inapoangushwa, au dikteta mbaya akiandika upya (kughushi) kwa namna inayomfaa data ya ndani, au mstari ukiondolewa, hufanya mfumo wa jamii nzima iliyounganishwa uporomoke kabisa kwa papo hapo na kuangamia yote. Lakini katika mtandao wa 'rika kwa rika (P2P)' au uliosambaa ambapo kila mtu anashikilia kidogo cha data kwa usawa na kuangaliana, hata sehemu 1 au 10 zikiharibiwa na adui, makumi ya maelfu ya kompyuta zilizobaki zinaendelea kufanya kazi salama, kwa hiyo mfumo unaendelea kuzunguka kwa kujitegemea bila kusimama milimita moja. Ni mantiki ya mfumo wenye nguvu zaidi: kutomruhusu mtawala mmoja mwenye nguvu ashike maisha na mali, na kudumisha dunia salama kwa imani ya usawa ya wote." },
  { id:120, topic:"Muhtasari wa kidijitali", emoji:"💡",
    question:"Swali la mwisho kwako, uliyemaliza Kifurushi cha 4 chote cha 'Wise World 3' hii. Ni nini [lengo kubwa la kweli] la kujifunza kwa usahihi jinsi za msingi za intaneti, teknolojia ya kidijitali, na uandishi wa programu?",
    choices:["Kuwa mdukuzi, kuharibu kompyuta za wengine, na kujivuna","Kuelewa kisayansi mfumo wa mantiki baridi (kanuni) ulio nyuma ya chombo cha kichawi cha teknolojia, kulinda kikamilifu pochi yako mwenyewe na afya ya ubongo wako kutoka taarifa za uongo na mitego ya uraibu iliyowekwa, kutumia hekima kwa ajili ya wote, na, kwa mkono wako mwenyewe, kubuni na kuumba 'dunia iliyosambaa yenye upole na imara' ambapo kila mtu anaweza kuishi huru na kwa kujitegemea bila kudanganywa","Kukusanya bila kikomo alama za uzoefu za michezo ya mtandaoni na kumaliza maisha bila kupiga hatua moja nje ya nyumba","Kujivuna rekodi ya nambari za majibu yote sahihi na kuamuru wengine watii"],
    answerIndex:1,
    explanation:"Ya ajabu! Kwa hili, maswali 30 ya Kifurushi cha 4 yamemalizika kikamilifu. Kompyuta na intaneti si michezo au vifaa vya kuchezea vya kuua muda tu. Ni msitu tata zaidi wa enzi ya kisasa, uliowekwa kwa wingi mitego ya kutisha ya kunyonya bila kikomo muda, pesa, na haki za binadamu za taarifa binafsi kutoka 'watu wasio na maarifa' wasiojua jinsi ya kuvitumia, na kuwatawala kama watumwa. Lakini sasa ukiwa umepata katika kifurushi hiki dira ya taarifa ya kisasa zaidi ya 'algoriti, usimbaji, mantiki ya kusambaa, uthibitisho wa ukweli', hautawahi tena ubongo wako kudukuliwa na walaghai na mitego ya AI inayovizia nyuma ya skrini. Badala ya kuwa 'mtumwa wa upande unaotumiwa' wa teknolojia, mudu kabisa kiini cha mfumo na uwe 'bwana wa upande unaotumia (mbunifu)' anayefanya dunia kuwa bora. Na kwa kutumia programu za ajabu na mwanga wa taarifa sahihi unazoumba, unganisha wenzako wa dunia nzima katika mazingira magumu, na uache kwa wakati ujao wa wanadamu eneo la kiuchumi la kujitegemea lenye upole, na mfumo wa ustawi, usiosalimu amri kwa udhibiti wa kati. Dunia nzima inasherehekea kutoka moyoni na kushangilia mafanikio ya akili ya kidijitali isiyoshindika iliyowashwa katika ubongo wako!" },
  { id:121, topic:"Bayanuwai wa viumbe", emoji:"🦋",
    question:"Ni sababu gani kuu ya kisayansi inayotuzuia kuangamiza aina nyingi za viumbe hai wa misituni na baharini (bayanuwai wa viumbe) kwa ajili ya manufaa ya binadamu tu?",
    choices:["Kwa sababu aina za viumbe zikipungua, kurasa za vitabu vya picha hupungua na kuwa za kuhuzunisha","Kwa sababu maumbile ni 'mfumo-ikolojia' mmoja ambamo viumbe vyote hutegemeana kama wavu tata, na hata kipande kimoja kikipotea kila kitu huporomoka kama domino hadi binadamu pia hawawezi kuishi","Kwa sababu viumbe vikiangamia hugeuka vumbi la angani siku inayofuata","Hakuna sababu halisi; ni kanuni tu ya kulinda wanyama"],
    answerIndex:1,
    explanation:"Viumbe vyote hai duniani vimeunganishwa kama magurudumu sahihi ya saa: si kwa nani anakula nani (msururu wa chakula) tu, bali pia kwa kuwa mimea hutengeneza oksijeni, wadudu hubeba chavua, na bakteria hurejesha taka kwenye udongo. Hili huitwa 'mfumo-ikolojia'. Iwapo uwindaji wa kupita kiasi au maendeleo ya ubinafsi yataangamiza kiumbe fulani, mamia ya maisha mengine yaliyokitegemea hufa kwa pamoja, na mwishowe hata maji ya kunywa, chakula, na hewa ya binadamu huharibiwa, hivyo binadamu hujiangamiza wenyewe. Kulinda bayanuwai ni wajibu wa lazima ili mfumo wa kudumisha uhai wa Dunia ufanye kazi vizuri." },
  { id:122, topic:"Joto la dunia", emoji:"🌡️",
    question:"Hewa iliyozunguka Dunia hunasa joto la Jua kwa kiasi kinachofaa, kama chumba, na kuhifadhi joto ambalo viumbe wanaweza kuishi (athari ya chafu). Ni hatari gani iliyofichwa nyuma ya mfumo huu wa ajabu?",
    choices:["Kwamba hewa ikipata joto kupita kiasi, Dunia hugeuka umbo la mraba","Kwamba tukichoma makaa ya mawe na mafuta kupita kiasi na 'kaboni dioksidi' hewani ikaongezeka mno, kizuizi kinachonasa joto huwa kinene mno na halijoto ya Dunia nzima hupanda kwa njia isiyo ya kawaida (joto la dunia)","Kwamba hewa ikiwa moto, namba kwenye noti hupotea zenyewe","Hakuna hatari yoyote; kadiri joto linavyoongezeka ndivyo daima salama zaidi"],
    answerIndex:1,
    explanation:"Dunia hubaki kwenye halijoto ambayo viumbe wanaweza kuishi badala ya kuganda, kwa sababu gesi za chafu kama kaboni dioksidi hewani hufanya kazi kama blanketi. Lakini kwa kuwa binadamu waliendelea kuchoma kiasi kikubwa cha mafuta ya kisukuku kwa ajili ya viwanda, blanketi hii imekuwa nene kinyume na maumbile, na joto la Dunia nzima haliwezi tena kutoroka angani. Hili ndilo 'joto la dunia'. Kupanda kwa nyuzi chache tu kunayeyusha barafu nene inayofunika nchi kavu ya Antaktika na Greenland, ikatiririka baharini, na maji ya bahari yenyewe hupata joto na kutanuka, hivyo usawa wa bahari hupanda; visiwa na miji mingi duniani huzama, ukame mkali na vimbunga vikubwa huwa rahisi zaidi kutokea, na binadamu wote hukabili hatari ya njaa. Tunahitaji hekima ya kulinda usawa wa hewa." },
  { id:123, topic:"Mafuta ya kisukuku", emoji:"⛽",
    question:"Ni udhaifu gani mkubwa zaidi, kama rasilimali ya Dunia, wa mafuta ya kisukuku kama 'makaa ya mawe' na 'mafuta' ambayo binadamu wameyatumia tangu zamani?",
    choices:["Kwamba hata yakichomwa hayatoi mwanga hata kidogo na kila kitu hubaki giza","Kwamba, kwa kuwa ni mabaki ya viumbe wa kale yaliyolundikana ardhini kwa mamia ya mamilioni ya miaka, binadamu wakiendelea kuyatumia 'siku moja hakika yataisha na kutoweka (rasilimali yenye kikomo)'","Kwamba ni mazito mno kiasi kwamba hayawezi kubebwa kwa meli au gari","Kwamba kutumia mafuta ya kisukuku hubadilisha maji yote kuwa juisi"],
    answerIndex:1,
    explanation:"Hii ni kanuni muhimu kuhusu mabadiliko ya nishati (mpito wa nishati). Mafuta ya kisukuku kama mafuta na makaa ya mawe ni makopo ya nishati ambayo Dunia iliyahifadhi kimuujiza kwa mamia ya mamilioni ya miaka, muda mrefu usiowazika. Lakini yakishatumiwa na kuchomwa hayarudi kamwe. Tukiendelea kuyatumia kwa kasi ya kutisha ya binadamu wa sasa, siku moja kiasi kinachoweza kuchimbwa kitaisha, na jamii iliyoyategemea kabisa itatumbukia katika fujo kubwa. Ndiyo maana hekima ya mabadiliko makubwa kuelekea 'nishati mbadala' inayozalishwa tena na tena kwa nguvu ya maumbile - mwanga wa Jua, upepo, nguvu ya maji - ni ya lazima kabisa kwa kuendelea kuishi kwa binadamu wote siku zijazo." },
  { id:124, topic:"Mgodi wa mjini", emoji:"♻️",
    question:"Badala ya kuzika kama taka mashine zilizovunjika, makopo ya chuma, na plastiki za nyumbani, tunaziyeyusha vizuri na kuzitumia tena mara nyingi kama 'rasilimali mpya'. Ni thamani gani halisi ya urejelezaji huu kwa kulinda Dunia?",
    choices:["Kwa sababu urejelezaji hufanya pipa la taka lionekane zuri zaidi","Kwa sababu hatuhitaji tena kuchimba zaidi milima na misitu mizuri ya Dunia na kuharibu maumbile (hatari ya uchimbaji) kwa kutafuta madini na malighafi mpya (mgodi wa mjini)","Kwa sababu kuyeyusha taka hufanya vipande vya dhahabu viruke nje vyenyewe","Kwa sababu urejelezaji ni mchezo tu wa kuongeza idadi ya noti"],
    answerIndex:1,
    explanation:"Rasilimali za madini za Dunia kama chuma, shaba, na madini adimu pia zote zina kikomo. Ili kupata mpya, binadamu hata sasa huharibu misitu ya asili yenye thamani ya Dunia kwa malori ya kubeba taka na kuchimba mashimo marefu, wakizirarua maumbile vipande vipande. Lakini tukikusanya vifaa tulivyotumia badala ya kuvitupa na kuvirejeleza, taka iliyoko tayari mijini huzaliwa upya kama rasilimali mpya bora. Hili huitwa 'mgodi wa mjini'. Ni hekima ya kudhibiti malighafi kwa ustadi ili kujenga jamii endelevu inayozungusha utajiri tulionao na kuufanya udumu, bila kuijeruhi Dunia zaidi." },
  { id:125, topic:"Rasilimali za maji", emoji:"💧",
    question:"Dunia huitwa 'sayari ya maji' kwa kuwa imefunikwa na maji mengi sana, lakini 'maji baridi' ambayo sisi binadamu tunaweza kunywa ni karibu asilimia ngapi tu ya maji yote ya Dunia?",
    choices:["Karibu 90% ya yote ni maji baridi matamu","Karibu 97.5% ya maji ya Dunia ni maji ya bahari ya chumvi, na maji baridi yanayopatikana kwa urahisi katika mito na maziwa ambayo binadamu wanaweza kuyatumia ni karibu '0.01% tu ya yote'","Maji hayana mwisho, hivyo asilimia haiwezi kuhesabiwa","Maji yote ya Dunia ni maji baridi"],
    answerIndex:1,
    explanation:"Hii ni ukweli baridi na mgumu (data) kuhusu rasilimali za maji. Maji ya bluu mazuri ya Dunia yanayoonekana kutoka angani mengi yake (karibu 97.5%) ni 'maji ya bahari ya chumvi' ambayo yakinywewa moja kwa moja yangekusababishia upungufu wa maji mwilini. Hata maji baridi machache yaliyobaki yamegandishwa karibu yote kama barafu kwenye Ncha ya Kaskazini, Ncha ya Kusini, na milima mirefu, hivyo maji laini ambayo sisi binadamu tunaweza kuyatumia mara moja kutoka mito na maziwa ni kiasi kidogo cha kimuujiza: 'karibu 0.01% ya maji yote ya Dunia'. Watu wachache kuhodhi, kuchafua, au kupoteza ovyo maji haya baridi ya thamani kuliko yote ni kukata kamba ya uokoaji ya kila mtu kwa mikono yao wenyewe. Na tuzingatie kwa dhati hekima ya kushirikiana maji na kuyaweka safi." },
  { id:126, topic:"Plastiki ndogo", emoji:"🧴",
    question:"Taka za plastiki zikitupwa baharini au mtoni, mwanga wa Jua na mawimbi huzivunja vipande vidogo viitwavyo 'plastiki ndogo'. Kwa nini hii hurudi kudhuru mwili wa binadamu?",
    choices:["Kwa sababu plastiki ndogo zikiingia machoni, kuona kwako kunaboreka ghafla","Kwa sababu plankton na samaki wa baharini hula vipande vidogo vya plastiki visivyotoweka kamwe, na mwishowe 'binadamu akila samaki hao, sumu yenye madhara hurundikana viungoni mwake na kumfanya awe mgonjwa' (mkusanyiko wa kibiolojia)","Kwa sababu kula plastiki hugeuza mwili wako kuwa roboti","Kwa sababu maji yote huganda na kugeuka barafu"],
    answerIndex:1,
    explanation:"Plastiki ni dutu iliyotengenezwa na kemia ya binadamu yenye sifa ya pekee kwamba 'nguvu ya maumbile karibu haiwezi kuivunja, wala hairudi kwenye udongo'. Taka iliyotiririka baharini inaweza kuonekana imevunjika vipande vidogo na kutoweka, lakini huendelea kuelea baharini kwa muda mrefu sana kama 'plastiki ndogo' chini ya milimita 5. Cha kutisha zaidi, vipande hivi vidogo vina sifa ya kuvuta kwenye uso wake kama sumaku kemikali zenye madhara (sumu) za baharini na kuzilundika. Samaki mdogo huzila, samaki mkubwa humla mdogo, na mwishowe 'binadamu' aliye juu ya msururu wa chakula humla, hivyo donge la sumu hurundikana kama bumerangi mwilini mwa watoto wetu wenyewe (mkusanyiko wa kibiolojia). Duniani kila kitu kimeunganishwa." },
  { id:127, topic:"Msitu wa mvua", emoji:"🌳",
    question:"Kwa nini misitu mikubwa kama msitu wa mvua wa Amerika Kusini (Amazoni), iitwayo 'mapafu ya Dunia', hulindwa kwa uangalifu mkubwa duniani kote?",
    choices:["Kwa sababu umbo la msitu linafanana kabisa na kiungo halisi cha pafu la binadamu","Kwa sababu huvuta kiasi kikubwa cha kaboni dioksidi inayoipasha Dunia joto kupita kiasi na kuihifadhi mwilini mwa miti (ghala la kaboni), hutoa mvuke mwingi wa maji kudhibiti mvua na hali ya hewa ya dunia, na ni hazina ya uhai ambapo viumbe wengi sana wa Dunia huishi","Kwa sababu wageni wa angani wamficha kituo cha siri ndani ya msitu","Kwa sababu kukata miti mingi hufanya ardhi iwe nyepesi na kuirusha Dunia angani"],
    answerIndex:1,
    explanation:"Misitu ya mvua kama Amazoni kwa muda mrefu imeitwa kwa jina la upendo 'mapafu ya Dunia'. Hata hivyo, jukumu lake muhimu zaidi kabisa kwa kweli si kutengeneza oksijeni. Mimea ya msituni hutengeneza oksijeni kwa usanisinuru, lakini viumbe na vijidudu vya msitu wenyewe hutumia karibu kiasi kile kile kwa kupumua, hivyo imebainika kwamba kiasi halisi cha oksijeni kinachotumwa hewani kiko karibu na sufuri (oksijeni nyingi tunazovuta zilitengenezwa na plankton ndogo za mimea baharini kwa muda mrefu). Basi kwa nini msitu wa mvua ni muhimu hivyo? Kwa sababu ni 'ghala la kaboni' linalovuta kiasi kikubwa cha kaboni dioksidi inayoipasha Dunia joto kupita kiasi na kuihifadhi mwilini mwa miti, ni 'kiyoyozi kikubwa cha Dunia' kinachotoa mvuke mwingi wa maji kudhibiti mvua na hali ya hewa ya dunia, na ni 'hazina ya uhai' ambapo aina nyingi sana za viumbe huishi. Tukikata msitu huu kwa ajili ya pesa za muda mfupi, kaboni iliyohifadhiwa hufurika hewani, joto huongezeka kwa kasi, na hali ya hewa ya dunia na maisha mengi huvunjika. Uharibifu wa maumbile katika eneo moja, ukizunguka, huvuruga hali ya hewa hata kwako wewe uishie nchi ya mbali. Tuwe na mtazamo wa kidunia unaolinda Dunia nzima kama mfumo mmoja." },
  { id:128, topic:"Haki za binadamu", emoji:"🗽",
    question:"Ni haki gani kamili anayoimiliki kila binadamu duniani - bila kujali nchi alikozaliwa, rangi ya ngozi yake, lugha yake, au kama ni mvulana au msichana - ya kuishi kama binadamu, kwa upole na usalama?",
    choices:["Haki ya kwenda kununua","Haki za msingi za binadamu (haki za binadamu)","Haki ya kuamuru wengine na kuwafanya watii","Haki ya kucheza michezo saa 24 mfululizo"],
    answerIndex:1,
    explanation:"Msingi mkuu zaidi wa hekima ya kijamii ni 'haki za msingi za binadamu'. Katika dunia ya zamani sana, ilikuwa jambo la kawaida kwa wafalme wenye nguvu na wenye silaha kunyakua maisha na uhuru wa wanyonge kama watumwa. Binadamu walijifunza kutokana na vita na mateso yasiyohesabika ya kuhuzunisha, na mwaka 1948 Umoja wa Mataifa ulipitisha 'Tamko la Kimataifa la Haki za Binadamu'. Ni ahadi kuu zaidi ya upole ya binadamu: 'Binadamu wote ni sawa tangu kuzaliwa, na uhuru wa yeyote, maisha ya yeyote, haviwezi kujeruhiwa kwa dhuluma na mtu mwingine.' Kujua haki za binadamu huwa nguvu kuu zaidi ya kujilinda na kulinda heshima ya wengine." },
  { id:129, topic:"Elimu ya wasichana", emoji:"👧",
    question:"Kwa nini kulinda haki ya wasichana (wanawake) ya kwenda shule na kupata 'elimu (masomo)' kama wavulana hufanya jamii nzima kuwa tajiri zaidi sana?",
    choices:["Kwa sababu wasichana wakisoma, idadi ya maua yanayochanua huongezeka mara mbili","Kwa sababu wanawake, ambao ni nusu ya idadi ya watu, wakiwa na maarifa sahihi ya sayansi, tiba, na uchumi, vifo vya watoto kutokana na magonjwa hupungua sana, na nguvu ya kuzalisha kazi mpya na hekima yenye manufaa huongezeka mara mbili","Kwa sababu wasichana huhesabu vizuri zaidi namba kwenye noti","Hakuna sababu halisi; ni kanuni ya kuonyesha tu"],
    answerIndex:1,
    explanation:"Katika baadhi ya maeneo ya dunia, hata sasa wasichana hunyimwa elimu kwa upendeleo potofu kwamba 'msichana hahitaji kwenda shule, afanye kazi nyumbani'. Lakini utafiti na data za maendeleo huonyesha kwamba kadiri nchi inavyosonga mbele elimu ya wanawake (usawa wa kijinsia), ndivyo inavyotoka haraka kwenye umaskini na kuendelea. Mama akiwa na maarifa ya usafi na tiba, anaweza kumlinda mtoto mchanga dhidi ya magonjwa; wanawake wakiwa na hekima ya biashara, miduara mipya ya uchumi yenye upole huzaliwa bila kukoma. Kufunga uwezekano wa mtu kwa jinsia yake kwa kweli ni breki kwa maendeleo ya jamii nzima." },
  { id:130, topic:"Ajira ya watoto", emoji:"⛏️",
    question:"Katika baadhi ya maeneo maskini ya dunia, watoto wadogo hawawezi kwenda shule na hulazimishwa kufanya kazi mchana kutwa kwenye migodi na mashamba hatari - hii ni 'ajira ya watoto'. Ni sababu gani halisi inayoifanya isisameheke kabisa?",
    choices:["Kwa sababu watoto wakifanya kazi, watu wazima hukosa ajira na kuingia matatizoni","Kwa sababu 'nafasi ya kujifunza (elimu)' muhimu zaidi inaponyakuliwa utotoni, hata wakiwa watu wazima hawaelewi herufi, hesabu, wala hekima ya sayansi, na hawawezi kamwe kutoka katika 'mzunguko hasi' wa kudanganywa na watu wabaya na kunyonywa katika umaskini maisha yote","Kwa sababu watoto wakitengeneza vitu, maumbo ya zana yote huwa duara","Kwa sababu sheria inasema watoto wanaweza kucheza nje tu"],
    answerIndex:1,
    explanation:"Hofu halisi ya ajira ya watoto si uchovu wa mwili wa papo hapo tu. Uhalifu mbaya zaidi ni kwamba huunyakua kwa mizizi uwezekano wa baadaye wa mtoto huyo (mbawa za hekima) na kupitisha minyororo ya umaskini hadi kizazi kijacho pia. Mtoto asiyeweza kusoma herufi wala kuhesabu, akiwa mtu mzima hulazimishwa kutia saini mikataba isiyo ya haki, hapati mshahara wa haki, na hulazimishwa kufanya kazi kwa faida ya wengine maisha yote, kama mtumwa. Elimu ndiyo chombo chenye nguvu zaidi cha kukata minyororo hii ya kuhuzunisha ya umaskini. Kulinda haki ya watoto duniani kote ya kujifunza kunahusiana moja kwa moja na kufuta mifumo isiyo ya haki kama hiyo." },
  { id:131, topic:"Vita na amani", emoji:"🕊️",
    question:"Nchi na nchi, au mtu na mtu, wanapokabiliana na tofauti za maoni au ugombea wa rasilimali, ni sababu gani kuu ya kutatua kwa mazungumzo (diplomasia) badala ya chaguo baya zaidi, 'vita (vurugu)'?",
    choices:["Kwa sababu vita huchafua nguo na kufanya kufua kuwe kugumu","Kwa sababu kushinda au kushindwa kwa vurugu hakuthibitishi hata kidogo 'upande gani uko sahihi'; huzaa tu matokeo ya kuhuzunisha ya 'upande gani unaweza kuharibu maisha mengi zaidi yasiyo na hatia', chaguo la kipumbavu ambamo kila mtu hupata hasara kubwa","Kwa sababu kupiga kelele ni rahisi zaidi wakati wa mazungumzo","Kwa sababu vita hupunguza ukubwa wa Dunia kwa nusu chenyewe"],
    answerIndex:1,
    explanation:"Asili ya vita (vurugu) ni kushindwa kabisa kwa mantiki. Hata wakishambuliana kwa silaha za kisasa kiasi gani, tatizo la asili (uhaba wa maji au mpaka wa ardhi) halitatuliwi hata kidogo. Kinachobaki baadaye ni kifo cha watu wasiohesabika, miji iliyobomolewa, na deni baya zaidi: 'mnyororo wa chuki' mkali usiofifia kwa vizazi. Binadamu wana maneno na hekima ili kupima hali na faida na hasara za kila upande, na kubuni kwa akili 'kanuni ya kugawana (diplomasia)' ambayo pande zote mbili zinaweza kuikubali. Uvumilivu wa kuendelea na mazungumzo bila kukata tamaa ndiyo hekima ya wenye nguvu kwa kweli." },
  { id:132, topic:"Wakimbizi", emoji:"🧳",
    question:"Watu waliopoteza makazi yao na kukimbia kwa shida hadi nchi nyingine salama kwa sababu nchi yao ya kuzaliwa iliingizwa vitani au ikapigwa na maafa makubwa huitwaje?",
    choices:["Watalii","Wakimbizi (watu waliohamishwa)","Kundi la wezi","Wageni wa angani"],
    answerIndex:1,
    explanation:"Watu waliofukuzwa makwao, 'wakimbizi', hawakuja nchi nyingine kwa kupenda hata kidogo. Hadi jana, kama wewe, walikuwa binadamu wa kawaida waliokula nyumbani, kwenda shule, na kuishi kwa utulivu wakitabasamu. Kwa vurugu au maafa ya ghafla, kwa papo hapo mali zao zote na amani vilinyakuliwa, na hawakuwa na njia nyingine isipokuwa kukimbia ili waishi. Jamii inayofunga mipaka yake, kuwakataa, na kuwaacha ni dunia baridi inayovunja kwa mikono yake ahadi ya haki za binadamu. Hekima ya huruma - kufikiria maumivu ya mwingine kama yako na, wakati wa shida, kutoa kwa upole hifadhi kwa roho ya 'leo wewe, kesho mimi' - huwa mstari imara wa ulinzi wa amani ya dunia." },
  { id:133, topic:"Kutokutumia nguvu", emoji:"☮️",
    question:"Kwa nini njia ya mapambano iitwayo 'kutokutumia nguvu' - ambayo viongozi wakuu wa zamani (kama Mahatma Gandhi) walipinga watawala dhalimu bila kushika silaha - ilikuwa na nguvu zaidi sana kuliko kutumia vurugu?",
    choices:["Kwa sababu kuokoa pesa ya kununua silaha kuliwawezesha kununua peremende nyingi tamu","Kwa sababu kwa kutotumia wenyewe vurugu, walithibitisha waziwazi, mbele ya macho ya watu wa dunia nzima, ukatili dhalimu wa mtawala na 'haki ya dai lao la haki za binadamu', na kuvuta washirika wasiohesabika","Kwa sababu kutangaza kutokutumia nguvu hufanya mwili kuwa mgumu kama chuma","Kwa sababu walijificha tu pembeni ya chumba ili wasipigwe"],
    answerIndex:1,
    explanation:"Unapokabiliana na vurugu kwa vurugu, kwa wanaotazama hili huonekana tu kama 'ugomvi kati ya watu wabaya', na tatizo halisi hufichwa. Lakini kadiri walivyopigwa, kadiri walivyokamatwa kwa dhuluma, tendo la kutokutumia nguvu (kutotii kwa raia) - kusimama imara kimya, bila kushika silaha kamwe, wakisema 'tunadai tu haki zetu halali kama binadamu' - huingiza moja kwa moja moyoni mwa watu wa dunia nzima ukweli kwamba 'mtawala anayeshambulia ndiye aliye na makosa'. Nguvu hii ya haki husisimua mioyo kwa nguvu kuliko mzinga wowote, na hatimaye huwa wimbi kubwa la imani linalosisimua mataifa, hadi mwishowe hubadilisha mfumo wenyewe wa utawala dhalimu." },
  { id:134, topic:"Matatizo ya kuvuka mipaka", emoji:"🌍",
    question:"Kwa nini matatizo kama mabadiliko ya tabianchi yanayotokea katika Dunia nzima, au magonjwa ya virusi yanayoenea duniani (mlipuko wa janga), hayawezi kutatuliwa na nchi moja tu kuchukua hatua?",
    choices:["Kwa sababu kwa nchi moja tu, viti vinabaki kwenye chumba cha mkutano na huleta huzuni","Kwa sababu kwa hewa ya maumbile, mawimbi ya bahari, na virusi visivyoonekana, mstari uliochorwa na binadamu uitwao 'mpaka (mpaka kati ya nchi)' haufanyi kazi hata kidogo, na Dunia nzima imeunganishwa kama chumba kimoja","Kwa sababu nchi ikiwa ndogo, maumbo ya dawa zote huwa duara","Kwa sababu nchi nyingine hukasirika na kuja kuvuruga hatua"],
    answerIndex:1,
    explanation:"Hii ni hali halisi ya kimaumbile ya Dunia. Kadiri binadamu wanavyochora mistari ramanini wakisema 'kuanzia hapa ni nchi yetu', hewa iliyochafuliwa mahali fulani huchanganyika na anga la dunia nzima, na virusi vinavyotokea nchi nyingine hupanda ndege na kutiririka mjini kwako kwa papo hapo. Matatizo ya mazingira na magonjwa ya kuambukiza hayawezi kuzuiwa kabisa hata nchi moja ikitumia pesa kujenga kizuizi. Ni mfumo wa 'ushirikiano wa kiwango cha kidunia (utawala wa kidunia)' tu - ambamo nchi zote za Dunia huweka pembeni maslahi yao ya ubinafsi (ubinafsi), hushirikiana data ileile, na huungana nguvu wakishika ahadi zilezile (mikataba ya kimataifa) - ndiyo njia ya kuokoa binadamu kutoka kwenye janga kubwa." },
  { id:135, topic:"Bayanuwai wa utamaduni", emoji:"🗿",
    question:"Ni hasara gani kubwa kwa binadamu wote pale lugha na tamaduni za kipekee (bayanuwai) ambazo watu wa kiasili na walio wachache wa kila ardhi wameziilinda kwa maelfu ya miaka zinapotoweka?",
    choices:["Kwamba hatuwezi tena kuona mavazi ya kupendeza ya sikukuu, jambo la kuchosha","Kwa sababu maarifa ya thamani ya binadamu ambayo sayansi ya kisasa bado haijayajua - 'hekima ya mimea inayokuwa dawa' na 'ujuzi wa kuangalia maumbile ili kunusurika majanga ya tabianchi' kwa ajili ya kuishi katika ardhi hiyo - hupotea milele","Kwa sababu lugha zikipungua, kamusi huwa ndogo na rahisi","Hakuna hasara yoyote; ni rahisi zaidi kuunganisha tamaduni zote za dunia kuwa moja"],
    answerIndex:1,
    explanation:"Tamaduni na lugha mbalimbali za dunia si burudani tu wala tofauti za sura. Ni 'mkusanyiko wa maarifa ya kunusurika yaliyosafishwa zaidi' ambao kila kabila lilijenga kwa kuangalia kwa kina maumbile ili kudumisha uhai kwa mamia ya vizazi katika ardhi yao ngumu (msitu mnene, jangwa, maeneo ya baridi kali). Kidokezo cha dawa ambayo tiba ya kisasa bado haijaipata mara nyingi kwa kweli hulala katika hekima ya mimea ya dawa iliyorithishwa na watu wa kiasili wa msitu mnene. Kukanyaga hili kama 'kitu cha zamani na kilichopitwa na wakati' na kukifuta ni upotevu sawa na kurarua na kutupa kwa mikono yako 'karata ya ushindi' ya thamani ambayo binadamu wangeweza kuitumia kutatua majanga ya baadaye." },
  { id:136, topic:"Biashara ya haki", emoji:"🍫",
    question:"Jaribio la ununuzi. Unaponunua chokoleti au kahawa dukani, ni 'giza la uchumi (dhuluma)' gani linaloweza kufichwa nyuma ya bidhaa ambayo bei yake ni rahisi mno?",
    choices:["Kwamba bidhaa rahisi haina chokoleti halisi ndani yake","Kwamba inaweza kuwa fuwele ya machozi, iliyotengenezwa na wakulima wa nchi maskini za mbali wanaolazimishwa kufanya kazi kwa dhuluma kwa pesa ndogo mno na makampuni makubwa, na watoto wasioweza kwenda shule na kulazimishwa kufanya kazi (unyonyaji)","Kwamba kula peremende rahisi huongeza uzito wako mara tatu ghafla","Kwamba bei ikiwa rahisi, rangi ya noti hubadilika kuwa rangi ya ukungu"],
    answerIndex:1,
    explanation:"Nyuma ya ununuzi ambamo tunafurahia 'aha, rahisi na faida!', kuna hali halisi ambamo watoto wa rika lako wanaoishi upande wa pili wa Dunia hulazimishwa kuvuna mbegu za kakao mchana kutwa wakitoka jasho, na kuteseka karibu bila mshahara. Mfumo unaonyonya kwa dhuluma faida kutoka kwa watu walio katika hali dhaifu kama hivi huitwa 'unyonyaji'. Ili usishiriki katika hili, kuwa na hekima ya kuchagua kwa busara bidhaa za 'biashara ya haki' ambazo shirika maalum limezithibitisha kwamba pesa ya haki imelipwa ipasavyo kwa waliozitengeneza. Jinsi unavyotumia pesa yako huwa kura inayoifanya dunia kuwa bora." },
  { id:137, topic:"Janga la rasilimali za pamoja", emoji:"🐑",
    question:"Kwenye malisho ya pamoja ya kijiji yanayotumiwa na wote, kila mtu alipuuza kanuni na kuchunga kondoo wengi mno akisema 'nataka kupata faida mimi tu', na matokeo yake nyasi zilililiwa zote na kondoo wa kila mtu wakaona njaa. Mtego huu maarufu wa uchumi huitwaje?",
    choices:["Ushindi wa kubadilishana bidhaa","Janga la rasilimali za pamoja (janga la ardhi ya pamoja)","Mlipuko wa uzalishaji","Ukamilishaji wa mfumuko wa bei"],
    answerIndex:1,
    explanation:"Mali bora inayoshirikiwa na kutumiwa na wote - kama maji ya mto, samaki wa baharini, na hewa ya Dunia - huitwa 'rasilimali za pamoja (commons)'. Kila mtu anapotenda kwa hamu ya 'kuongeza faida yangu mwenyewe', rasilimali huisha kwa kasi inayozidi kasi yake ya kujirejesha, na mwishowe wote huporomoka pamoja. Hili huitwa 'janga la rasilimali za pamoja'. Ili kuzuia janga hili, badala ya kumwacha dikteta mwenye nguvu ahodhi rasilimali, haiwezekani kufanya bila hekima ya kijamii ambapo wote, kwa usawa, hutunga kanuni imara (mkataba) - 'hatutatumia zaidi ya hii, hatutaichafua' - na kuiendesha huku wakichungana." },
  { id:138, topic:"Mzunguko wa mazao", emoji:"🌾",
    question:"Shambani, ukipanda kila mwaka katika ardhi ileile mmea wa aina ileile kabisa (kama ngano) bila kuipumzisha (kilimo cha mmea mmoja, kupanda mfululizo), kwa nini hushindwa vibaya baada ya miaka michache, udongo ukikonda kiasi kwamba mazao hayaoti?",
    choices:["Kwa sababu kuona mmea uleule daima hufanya udongo wa ardhi uchoke na kulala","Kwa sababu virutubisho fulani tu (madini) vya udongo hufyonzwa kuisha, na magonjwa na wadudu fulani tu wanaoupenda mmea huo huongezeka kwa mlipuko, hadi udongo ukonde na kuishiwa nguvu (uharibifu wa kupanda mfululizo)","Kwa sababu mimea hujisikia upweke na yote hukimbia mahali fulani usiku","Kwa sababu halijoto ya udongo hupanda yenyewe hadi nyuzi 100 na kuwa hatari"],
    answerIndex:1,
    explanation:"Katika udongo wa maumbile makuu, vijidudu visivyohesabika visivyoonekana (bakteria na fangasi) huhifadhi usawa wa aina mbalimbali na kuutunza udongo kuwa laini na ulio na hewa. Lakini unapopanda kitu kimoja tu kwa manufaa ya binadamu kwa sababu 'ngano huleta pesa' (kilimo cha mmea mmoja), bayanuwai wa mfumo-ikolojia wa udongo huporomoka, na huwa mahali ambapo ukungu mbaya fulani na wadudu huongezeka kwa urahisi. Hili huitwa 'uharibifu wa kupanda mfululizo'. Watu wenye hekima wa zamani walibuni hekima ya 'mzunguko wa mazao' - kubadilisha kinachopandwa kila mwaka, kama maharagwe mwaka huu, viazi mwaka ujao, kisha nyasi za malisho - na kuupumzisha udongo kwa miaka kadhaa, na hivyo wakaihifadhi nguvu ya udongo kwa mamia ya miaka. Kuendana na mzunguko wa maumbile ndiyo hekima ya kudumu kwa muda mrefu." },
  { id:139, topic:"Mzunguko wa kaboni", emoji:"🔄",
    question:"Dutu iitwayo 'kaboni' duniani huzunguka bila kukoma kati ya miili ya viumbe, hewa, na bahari. Ni sababu gani halisi ya binadamu kuvuruga vibaya usawa wa mzunguko huu wa kaboni?",
    choices:["Kwa sababu binadamu hupumua kupita kiasi na kula oksijeni yote ya hewani","Kwa sababu makaa ya mawe na mafuta (madonge ya kaboni) ambayo Dunia ya kale iliyafunga ndani kabisa ya ardhi kwa mamia ya mamilioni ya miaka, yalichimbwa na kuchomwa kwa pamoja na binadamu kwa miaka mia chache tu, na kuyarudisha hewani","Kwa sababu magari mengi yakitembea, kaboni ya ardhini huruka angani","Kwa sababu mwanga wa Jua hubadilisha rangi ya kaboni kuwa nyeusi"],
    answerIndex:1,
    explanation:"Kiasi cha jumla cha kaboni duniani ni karibu kisichobadilika, lakini usawa wa 'iko wapi' ndiyo ufunguo wa uhai. Kaboni iliyo katika miti ya msituni na miili ya viumbe hurudi kwenye udongo wanapokufa, ikizunguka kwa usawa unaofaa. Lakini tatizo kubwa zaidi ni kwamba binadamu, baada ya Mapinduzi ya Viwanda, walifungua kwa pamoja kapsuli kubwa ya wakati ya kaboni - mafuta ya kisukuku (mabaki ya viumbe wa kale) ambayo Dunia iliyafunga kwa uangalifu ndani kabisa ya ardhi kwa mamia ya mamilioni ya miaka ili yasitoke kamwe juu ya uso - na kuyachoma. Kwa tendo hili, lililoshinda kabisa kasi ambayo maumbile yalikuwa yakiizungusha taratibu, kaboni dioksidi hewani iliongezeka ghafla na inasababisha joto la dunia. Sababu iliumbwa na ujinga na uchoyo wa binadamu." },
  { id:140, topic:"Kuokoa nishati", emoji:"🔌",
    question:"Ni maana gani muhimu zaidi, kwa Dunia nzima, ya kuzima mara kwa mara taa za chumba chako na kupunguza matumizi ya nishati ya bure (kuokoa nishati)?",
    choices:["Kwa sababu kuzima taa hufanya chumba kiwe giza na kufanya mizimu iwe rahisi zaidi kutokea","Kwa sababu umeme mwingi unaotumiwa duniani bado hutengenezwa kwa kuchoma mafuta ya kisukuku, hivyo kupunguza upotevu wa umeme hupunguza moja kwa moja gesi za joto na kusimamisha uharibifu wa maumbile","Kwa sababu kuokoa nishati huongeza ukubwa wa simu yako yenyewe","Kwa sababu nchi hukupa noti iliyoandikwa 'umefanya vizuri'"],
    answerIndex:1,
    explanation:"Umeme unaotiririka kutoka kwenye plagi haububujiki wenyewe kutoka mahali fulani. Nyuma yake, vituo vingi vya umeme wa joto hutengeneza umeme kwa kuchoma mafuta na makaa ya mawe ya thamani ya Dunia huku vikitoa moshi na kaboni dioksidi (zaidi ya nusu ya umeme wa dunia bado hutoka kwenye mafuta ya kisukuku kama hayo). Kwa maneno mengine, unapoacha taa za chumba zikiwaka, mahali fulani duniani rasilimali zinatumika na hewa inachafuliwa. Kila matumizi ya nishati yameunganishwa na kutoa kwenye rasilimali za Dunia nzima. Hekima makini ya kukata upotevu ni tendo jema ambalo kila mtu anaweza kufanya, likiongeza umri wa Dunia kidogo kidogo." },
  { id:141, topic:"Kutengeneza mboji", emoji:"🍂",
    question:"Badala ya kutupa kwenye taka za kuchomwa maganda ya mboga na mabaki ya chakula (taka za jikoni) yanayotoka kupika, unayachanganya na udongo na kuacha nguvu ya hewa na vijidudu iyaoze taratibu (kutengeneza mboji). Yanazaliwa upya kuwa nini?",
    choices:["Taka huyeyuka kuwa tope na kugeuka ndoo safi ya plastiki","Kwa nguvu ya vijidudu taka huoza kuwa virutubisho na kuzaliwa upya kama 'udongo bora laini ulio na hewa (mboji)' unaokuza kwa nguvu na afya mimea inayofuata na mboga tamu","Kuweka taka za chakula kwenye udongo hufanya noti zibubujike zenyewe","Taka hugeuka moja kwa moja donge la jiwe na kuwa msingi wa kujenga nyumba"],
    answerIndex:1,
    explanation:"Katika maumbile makuu, kwa asili hakuna kitu kiitwacho 'taka'. Majani yanayoanguka msituni na kinyesi cha wanyama vyote huwa chakula cha vijidudu visivyohesabika (bakteria na fangasi za uyoga) vya udongo, huoza baada ya muda, na kuzaliwa upya kama virutubisho (mboji) ili miti mipya iote majira ya kuchipua yanayofuata. Hekima ya kuleta mzunguko huu mkubwa wa maumbile usio na upotevu katika maisha ya binadamu huitwa 'kutengeneza mboji'. Kurudisha kwa uwajibikaji ulichokitoa kwenye mbegu ya uhai unaofuata ni upole wa msingi wa kutoifanya Dunia kuwa jaa la taka." },
  { id:142, topic:"Kutokomeza magonjwa", emoji:"🩺",
    question:"Zamani, ugonjwa wa kutisha wa virusi 'ndui' uliua maisha ya watu wengi (hasa watoto) duniani kote, na mwaka 1980 [ulifutwa kabisa kutoka ulimwengu wa asili wa Dunia (kutokomeza)]. Ni sababu gani ya mafanikio haya makuu katika historia ya binadamu?",
    choices:["Kwa sababu watu wote duniani walipoomba kwa sauti kubwa kila siku, virusi viliogopa na kukimbilia angani","Kwa sababu nchi za dunia nzima, madaktari, na Umoja wa Mataifa (WHO) waliungana nguvu wakivuka mipaka na kufikisha 'chanjo (kinga)' kwa kila mtu duniani bila ubaguzi, bila kuacha mahali pa virusi kukimbilia (ushindi wa ushirikiano wa binadamu)","Kwa sababu virusi vilichoshwa na ladha ya binadamu na kutoweka vyenyewe","Kwa sababu halijoto ya Dunia ilishuka ghafla na virusi vyote vikafa kwa baridi"],
    answerIndex:1,
    explanation:"Huu ni mmoja wa ushindi mkubwa zaidi katika historia ya binadamu, ulioletwa na hekima na ushirikiano. 'Ndui' ulikuwa ugonjwa wa kutisha sana uliofunika mwili mzima vipele na kuua kwa kiwango kikubwa watoto na watu wazima. Ili kumshinda adui huyu, binadamu walivuka mgogoro kati ya nchi (Vita Baridi) na kushirikiana, wakiendeleza kwa miaka operesheni ya kushangaza ya kufikisha chanjo kwa watu wa dunia nzima. Virusi, kwa kuwa wote ambao virusi vilijaribu kuhamia kwao walikuwa na 'ngao ya kinga', vilikosa mahali pa kuongezeka na hatimaye vikatoweka kabisa kutoka ulimwengu wa asili (hili huitwa 'kutokomeza'). Ni ushahidi imara kutoka historia kwamba binadamu wakishirikiana hekima kwa dhati na kuungana, wanaweza kuandika upya hata hatima inayoonekana isiyo na matumaini na kuokoa dunia." },
  { id:143, topic:"Uhuru wa kujieleza", emoji:"🗣️",
    question:"Kwa nini haki ambayo kwayo yeyote katika jamii anaweza kuchapisha kwa uhuru, kwa maneno na maandishi, maoni anayoyaona sahihi na mawazo ya kuiboresha jamii, bila kutishwa na yeyote (uhuru wa kujieleza), ni ya lazima kwa kulinda nchi?",
    choices:["Kwa sababu wote wakipiga kelele majina yao kwa sauti, mji huwa na shamrashamra na sherehe inaweza kufanyika","Kwa sababu uhuru huu usipokuwepo na maoni ya mtawala fulani mwenye nguvu tu ndiyo yanayoruhusiwa kusemwa, hakuna anayeweza kuweka breki kwa makosa makubwa ya jamii, na nchi nzima hukimbia bila kudhibitiwa","Kwa sababu kuandika kwa uhuru huongeza idadi ya kurasa za daftari bila kikomo","Kwa sababu kufanya kujieleza kuwe huru huongeza namba kwenye noti zenyewe"],
    answerIndex:1,
    explanation:"Kama tulivyojifunza pia kwenye pakiti ya habari, ili kuhifadhi usalama wa jamii nzima (ustahimilivu) kwa kiwango cha juu, haiwezekani kufanya bila breki (uhuru wa kujieleza) ambayo kwayo watu wanaweza kupaza sauti kusema 'amri au kanuni hiyo ni ya ajabu, ni hatari'. Jamii ikijaa watu ambao kwa hofu hawawezi kusema ukweli kwa mtawala mwenye nguvu na wanaoweza kukubaliana hata na uongo, basi kiongozi anaposhinikiza kitufe cha vita visivyo sahihi au uharibifu wa mazingira, hakuna anayeweza kumzuia na raia wote huburuzwa ndani. Mfumo wa kidemokrasia ambamo watu mbalimbali hubadilishana maoni kwa uhuru na usawa na kuweza kurekebisha makosa kila wakati ndiyo hasa hekima inayoifanya jamii kuwa salama zaidi na ya kudumu zaidi." },
  { id:144, topic:"Mji unaohimili maafa", emoji:"🏙️",
    question:"Ili kujenga 'mji imara dhidi ya maafa (mji wa kuzuia maafa)' ambapo watu wanaweza kuishi kwa usalama kwa muda mrefu bila kujeruhiwa, hata katika ardhi ngumu ambapo matetemeko makubwa na mafuriko makubwa hutokea kwa urahisi, ni hekima gani ya usanifu iliyo muhimu zaidi?",
    choices:["Kufunika kuta zote za majengo kwa vipande vya dhahabu ili vionekane kama jumba la kifahari zaidi","Kujifunza vizuri kumbukumbu za maafa makubwa ya zamani (data ya kihistoria), na kusanifu mapema 'muundo wa jengo unaonyumbulika (kutenganisha mitetemo)' unaopitisha nishati ya kutisha ya maumbile, na mifereji ambapo maji hutoka kwa usalama (wazo la kupunguza maafa)","Kupanda kila siku maua mengi mazuri kuzunguka nyumba ili maafa yasije","Kujishawishi kwamba tutakuwa salama hata kitu chochote kikitokea na kutochukua hatua yoyote"],
    answerIndex:1,
    explanation:"Mbele ya nguvu kubwa ya uharibifu ya maumbile, usanifu unaojenga tu kuta ngumu na imara na kujaribu kuikabili moja kwa moja kwa nguvu, siku moja utavunjwa vipande kwa papo hapo na nishati ya maumbile inayouzidi, ukasababisha ajali kubwa. Hekima halisi ya kusimamia majanga ni kutumia data ya maafa ya mamia ya miaka kama kitabu cha kiada na kujenga mapema, katika mji mzima, mifumo ya 'kupunguza maafa' na 'kutenganisha mitetemo' inayo 'pitisha kwa ustadi nguvu ya maumbile (mvuto na mtiririko wa maji)'. Werevu wa kusanifu mifumo inayofanya sheria za maumbile kuwa mshirika wako, badala ya kwenda kinyume nazo, hulinda maisha ya familia yako mpendwa kwa vizazi." },
  { id:145, topic:"Mbinu ya kisayansi", emoji:"🔬",
    question:"Unapokutana na tukio la ajabu, au ugonjwa ambao hujawahi kuona, huitwaje 'njia ya kutumia akili' ambayo kwayo unaacha kuamini kwa upofu kwamba 'mtu fulani muhimu alisema hivyo' au 'ni hekaya ya zamani', na badala yake unaangalia na kufanya majaribio mwenyewe ili kubaini ukweli wa hakika?",
    choices:["Fikra za kichawi","Njia ya kufikiri ya kisayansi (mbinu ya kisayansi, fikra makini)","Dhana ya kujipendekeza tu","Kufutwa kwa nenosiri kiotomatiki"],
    answerIndex:1,
    explanation:"Njia yenye nguvu zaidi ya kutumia akili, iliyookoa binadamu kutoka hofu ya giza na ushirikina na kuendeleza tiba na teknolojia yenye manufaa kiasi hiki, ni 'mbinu ya kisayansi'. Ni njia ya kufikiri (fikra makini) ambamo, badala ya kusombwa na maneno ya hisia au uvumi wa mtu, unasimama mara moja kwa akili yako mwenyewe ukiuliza 'je, ni kweli? nikijaribu, naweza kurudia matokeo yaleyale mara nyingi?', na kulundika ushahidi. Mtu ambaye injini hii ya kisayansi inafanya kazi kichwani mwake anaweza kuona kwa ukali maneno matamu ya walaghai na habari za uongo za kutiliwa shaka zilizojificha duniani. Ni chombo bora zaidi cha fikra cha kuwa bwana wa hekima yako mwenyewe." },
  { id:146, topic:"Haki kati ya vizazi", emoji:"👶",
    question:"Mazingira tajiri ya Dunia, zana zetu zenye manufaa, na maarifa ya ajabu ya tiba si mali ya sisi tulio hai sasa peke yetu. Tunapaswa kuvirithisha vitu hivi kwa watoto wa baadaye ambao bado hawajazaliwa katika hali gani?",
    choices:["Kuvitumia vyote katika kizazi chetu, kukata miti yote, na kuviacha vimejaa taka","Kupokea kwa uangalifu kijiti cha historia ambacho mababu zetu walikiunganisha kwetu, kuking'arisha zaidi kwa hekima yetu kuwa 'Dunia safi zaidi kuliko jana na salama zaidi kuliko jana', na kukikabidhi kizazi kijacho (haki kati ya vizazi)","Kubomoa majengo yote, kurudi kwenye maisha ya zama za kale za awali, na kurithisha hilo","Kwa kuwa baadaye hainihusu, kuiacha ilivyo bila kufikiri lolote"],
    answerIndex:1,
    explanation:"Sababu halisi ya binadamu kuwa na hekima na kuweza kujifunza historia ni kuunganisha 'kijiti hiki cha hekima (haki kati ya vizazi)' hadi baadaye. Tunaweza sasa kunywa maji salama, kupona kwa dawa tunapougua, na kusoma vitabu kujifunza, kwa sababu mamia ya vizazi vya mababu wa zamani sana, badala ya kuzitumia katika kizazi chao almasi za hekima walizozipata kwa kushindwa na juhudi nyingi, walizihifadhi kwa uangalifu na kuzifikisha kwetu. Sasa ni zamu yetu, kama walinzi wa Dunia, kukikabidhi kijiti hiki kwa maisha madogo ya baadaye katika umbo bora zaidi. Tuwe na mtazamo mpana unaojali maisha ya baadaye." },
  { id:147, topic:"Kujitolea kwa wengine", emoji:"🙋",
    question:"Mtu usiyemfahamu anayetembea mbele yako ameangusha mzigo mzito na yuko shidani. Mtu huyo alizaliwa nchi tofauti na anaongea lugha tofauti na wewe, na hakuna uwezekano wowote wa kukulipa (kukushukuru). Ni uamuzi gani wa busara zaidi unaopaswa kuuchukua?",
    choices:["Kwa kuwa mambo ya wengine hayanihusu, kucheka na kupita bila kujali","Hata bila malipo, kumsaidia mtu aliye shidani huongeza 'akiba ya imani ya jamii nzima (mtaji wa kijamii)', jambo linalojenga dunia salama ambapo mtu fulani atakusaidia kwa upole siku moja utakapokuwa shidani, hivyo nyoosha mkono kwa hiari","Kunyakua mzigo wa mtu huyo na kukimbia","Kuweka mawe makubwa mengi kuzunguka mzigo ili kuzuia"],
    answerIndex:1,
    explanation:"Hii ni ushahidi wa msingi wa upole usiotafuta malipo (tabia ya kujitolea kwa wengine). Binadamu hawezi kunusurika majanga ya maumbile au jamii kwa nguvu ya mtu mmoja peke yake. Tendo la upole ambalo kwalo ulimsaidia mgeni aliye shidani leo huongeza, kidogo kidogo, imani ya jamii nzima (mtaji wa mahusiano ya kijamii) kwamba 'dunia hii ni mahali pa upole na salama'. Katika jamii ambayo akiba hii ya imani imejaa tele, ukianguka siku moja kwenye kina cha upweke au ugonjwa mzito, mtu usiyemfahamu atakunyooshea mkono. Kuzungusha upole huwa pia usalama mkubwa zaidi kwako wewe mwenyewe." },
  { id:148, topic:"Sayansi huria", emoji:"🔓",
    question:"Mtu fulani amebuni 'mchoro wa nishati safi mpya itakayoiokoa Dunia'. Ni kipi kinachookoa binadamu haraka zaidi: kuihifadhi hekima hii kuwa siri kwa ajili yake mwenyewe tu, au kuifanya 'huria na ya wazi kwa wote' kwa wanasayansi wa dunia nzima?",
    choices:["Kuihifadhi kuwa siri ili yeye peke yake awe tajiri zaidi duniani na kuweza kujivuna ndiko kunakoisafisha Dunia haraka zaidi","Kwa sababu kuifanya wazi kabisa kwa dunia nzima (sayansi huria) kunawezesha kuunganisha hekima ya watafiti wengi, kuiboresha haraka, na kuieneza dunia nzima, kusimamisha joto la dunia mapema (nguvu ya ushirikiano)","Kukunja mchoro kuwa ndege ya karatasi na kuirusha kuelekea baharini","Bila kumwambia yeyote, kuuzika ndani kabisa ya ardhi na kuusahau"],
    answerIndex:1,
    explanation:"Kama tulivyojifunza pia kuhusu chanzo huria (OSS) kwenye pakiti ya habari, hii ni hekima ya 'sayansi huria' inayookoa baadaye ya Dunia. Mtu mmoja anapoficha mchoro kwa siri na kujaribu kupata utajiri, joto la dunia husonga mbele na uharibifu huenea hadi visiwa vya dunia vizame. Moyo unaojaribu kuhodhi hekima huleta mwishowe maangamizi ya jumla. Kushirikiana kwa ukarimu uvumbuzi au wazo lako bora kwa ajili ya wenzako wote waliopanda meli moja iitwayo Dunia, na kusawazisha nguvu za akili za dunia nzima ili kutatua tatizo kubwa haraka - hii ndiyo nguvu kuu ya ushirikiano anayoimiliki binadamu." },
  { id:149, topic:"Hatari ya utii wa upofu", emoji:"⛓️",
    question:"Ni hatari gani kubwa zaidi iliyofichwa ya kuendelea tu kutii bila kufikiri lolote (utii wa upofu), iwe kwa kanuni na sheria alizotunga mtu fulani, au kwa wanachosema watu wazima?",
    choices:["Kwa sababu ukiendelea kutii, ukubwa wa kiatu chako hupungua ghafla na miguu yako huuma","Kwa sababu iwapo katika kanuni au amri hiyo kumechanganyika kosa linalojeruhi haki za binadamu, kama 'kumtenga na kumdhulumu mtu dhaifu', na ukaacha kufikiri mwenyewe, kabla hujatambua wewe mwenyewe huwa 'mtendaji' wa ubaguzi au uhalifu","Kwa sababu kuna sheria isemayo kwamba kwa watu makini watiifu chakula chote huwa kichungu","Hakuna hatari yoyote; kutii daima wanachosema watu wazima bila kufikiri ndilo jambo salama zaidi duniani"],
    answerIndex:1,
    explanation:"Vita na mauaji ya halaiki (mauaji ya kimbari) ya kuhuzunisha zaidi katika historia mengi hayakuanzishwa na wadudu wakatili tangu kuzaliwa. Yalisababishwa na matendo ya watu wa kawaida kabisa na makini ambao, wakisema 'kwa kuwa ni amri kutoka juu' au 'kwa kuwa kila mtu anafanya hivyo', waliacha kabisa kufikiri wenyewe juu ya jema na baya (kuachana na kufikiri). Mwanafikra Hannah Arendt aliliita hili 'uchache wa uovu'. Hata yule aliyetunga kanuni awe muhimu kiasi gani, daima chunguza kwa jicho la akili yako mwenyewe (fikra makini) kama inajeruhi 'uhai wa mtu, haki za binadamu, au upole', na daima weka moyoni mwako ngao imara ya kujitegemea inayoweza kusema 'HAPANA' waziwazi kwa lililo baya." },
  { id:150, topic:"Tamati ya utatu", emoji:"🎓",
    question:"Hongera! Kwa hili umemaliza maswali yote 150 ya msururu wa 'Wise World', na maswali yote ya utatu. Ni lengo gani halisi la mwisho na kuu zaidi la masomo yako yote hadi sasa - kuhusu jinsi mwili unavyofanya kazi, sheria za maumbile, uchumi na imani, kusimamia majanga, teknolojia ya kidijitali, na baadaye ya Dunia?",
    choices:["Kujivunia rekodi ya majibu yako yote sahihi, kuwa mfalme mkuu zaidi duniani, na kuwafanya wanyonge watii amri zako","Kuhifadhi kwa dhati kichwani mwako 'ngao yenye nguvu zaidi, iitwayo hekima', kuwa huru, kutodanganywa tena kamwe na habari mbaya au utawala popote ulipo duniani, kulinda haki za binadamu na maisha yako na ya wenzako wote, na kuumba na kuacha, kwa mikono yako, 'mduara wa uchumi wenye upole na salama na dunia ya ustawi' unaoendelea kuzunguka kwa ajili ya watoto wa baadaye hata baada yako kuondoka","Kupandisha kiwango cha mchezo wa intaneti hadi cha juu zaidi, na kumaliza maisha yako yote bila kutoka hata hatua moja nje ya chumba","Kutazama tu skrini ya 'umemaliza yote' na kusahau kabisa kila ulichojifunza"],
    answerIndex:1,
    explanation:"Kweli hongera - makofi makubwa makubwa! Kuanzia swali la kwanza kabisa ulilokutana nalo ukiwa mtoto mdogo hadi kilele cha swali hili la 150, umetatua kila kitendawili cha hekima, na akili yako haitashindwa tena kwa urahisi na maneno ya mlaghai yeyote wa dunia ya watu wazima, wala na mtego wowote wa uraibu unaojaribu kuteka ubongo wako, wala na mnyororo wowote unaojaribu kukutawala kwa dhuluma. 'Mantiki ya sayansi, imani ya uchumi, uoni wa mbele wa kusimamia majanga, ngao ya kidijitali, na mtazamo mpana unaopenda Dunia nzima' uliopata katika utatu huu vitakuwa hirizi imara zaidi duniani, vikilinda maisha yako milele. Na kwa mwanga huo uliowashwa wa hekima, shika kwa upole mkono wa watu wanaolia kuzunguka kwako na wa wenzako usiowafahamu wa dunia nzima ambao hata simu hawawezi kumiliki, na ujenge kwa mikono yako, hapa juu ya Dunia hii, mduara wa uchumi wenye upole (mduara wa uchumi wa upole) usiotegemea mamlaka kuu peke yake, ambapo hakuna anayeona njaa na hakuna anayetengwa. Kijiti cha hakika cha hekima ulichojifunza hadi mwisho kitaandika upya dunia ijayo iwe nzuri zaidi kuliko jana, na kitakuwa mwanga unaomulika bila kikomo njia ya watoto wote wa baadaye. Kila mtu duniani anakushangilia kwa moyo wote kwa ajili ya uhuru wako ujao na mafanikio kamili ya safari yako kuu ya matukio. Kweli, kweli, hongera!" }
];
